                    <th className="p-4 text-xs font-black uppercase text-gray-500 tracking-wider">Student Name</th>
                    <th className="p-4 text-xs font-black uppercase text-gray-500 tracking-wider">Email</th>
                    <th className="p-4 text-xs font-black uppercase text-gray-500 tracking-wider">ID</th>
                    <th className="p-4 text-xs font-black uppercase text-gray-500 tracking-wider">Batches</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {(studentsForDialog || []).map((s, i) => (
                    <tr key={s.id || i} className="hover:bg-gray-50/50 transition-colors">
                      <td className="p-4 text-sm font-bold text-gray-400">{i + 1}</td>
                      <td className="p-4 text-sm font-bold text-gray-800">{s.name || s.student_name || 'Unnamed'}</td>
                      <td className="p-4 text-sm font-medium text-gray-600">{s.email || '-'}</td>
                      <td className="p-4 text-sm font-medium text-gray-500">{s.id || '-'}</td>
                      <td className="p-4">
                        {renderAssignedBatches(s)}
                      </td>
                    </tr>
                  ))}
                  {(studentsForDialog || []).length === 0 && (
                    <tr>
                      <td colSpan="5" className="p-8 text-center text-gray-400 font-medium">No students found</td>
                    </tr>
                  )}
                </tbody>
              </table>
            )}
          </div>
        </div>
      </Modal>

    </AdminLayout>
  );
}

import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { clearSession, setSession } from '../utils/auth';
import AuthShell from '../components/AuthShell';

const AdminLogin = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const navigate = useNavigate();
  const API_USER_LOGIN = 'http://localhost:3000/api/v1/users/login';
  const API_STUDENT_LOGIN = 'http://localhost:3000/api/students/login';

  const redirectByRole = (role) => {
    if (role === 'admin') return '/admin/dashboard';
    if (role === 'faculty') return '/faculty/dashboard';
    if (role === 'student') return '/student/dashboard';
    return '/';
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    clearSession();

    try {
      const payload = { email: email.trim().toLowerCase(), password };
      let token = null;
      let user = null;

      try {
        const response = await axios.post(API_USER_LOGIN, payload);
        token = response?.data?.token;
        user = response?.data?.user;
      } catch (userLoginError) {
        const studentResponse = await axios.post(API_STUDENT_LOGIN, payload);
        token = studentResponse?.data?.token;
        user = studentResponse?.data?.user;
      }

      if (!token || !user?.role) {
        throw new Error('Invalid login response');
      }

      setSession({ token, user });
      navigate(redirectByRole(user.role));
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password');
      clearSession();
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthShell
      portalLabel="Unified Portal"
      title="Sign In"
      subtitle="Use your LMS account credentials to continue."
    >
      <form onSubmit={handleLogin} className="space-y-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1.5">Email</label>
          <input
            type="email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="name@company.com"
            className="lms-input"
          />
        </div>

        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1.5">Password</label>
          <input
            type="password"
            required
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="********"
            className="lms-input"
          />
        </div>

        {error && <p className="text-sm font-medium text-rose-600">{error}</p>}

        <div className="flex items-center justify-end text-sm">
          <button
            type="button"
            onClick={() => navigate('/forgot-password')}
            className="font-semibold text-blue-700 hover:text-blue-900 underline underline-offset-4"
          >
            Forgot Password?
          </button>
        </div>

        <button
          type="submit"
          disabled={loading}
          className="lms-btn-primary w-full py-3 text-base"
        >
          {loading ? 'Signing in...' : 'Sign In'}
        </button>
      </form>
    </AuthShell>
  );
};

export default AdminLogin;

import React, { useEffect, useMemo, useState } from "react";
import AdminLayout from "./AdminLayout";
import axios from "axios";
import {
  ResponsiveContainer, AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip,
  PieChart, Pie, Cell, BarChart, Bar, Legend
} from "recharts";
import {
  Users, BookOpen, GraduationCap, Edit, Lock, Download,
  Search, Filter, ChevronDown, CheckCircle, X, Shield,
  Mail, Phone, Calendar, PieChart as PieChartIcon, Activity, RefreshCw
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

const API_USERS = "http://localhost:3000/api/v1/users";
const API_COURSES = "http://localhost:3000/api/courses";
const API_STUDENTS = "http://localhost:3000/api/students";
const API_FACULTIES = "http://localhost:3000/api/v1/users/faculties";

const COLORS = ["#6366f1", "#10b981", "#f59e0b", "#ef4444", "#8b5cf6", "#06b6d4", "#f97316"];

// --- Helper Components ---

const Modal = ({ isOpen, onClose, title, children, maxWidth = 'max-w-md' }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
        />
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className={`relative w-full ${maxWidth} bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]`}
        >
          <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <h3 className="text-lg font-bold text-slate-800">{title}</h3>
            <button
              onClick={onClose}
              className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors"
            >
              <X size={20} />
            </button>
          </div>
          <div className="p-6 overflow-y-auto">
            {children}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const ActionButton = ({ onClick, icon: Icon, label, variant = 'primary', disabled = false, size = 'normal' }) => {
  const baseClass = "flex items-center justify-center gap-2 rounded-xl font-bold transition-all duration-300 transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none";
  const sizeClass = size === 'small' ? 'px-3 py-1.5 text-xs' : 'px-4 py-2 text-sm';
  const variants = {
    primary: "bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-lg shadow-indigo-500/25 hover:shadow-indigo-500/40 hover:-translate-y-0.5",
    secondary: "bg-white text-slate-700 border border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm",
    ghost: "bg-transparent text-slate-500 hover:text-indigo-600 hover:bg-indigo-50"
  };

  return (
    <button onClick={onClick} disabled={disabled} className={`${baseClass} ${sizeClass} ${variants[variant]}`}>
      {Icon && <Icon size={size === 'small' ? 14 : 18} strokeWidth={2.5} />}
      {label}
    </button>
  );
};

const StatCard = ({ title, value, icon: Icon, color, subtitle }) => {
  const getColorClasses = (c) => {
    switch (c) {
      case 'indigo': return 'from-indigo-500 to-purple-600 text-indigo-50 bg-indigo-50 border-indigo-100';
      case 'purple': return 'from-purple-500 to-pink-600 text-purple-50 bg-purple-50 border-purple-100';
      case 'cyan': return 'from-cyan-500 to-blue-600 text-cyan-50 bg-cyan-50 border-cyan-100';
      default: return 'from-slate-500 to-slate-600 text-slate-50 bg-slate-50 border-slate-100';
    }
  };

  // Custom color mapping just for gradient bg
  const bgGradient = color === 'indigo' ? 'bg-indigo-50' : color === 'purple' ? 'bg-purple-50' : 'bg-cyan-50';
  const border = color === 'indigo' ? 'border-indigo-100' : color === 'purple' ? 'border-purple-100' : 'border-cyan-100';
  const iconGradient = color === 'indigo' ? 'from-indigo-500 to-purple-600' : color === 'purple' ? 'from-purple-500 to-pink-600' : 'from-cyan-500 to-blue-600';
  const textGradient = color === 'indigo' ? 'from-indigo-600 to-purple-600' : color === 'purple' ? 'from-purple-600 to-pink-600' : 'from-cyan-600 to-blue-600';

  return (
    <div className={`relative overflow-hidden rounded-2xl border ${border} ${bgGradient} p-6 transition-all duration-300 hover:shadow-lg hover:-translate-y-1`}>
      <div className="relative z-10 flex items-start justify-between">
        <div>
          <p className="text-sm font-bold uppercase tracking-wider text-slate-500 mb-1">{title}</p>
          <h3 className={`text-3xl font-black bg-gradient-to-r ${textGradient} bg-clip-text text-transparent`}>
            {value}
          </h3>
          {subtitle && <p className="text-xs font-semibold text-slate-400 mt-1">{subtitle}</p>}
        </div>
        <div className={`p-3 rounded-xl bg-gradient-to-br ${iconGradient} text-white shadow-lg`}>
          <Icon size={24} />
        </div>
      </div>
    </div>
  );
};

// Data Helpers
const getId = (obj) => {
  if (obj == null) return null;
  if (typeof obj === "string" || typeof obj === "number") return String(obj);
  return obj.id ?? obj._id ?? obj.courseId ?? obj.course_id ?? obj._id?.$oid ?? null;
};
const asKey = (s) => (s == null ? null : String(s).trim().toLowerCase());

export default function AdminProfile() {
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState("");
  const [profile, setProfile] = useState(null);
  const [courses, setCourses] = useState([]);
  const [faculties, setFaculties] = useState([]);
  const [students, setStudents] = useState([]);

  const [courseSearch, setCourseSearch] = useState("");
  const [courseSortBy, setCourseSortBy] = useState("name");

  const [editOpen, setEditOpen] = useState(false);
  const [editForm, setEditForm] = useState({ name: "", email: "", phone: "" });

  const [pwdOpen, setPwdOpen] = useState(false);
  const [pwdForm, setPwdForm] = useState({ currentPassword: "", newPassword: "", confirmPassword: "" });
  const [pwdErrors, setPwdErrors] = useState({});

  useEffect(() => {
    let mounted = true;
    const load = async () => {
      setLoading(true);
      setLoadError("");
      try {
        const token = localStorage.getItem("token");
        const headers = token ? { Authorization: `Bearer ${token}` } : {};

        const [meRes, coursesRes, facultiesRes, studentsRes] = await Promise.allSettled([
          axios.get(`${API_USERS}/me`, { headers }).catch(e => e),
          axios.get(`${API_COURSES}/get-all-courses`).catch(e => e),
          axios.get(API_FACULTIES, { headers }).catch(e => e),
          axios.get(`${API_STUDENTS}/get-all-students`).catch(e => e),
        ]);

        if (!mounted) return;

        if (meRes.status === "fulfilled" && meRes.value?.data) {
          const me = meRes.value.data?.data ?? meRes.value.data ?? null;
          setProfile(me);
          setEditForm({ name: me?.name ?? "", email: me?.email ?? "", phone: me?.phone ?? "" });
        }

        const getArr = (res) => {
          if (res.status !== 'fulfilled' || !res.value) return [];
          const d = res.value.data;
          if (d?.courses && Array.isArray(d.courses)) return d.courses;
          if (d?.faculties && Array.isArray(d.faculties)) return d.faculties;
          if (d?.students && Array.isArray(d.students)) return d.students;
          if (Array.isArray(d)) return d;
          return [];
        };

        setCourses(getArr(coursesRes));
        setFaculties(getArr(facultiesRes));
        setStudents(getArr(studentsRes));

      } catch (err) {
        console.error("load error", err);
        setLoadError("Unexpected error while loading admin page.");
      } finally {
        if (mounted) setLoading(false);
      }
    };
    load();
    return () => { mounted = false; };
  }, []);

  // Compute logic (kept from original)
  const { courseCountsMap, unassignedCounts } = useMemo(() => {
    const byId = {}; const byCode = {}; const byName = {};
    (courses || []).forEach(c => {
      const id = getId(c) ?? Math.random().toString(36).slice(2);
      const idStr = String(id);
      byId[idStr] = { course: c, studentCount: 0, facultyCount: 0, reportedStudentCount: c.studentCount ?? c.studentsCount ?? c.enrolled ?? null };
      const codeKey = asKey(c.course_code ?? c.code ?? c.courseCode);
      if (codeKey) byCode[codeKey] = idStr;
      const nameKey = asKey(c.name ?? c.title ?? c.course_name);
      if (nameKey) byName[nameKey] = idStr;
    });

    let unassignedStudents = 0; let unassignedFaculties = 0;
    const matchCourseIdFrom = (val) => {
      if (val == null) return null;
      const id = getId(val);
      if (id != null && byId[String(id)]) return String(id);
      const s = String(val).trim();
      const codeKey = asKey(val?.code ?? val?.course_code ?? s);
      if (codeKey && byCode[codeKey]) return byCode[codeKey];
      const nameKey = asKey(val?.name ?? val?.title ?? s);
      if (nameKey && byName[nameKey]) return byName[nameKey];
      return null;
    };

    const extractCourseIdsFromEntity = (ent) => {
      const found = new Set();
      const singleFields = ["courseId", "course_id", "course", "assignedCourse", "assigned_course"];
      for (const f of singleFields) {
        const v = ent[f];
        if (v != null) {
          if (Array.isArray(v)) { v.forEach(item => { const mid = matchCourseIdFrom(item); if (mid) found.add(mid); }); }
          else { const mid = matchCourseIdFrom(v); if (mid) found.add(mid); }
        }
      }
      return Array.from(found);
    };

    (students || []).forEach(s => {
      let ids = extractCourseIdsFromEntity(s);
      if (ids.length === 0) {
        const direct = s.course ?? s.Course ?? null;
        const mid = matchCourseIdFrom(direct ?? s);
        if (mid) ids.push(mid);
      }
      if (ids.length === 0) unassignedStudents += 1;
      else ids.forEach(id => { if (byId[id]) byId[id].studentCount += 1; });
    });

    (faculties || []).forEach(f => {
      const ids = extractCourseIdsFromEntity(f);
      if (ids.length === 0) unassignedFaculties += 1;
      else ids.forEach(id => { if (byId[id]) byId[id].facultyCount += 1; });
    });

    return { courseCountsMap: byId, unassignedCounts: { students: unassignedStudents, faculties: unassignedFaculties } };
  }, [courses, students, faculties]);

  const courseEnrollments = useMemo(() => {
    const arr = Object.keys(courseCountsMap).map(id => {
      const item = courseCountsMap[id];
      const name = item.course?.name ?? item.course?.title ?? item.course?.course_name ?? `Course ${id}`;
      return { id, name: name.substring(0, 15) + '...', full_name: name, value: item.studentCount ?? 0 };
    }).sort((a, b) => b.value - a.value);
    return arr.slice(0, 6).length ? arr.slice(0, 6) : [{ id: "nodata", name: "No data", value: 0 }];
  }, [courseCountsMap]);

  const signupsByDay = useMemo(() => {
    const days = 14; const map = {};
    for (let i = days - 1; i >= 0; i--) {
      const d = new Date(); d.setHours(0, 0, 0, 0); d.setDate(d.getDate() - i);
      map[d.toISOString().slice(0, 10)] = 0;
    }
    (students || []).forEach(s => {
      const dt = s.createdAt ?? s.created_at ?? s.timestamp ?? s.joinedAt ?? s.created;
      if (!dt) return;
      const d = new Date(dt); if (isNaN(d.getTime())) return;
      const key = d.toISOString().slice(0, 10);
      if (map[key] != null) map[key] += 1;
    });
    return Object.keys(map).map(k => ({ date: k.slice(5), count: map[k] }));
  }, [students]);

  const facultyByDept = useMemo(() => {
    const m = {};
    (faculties || []).forEach(f => {
      const dept = f.department ?? f.dept ?? f.role ?? "Unknown";
      m[dept] = (m[dept] || 0) + 1;
    });
    return Object.keys(m).map((k, i) => ({ name: k, value: m[k], color: COLORS[i % COLORS.length] }));
  }, [faculties]);

  const filteredCourses = useMemo(() => {
    const q = (courseSearch || "").trim().toLowerCase();
    const arr = (courses || []).map(c => {
      const id = getId(c) ?? Math.random().toString(36).slice(2);
      const mapEntry = courseCountsMap[String(id)] ?? { studentCount: 0, facultyCount: 0 };
      return {
        ...c,
        id,
        computedStudents: mapEntry.studentCount ?? 0,
        computedFaculties: mapEntry.facultyCount ?? 0,
        reportedStudents: c.studentCount ?? c.studentsCount ?? c.enrolled ?? null
      };
    }).filter(c => {
      if (!q) return true;
      const name = (c.name ?? c.course_name ?? c.title ?? "").toString().toLowerCase();
      const code = (c.course_code ?? c.code ?? "").toString().toLowerCase();
      return name.includes(q) || code.includes(q);
    });
    if (courseSortBy === "students") return arr.sort((a, b) => (b.computedStudents || 0) - (a.computedStudents || 0));
    return arr.sort((a, b) => (a.name || "").localeCompare(b.name || ""));
  }, [courses, courseCountsMap, courseSearch, courseSortBy]);

  const exportCSV = (rows, filename) => {
    const csv = rows.map(r => r.map(c => `"${(c ?? "").toString().replace(/"/g, '""')}"`).join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url; a.download = filename; document.body.appendChild(a); a.click(); a.remove(); URL.revokeObjectURL(url);
  };

  const handleSaveProfile = async () => {
    try {
      const token = localStorage.getItem("token");
      await axios.put(`${API_USERS}/me`, { name: editForm.name, email: editForm.email, phone: editForm.phone }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const r = await axios.get(`${API_USERS}/me`, { headers: { Authorization: `Bearer ${token}` } });
      setProfile(r?.data?.data ?? r?.data ?? null);
      setEditOpen(false);
      alert('Profile updated');
    } catch (err) {
      alert('Update failed');
    }
  };

  const handleChangePassword = async () => {
    if (pwdForm.newPassword !== pwdForm.confirmPassword) {
      setPwdErrors({ confirmPassword: 'Passwords do not match' });
      return;
    }
    try {
      const token = localStorage.getItem("token");
      await axios.post(`${API_USERS}/change-password`, { currentPassword: pwdForm.currentPassword, newPassword: pwdForm.newPassword }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setPwdOpen(false);
      setPwdForm({ currentPassword: "", newPassword: "", confirmPassword: "" });
      alert('Password changed');
    } catch (err) {
      alert('Password change failed');
    }
  };

  if (loading) return <AdminLayout><div className="flex justify-center items-center h-screen"><div className="animate-spin text-indigo-600"><RefreshCw size={40} /></div></div></AdminLayout>;
  if (loadError) return <AdminLayout><div className="p-8 text-center text-red-500">{loadError}</div></AdminLayout>;

  return (
    <AdminLayout>
      <div className="bg-slate-50 min-h-screen pb-10">

        {/* Profile Header */}
        <div className="bg-white border-b border-slate-200 px-6 py-8 shadow-sm mb-6">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center gap-6">
            <div className="w-24 h-24 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white text-3xl font-bold border-4 border-indigo-50 shadow-xl">
              {(profile?.name || "A").substring(0, 2).toUpperCase()}
            </div>
            <div className="flex-1 text-center md:text-left">
              <h1 className="text-3xl font-bold text-slate-900 mb-1">{profile?.name || "Administrator"}</h1>
              <p className="text-slate-500 font-medium mb-3">{profile?.email}</p>
              <div className="flex flex-wrap justify-center md:justify-start gap-2">
                <span className="px-3 py-1 rounded-full bg-indigo-50 text-indigo-700 text-sm font-bold border border-indigo-100 flex items-center gap-1.5"><Shield size={14} /> Admin</span>
                <span className="px-3 py-1 rounded-full bg-emerald-50 text-emerald-700 text-sm font-bold border border-emerald-100 flex items-center gap-1.5"><CheckCircle size={14} /> Active</span>
              </div>
            </div>
            <div className="flex gap-3">
              <ActionButton icon={Edit} label="Edit" variant="ghost" onClick={() => setEditOpen(true)} />
              <ActionButton icon={Lock} label="Password" variant="ghost" onClick={() => setPwdOpen(true)} />
              <ActionButton icon={Download} label="Export System Data" onClick={() => exportCSV([["Course", "Code", "Count"], ...filteredCourses.map(c => [c.name, c.computedStudents])], "system_data.csv")} />
            </div>
          </div>
        </div>

        <div className="max-w-7xl mx-auto px-6 space-y-6">
          {/* KPI Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <StatCard title="Total Courses" value={courses.length} icon={BookOpen} color="indigo" subtitle="Active academic courses" />
            <StatCard title="Faculty Members" value={faculties.length} icon={Users} color="purple" subtitle="Teaching & support staff" />
            <StatCard title="Enrolled Students" value={students.length} icon={GraduationCap} color="cyan" subtitle="Across all batches" />
          </div>

          {/* Charts Row */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Enrollment Chart */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <div className="flex items-center justify-between mb-4">
                <h3 className="font-bold text-slate-800 flex items-center gap-2"><Activity size={18} className="text-indigo-500" /> Enrollment Trends</h3>
                <select className="text-xs border rounded-lg px-2 py-1 bg-slate-50 outline-none"><option>Last 14 Days</option></select>
              </div>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={signupsByDay}>
                    <defs>
                      <linearGradient id="colorStudents" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#6366f1" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="#6366f1" stopOpacity={0} />
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                    <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} />
                    <RechartsTooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }} />
                    <Area type="monotone" dataKey="count" stroke="#6366f1" strokeWidth={3} fillOpacity={1} fill="url(#colorStudents)" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Top Courses */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <div className="flex items-center justify-between mb-4">
                <h3 className="font-bold text-slate-800 flex items-center gap-2"><PieChartIcon size={18} className="text-purple-500" /> Top Courses</h3>
              </div>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={courseEnrollments} layout="vertical" margin={{ left: 10 }}>
                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#e2e8f0" />
                    <XAxis type="number" hide />
                    <YAxis dataKey="name" type="category" width={100} axisLine={false} tickLine={false} tick={{ fontSize: 11, fill: '#64748b' }} />
                    <RechartsTooltip cursor={{ fill: 'transparent' }} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }} />
                    <Bar dataKey="value" fill="#8b5cf6" radius={[0, 4, 4, 0]} barSize={20} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>

          {/* Course Data Table */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row md:items-center justify-between gap-4">
              <h3 className="font-bold text-slate-800">System Course Overview</h3>
              <div className="flex gap-3">
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="text"
                    placeholder="Search courses..."
                    value={courseSearch}
                    onChange={e => setCourseSearch(e.target.value)}
                    className="pl-9 pr-3 py-1.5 rounded-lg border border-slate-200 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  />
                </div>
                <select
                  value={courseSortBy}
                  onChange={e => setCourseSortBy(e.target.value)}
                  className="px-3 py-1.5 rounded-lg border border-slate-200 text-sm focus:outline-none bg-white"
                >
                  <option value="name">Sort by Name</option>
                  <option value="students">Sort by Students</option>
                </select>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="text-xs text-slate-500 uppercase bg-slate-50/50">
                  <tr>
                    <th className="px-6 py-3 font-bold">Course Name</th>
                    <th className="px-6 py-3 font-bold">Code</th>
                    <th className="px-6 py-3 font-bold">Calculated Students</th>
                    <th className="px-6 py-3 font-bold">Calculated Faculties</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredCourses.slice(0, 50).map((c, i) => (
                    <tr key={c.id || i} className="hover:bg-slate-50 transition-colors">
                      <td className="px-6 py-3 font-medium text-slate-900">{c.name}</td>
                      <td className="px-6 py-3 text-slate-500 font-mono text-xs">{c.course_code || c.code}</td>
                      <td className="px-6 py-3">
                        <span className={`px-2 py-0.5 rounded text-xs font-bold ${c.computedStudents > 0 ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                          {c.computedStudents}
                        </span>
                      </td>
                      <td className="px-6 py-3 text-slate-500">{c.computedFaculties}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
              <div className="p-3 text-center text-xs text-slate-400 bg-slate-50/30 border-t border-slate-100">
                Showing top {Math.min(filteredCourses.length, 50)} of {filteredCourses.length} courses
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Edit Profile Modal */}
      <Modal isOpen={editOpen} onClose={() => setEditOpen(false)} title="Edit Profile">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Full Name</label>
            <input type="text" className="w-full px-4 py-2 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" value={editForm.name} onChange={e => setEditForm({ ...editForm, name: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Email</label>
            <input type="email" className="w-full px-4 py-2 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" value={editForm.email} onChange={e => setEditForm({ ...editForm, email: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Phone</label>
            <input type="text" className="w-full px-4 py-2 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" value={editForm.phone} onChange={e => setEditForm({ ...editForm, phone: e.target.value })} />
          </div>
          <div className="flex justify-end gap-3 pt-4">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setEditOpen(false)} />
            <ActionButton label="Save Changes" onClick={handleSaveProfile} />
          </div>
        </div>
      </Modal>

      {/* Change Password Modal */}
      <Modal isOpen={pwdOpen} onClose={() => setPwdOpen(false)} title="Change Password">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Current Password</label>
            <input type="password" className="w-full px-4 py-2 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" value={pwdForm.currentPassword} onChange={e => setPwdForm({ ...pwdForm, currentPassword: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">New Password</label>
            <input type="password" className="w-full px-4 py-2 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" value={pwdForm.newPassword} onChange={e => setPwdForm({ ...pwdForm, newPassword: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Confirm New Password</label>
            <input type="password" className="w-full px-4 py-2 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" value={pwdForm.confirmPassword} onChange={e => setPwdForm({ ...pwdForm, confirmPassword: e.target.value })} />
            {pwdErrors.confirmPassword && <p className="text-red-500 text-xs mt-1">{pwdErrors.confirmPassword}</p>}
          </div>
          <div className="flex justify-end gap-3 pt-4">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setPwdOpen(false)} />
            <ActionButton label="Change Password" onClick={handleChangePassword} />
          </div>
        </div>
      </Modal>
    </AdminLayout>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  ArrowLeft, Trash2, Edit, Plus, RefreshCw, BarChart2, Users, Folder, Code, Type,
  FileText, Terminal, CheckCircle, Search, X, Monitor, Cpu, Database, Globe, Hash, Layout, Download, Filter
} from 'lucide-react';
import axios from 'axios';
import AdminLayout from './AdminLayout';
import { motion, AnimatePresence } from 'framer-motion';

const API = 'http://localhost:3000/api';
const API_COURSES = `${API}/courses/get-all-courses`;
const API_FACULTIES_ALL = `${API}/v1/users/faculties`;
const API_FACULTIES_BY_COURSE = `${API}/v1/users/faculties/course`;

// Programming languages mapping
const PROGRAMMING_LANGUAGES = [
  { id: 62, name: 'Java', icon: Monitor },
  { id: 63, name: 'JavaScript', icon: Code },
  { id: 71, name: 'Python', icon: Terminal },
  { id: 54, name: 'C++', icon: Code },
  { id: 50, name: 'C', icon: Code },
  { id: 51, name: 'C#', icon: Hash },
  { id: 72, name: 'Ruby', icon: Code },
  { id: 73, name: 'Go', icon: Code },
  { id: 74, name: 'TypeScript', icon: Code },
  { id: 82, name: 'SQL', icon: Database }
];

// --- Reusable Components (Tailwind) ---

const Modal = ({ isOpen, onClose, title, children, footer }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
        />
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className="relative w-full max-w-2xl bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]"
        >
          <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <h3 className="text-lg font-bold text-slate-800">{title}</h3>
            <button onClick={onClose} className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors">
              <X size={20} />
            </button>
          </div>
          <div className="p-6 overflow-y-auto custom-scrollbar">
            {children}
          </div>
          {footer && (
            <div className="px-6 py-4 border-t border-slate-100 bg-slate-50 flex justify-end gap-3">
              {footer}
            </div>
          )}
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const Spinner = ({ size = "md", color = "indigo" }) => {
  const sizeClasses = { sm: "w-4 h-4", md: "w-8 h-8", lg: "w-12 h-12" };
  const colorClasses = { indigo: "text-indigo-600", white: "text-white" };
  return (
    <svg className={`animate-spin ${sizeClasses[size]} ${colorClasses[color]}`} xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
    </svg>
  );
};

const Toast = ({ message, type = 'success', onClose }) => {
  useEffect(() => {
    const timer = setTimeout(onClose, 4000);
    return () => clearTimeout(timer);
  }, [onClose]);

  const bgClass = type === 'success' ? 'bg-emerald-500' : type === 'error' ? 'bg-rose-500' : 'bg-amber-500';

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: 20 }}
      className={`fixed bottom-6 right-6 z-50 px-6 py-3 rounded-xl shadow-lg flex items-center gap-3 text-white font-medium ${bgClass}`}
    >
      <span>{message}</span>
      <button onClick={onClose} className="opacity-80 hover:opacity-100"><X size={16} /></button>
    </motion.div>
  );
};

export default function AdminQuestionBanks() {
  const token = localStorage.getItem('token') || '';
  const authHeader = useMemo(() => (token ? { Authorization: `Bearer ${token}` } : {}), [token]);

  const [courses, setCourses] = useState([]);
  const [courseId, setCourseId] = useState('');
  const [faculties, setFaculties] = useState([]);
  const [questions, setQuestions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [toast, setToast] = useState(null);

  // Dialog states
  const [openCreate, setOpenCreate] = useState(false);
  const [openEdit, setOpenEdit] = useState(false);
  const [editingQ, setEditingQ] = useState(null);
  const [form, setForm] = useState({
    title: '',
    description: '',
    sample_input: '',
    sample_output: '',
    language_id: 62,
    score: 100,
    faculty_id: ''
  });

  const showToast = (msg, type = 'success') => setToast({ msg, type });

  useEffect(() => {
    loadCourses();
    loadFaculties();
  }, []);

  useEffect(() => {
    if (!courseId) {
      setQuestions([]);
      setFaculties([]);
      return;
    }
    const doLoad = async (cid) => {
      await loadFaculties(cid);
      await loadQuestions(cid);
    };
    doLoad(courseId);
  }, [courseId]);

  const loadCourses = async () => {
    try {
      const res = await axios.get(API_COURSES, { headers: authHeader });
      setCourses(res.data?.courses || []);
    } catch (err) {
      showToast('Failed to load courses', 'error');
    }
  };

  const loadFaculties = async (cid) => {
    try {
      const url = cid ? `${API_FACULTIES_BY_COURSE}/${cid}` : API_FACULTIES_ALL;
      const res = await axios.get(url, { headers: authHeader });
      const raw = res.data?.faculties ?? res.data ?? [];
      const list = Array.isArray(raw) ? raw : (raw.faculties || raw.items || []);
      const normalized = (list || []).map(f => ({ ...f, id: Number(f.id) }));
      setFaculties(normalized);
      return normalized;
    } catch (err) {
      setFaculties([]);
      return [];
    }
  };

  const resolveFacultyName = (q, localFaculties) => {
    if (q && q.faculty) return q.faculty.name || q.faculty.fullname || q.faculty.username;
    if (q && q.faculty_user) return q.faculty_user.name || q.faculty_user.fullname || q.faculty_user.username;
    if (q && q.faculty_name) return q.faculty_name;
    if (q && q.created_by_name) return q.created_by_name;
    if (q && (q.faculty_id !== undefined && q.faculty_id !== null)) {
      const found = (localFaculties || []).find(x => Number(x.id) === Number(q.faculty_id));
      if (found) return found.name || found.fullname || found.email || String(found.id);
    }
    if (q && (q.faculty_id === null || q.faculty_id === undefined)) return 'Admin';
    return (q && q.faculty_id) ? String(q.faculty_id) : 'Unknown';
  };

  const getLanguageName = (languageId) => {
    return PROGRAMMING_LANGUAGES.find(lang => lang.id === languageId)?.name || 'Unknown';
  };

  const loadQuestions = async (cid) => {
    setLoading(true);
    setQuestions([]);
    try {
      const res = await axios.get(`${API}/questions/admin/bank/${cid}?includeBatches=1`, { headers: authHeader });
      const qs = res.data?.questions || [];
      const normalized = qs.map(q => ({
        ...q,
        faculty_name: resolveFacultyName(q, faculties),
        language_name: getLanguageName(q.language_id),
        toggle_count: (q.enabled_batches?.length) || (q.batch_states ? Object.keys(q.batch_states).length : 0),
        createdAt: q.createdAt || q.created_at,
        updatedAt: q.updatedAt || q.updated_at,
      }));
      setQuestions(normalized);
    } catch (err) {
      showToast(err.response?.data?.message || 'Failed to load questions', 'error');
    } finally {
      setLoading(false);
    }
  };

  const openCreateDialog = () => {
    if (!courseId) return showToast('Select course first', 'warning');
    setForm({
      title: '', description: '', sample_input: '', sample_output: '',
      language_id: 62, score: 100, faculty_id: ''
    });
    setOpenCreate(true);
  };

  const handleCreate = async () => {
    if (!form.title) return showToast('Title required', 'error');
    setSaving(true);
    try {
      const payload = {
        ...form,
        course_id: courseId,
        faculty_id: form.faculty_id || undefined,
        duration: form.duration || 10
      };
      await axios.post(`${API}/questions/admin/add`, payload, { headers: authHeader });
      await loadQuestions(courseId);
      showToast('Question created', 'success');
      setOpenCreate(false);
    } catch (err) {
      showToast(err.response?.data?.message || 'Create failed', 'error');
    } finally {
      setSaving(false);
    }
  };

  const openEditDialog = (q) => {
    setEditingQ(q);
    setForm({
      title: q.title || '', description: q.description || '',
      sample_input: q.sample_input || '', sample_output: q.sample_output || '',
      language_id: q.language_id || 62, score: q.score || 100,
      faculty_id: q.faculty_id ?? ''
    });
    setOpenEdit(true);
  };

  const handleUpdate = async () => {
    if (!editingQ) return;
    setSaving(true);
    try {
      await axios.put(`${API}/questions/admin/update/${editingQ.id}`, form, { headers: authHeader });
      showToast('Question updated', 'success');
      setOpenEdit(false);
      setEditingQ(null);
      await loadQuestions(courseId);
    } catch (err) {
      showToast('Update failed', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this question?')) return;
    try {
      await axios.delete(`${API}/questions/admin/delete/${id}`, { headers: authHeader });
      showToast('Question deleted', 'success');
      await loadQuestions(courseId);
    } catch (err) {
      showToast('Delete failed', 'error');
    }
  };

  // Form Content Renderer
  const renderFormContent = () => (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      <div className="md:col-span-2 space-y-1">
        <label className="block text-sm font-bold text-slate-700">Title <span className="text-red-500">*</span></label>
        <div className="relative">
          <Type className="absolute left-3 top-2.5 text-slate-400" size={16} />
          <input
            type="text"
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={form.title}
            onChange={e => setForm({ ...form, title: e.target.value })}
            placeholder="e.g. Array Summation"
          />
        </div>
      </div>

      <div className="md:col-span-2 space-y-1">
        <label className="block text-sm font-bold text-slate-700">Description</label>
        <div className="relative">
          <FileText className="absolute left-3 top-3 text-slate-400" size={16} />
          <textarea
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all min-h-[100px]"
            value={form.description}
            onChange={e => setForm({ ...form, description: e.target.value })}
            placeholder="Detailed problem statement..."
          />
        </div>
      </div>

      <div className="space-y-1">
        <label className="block text-sm font-bold text-slate-700">Language</label>
        <div className="relative">
          <Code className="absolute left-3 top-2.5 text-slate-400" size={16} />
          <select
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white appearance-none"
            value={form.language_id}
            onChange={e => setForm({ ...form, language_id: Number(e.target.value) })}
          >
            {PROGRAMMING_LANGUAGES.map(l => (
              <option key={l.id} value={l.id}>{l.name}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="space-y-1">
        <label className="block text-sm font-bold text-slate-700">Score</label>
        <div className="relative">
          <BarChart2 className="absolute left-3 top-2.5 text-slate-400" size={16} />
          <input
            type="number"
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
            value={form.score}
            onChange={e => setForm({ ...form, score: Number(e.target.value) })}
          />
        </div>
      </div>

      <div className="space-y-1">
        <label className="block text-sm font-bold text-slate-700">Sample Input</label>
        <div className="relative">
          <Terminal className="absolute left-3 top-3 text-slate-400" size={16} />
          <textarea
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-mono text-sm"
            value={form.sample_input}
            onChange={e => setForm({ ...form, sample_input: e.target.value })}
            placeholder="Input data..."
            rows={3}
          />
        </div>
      </div>

      <div className="space-y-1">
        <label className="block text-sm font-bold text-slate-700">Sample Output</label>
        <div className="relative">
          <Terminal className="absolute left-3 top-3 text-slate-400" size={16} />
          <textarea
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-mono text-sm"
            value={form.sample_output}
            onChange={e => setForm({ ...form, sample_output: e.target.value })}
            placeholder="Expected output..."
            rows={3}
          />
        </div>
      </div>

      <div className="md:col-span-2 space-y-1">
        <label className="block text-sm font-bold text-slate-700">Assign Faculty (Optional)</label>
        <div className="relative">
          <Users className="absolute left-3 top-2.5 text-slate-400" size={16} />
          <select
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white appearance-none"
            value={form.faculty_id}
            onChange={e => setForm({ ...form, faculty_id: e.target.value })}
          >
            <option value="">-- Admin (Unassigned) --</option>
            {faculties.map(f => (
              <option key={f.id} value={f.id}>{f.name || f.fullname || f.username}</option>
            ))}
          </select>
        </div>
      </div>
    </div>
  );

  return (
    <AdminLayout>
      <div className="min-h-full bg-slate-50 relative">
        {/* Toast */}
        <AnimatePresence>
          {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}
        </AnimatePresence>

        <div className="px-4 md:px-8 pb-8 max-w-[1600px] mx-auto space-y-6">

          {/* Header Card */}
          <div className="bg-white rounded-3xl p-8 relative overflow-hidden shadow-xl border border-white/50">
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>
            <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
              <div className="flex items-center gap-6">
                <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-indigo-600 to-purple-600 flex items-center justify-center shadow-lg transform rotate-3 hover:rotate-6 transition-transform">
                  <Database className="text-white" size={40} />
                </div>
                <div>
                  <h1 className="text-4xl font-black text-slate-800 tracking-tight mb-1">Question Bank</h1>
                  <p className="text-slate-500 font-medium text-lg">Manage coding questions and evaluation criteria</p>
                </div>
              </div>

              <div className="flex items-center gap-3">
                <button
                  onClick={() => window.location.reload()}
                  className="p-3 bg-white border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-50 hover:border-slate-300 transition-all shadow-sm"
                >
                  <RefreshCw size={20} />
                </button>
              </div>
            </div>
          </div>

          {/* Controls Bar */}
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 flex flex-col md:flex-row items-center justify-between gap-4 sticky top-0 z-30">
            <div className="flex items-center gap-4 w-full md:w-auto">
              <div className="relative w-full md:w-72">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <select
                  value={courseId}
                  onChange={(e) => setCourseId(e.target.value)}
                  className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer hover:bg-slate-100 transition-colors"
                >
                  <option value="">-- Select Course --</option>
                  {courses.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none">
                  <Filter size={16} className="text-slate-400" />
                </div>
              </div>

              {questions.length > 0 && (
                <span className="hidden md:inline-flex px-3 py-1 bg-indigo-50 text-indigo-700 rounded-lg text-sm font-bold border border-indigo-100 items-center gap-1">
                  <Folder size={14} /> {questions.length} Questions
                </span>
              )}
            </div>

            <button
              onClick={openCreateDialog}
              className="flex items-center gap-2 px-6 py-2.5 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-xl font-bold hover:shadow-lg hover:shadow-indigo-500/30 hover:-translate-y-0.5 transition-all active:scale-95 disabled:opacity-50 disabled:active:scale-100"
              disabled={!courseId}
            >
              <Plus size={20} />
              Add Question
            </button>
          </div>

          {/* Main Content */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 min-h-[500px]">
            {loading ? (
              <div className="h-[500px] flex flex-col items-center justify-center gap-4 text-slate-400">
                <Spinner size="lg" />
                <p className="font-medium animate-pulse">Loading questions...</p>
              </div>
            ) : !courseId ? (
              <div className="h-[500px] flex flex-col items-center justify-center gap-4 text-slate-300">
                <div className="w-32 h-32 rounded-full bg-slate-50 flex items-center justify-center mb-2">
                  <Layout size={64} className="opacity-50" />
                </div>
                <h3 className="text-xl font-bold text-slate-400">No Course Selected</h3>
                <p className="text-slate-400">Please select a course from the dropdown above.</p>
              </div>
            ) : questions.length === 0 ? (
              <div className="h-[500px] flex flex-col items-center justify-center gap-4 text-slate-400">
                <div className="w-24 h-24 rounded-full bg-indigo-50 flex items-center justify-center mb-2 text-indigo-300">
                  <Code size={48} />
                </div>
                <h3 className="text-xl font-bold text-slate-600">No Questions Found</h3>
                <p className="text-slate-500 max-w-sm text-center">Get started by creating the first question for this course bank.</p>
                <button onClick={openCreateDialog} className="mt-4 px-6 py-2 bg-indigo-50 text-indigo-600 rounded-xl font-bold hover:bg-indigo-100 transition-colors">
                  Create First Question
                </button>
              </div>
            ) : (
              <div className="overflow-x-auto rounded-2xl">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider font-bold border-b border-slate-200">
                      <th className="px-6 py-4">ID</th>
                      <th className="px-6 py-4">Title</th>
                      <th className="px-6 py-4 w-1/3">Description</th>
                      <th className="px-6 py-4 text-center">Lang</th>
                      <th className="px-6 py-4 text-center">Score</th>
                      <th className="px-6 py-4">Faculty</th>
                      <th className="px-6 py-4 text-center">Usage</th>
                      <th className="px-6 py-4 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {questions.map((q) => (
                      <tr key={q.id} className="hover:bg-slate-50/80 transition-colors group">
                        <td className="px-6 py-4 text-xs font-mono text-slate-400">#{q.id}</td>
                        <td className="px-6 py-4">
                          <span className="font-bold text-slate-700 block">{q.title}</span>
                          <span className="text-xs text-slate-400">{new Date(q.createdAt).toLocaleDateString()}</span>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-500 line-clamp-2" title={q.description}>{q.description}</p>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <span className="px-2.5 py-1 bg-slate-100 text-slate-600 rounded text-xs font-bold border border-slate-200 inline-flex items-center gap-1">
                            {q.language_name === 'Java' && <Monitor size={10} />}
                            {q.language_name}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <span className="px-2 py-1 bg-emerald-50 text-emerald-600 rounded-full text-xs font-bold">
                            {q.score}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-sm font-medium text-indigo-600">
                          {q.faculty_name}
                        </td>
                        <td className="px-6 py-4 text-center">
                          {q.toggle_count > 0 ? (
                            <span className="px-2 py-1 bg-indigo-50 text-indigo-600 rounded-full text-xs font-bold">
                              {q.toggle_count} Batches
                            </span>
                          ) : (
                            <span className="text-xs text-slate-400">-</span>
                          )}
                        </td>
                        <td className="px-6 py-4 text-right">
                          <div className="flex items-center justify-end gap-2 opacity-60 group-hover:opacity-100 transition-opacity">
                            <button onClick={() => openEditDialog(q)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit">
                              <Edit size={16} />
                            </button>
                            <button onClick={() => handleDelete(q.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete">
                              <Trash2 size={16} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Create Modal */}
      <Modal
        isOpen={openCreate}
        onClose={() => setOpenCreate(false)}
        title="Add Question"
        footer={
          <>
            <button onClick={() => setOpenCreate(false)} className="px-4 py-2 text-slate-500 font-bold hover:bg-slate-100 rounded-xl transition-colors">Cancel</button>
            <button onClick={handleCreate} disabled={saving} className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-colors flex items-center gap-2">
              {saving && <Spinner size="sm" color="white" />}
              Create
            </button>
          </>
        }
      >
        {renderFormContent()}
      </Modal>

      {/* Edit Modal */}
      <Modal
        isOpen={openEdit}
        onClose={() => setOpenEdit(false)}
        title="Edit Question"
        footer={
          <>
            <button onClick={() => setOpenEdit(false)} className="px-4 py-2 text-slate-500 font-bold hover:bg-slate-100 rounded-xl transition-colors">Cancel</button>
            <button onClick={handleUpdate} disabled={saving} className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-colors flex items-center gap-2">
              {saving && <Spinner size="sm" color="white" />}
              Save Changes
            </button>
          </>
        }
      >
        {renderFormContent()}
      </Modal>

    </AdminLayout>
  );
}

// src/pages/AdminStudentAlloted.jsx
import React, { useEffect, useState } from 'react';
import {
  ArrowLeft,
  Users,
  Filter,
  Download,
  Mail,
  Phone,
  User,
  RefreshCw,
  LayoutDashboard
} from 'lucide-react';
import axios from 'axios';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import AdminLayout from './AdminLayout';

const API_STUDENTS = 'http://localhost:3000/api/students';

// Helper hook for mobile detection
const useIsMobile = () => {
  const [mobile, setMobile] = useState(window.innerWidth <= 768);
  useEffect(() => {
    const onResize = () => setMobile(window.innerWidth <= 768);
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);
  return mobile;
};

export default function AdminStudentAlloted() {
  const { courseId } = useParams();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const initialBatch = searchParams.get('batchId') || '';

  const [batches, setBatches] = useState([]);
  const [selectedBatch, setSelectedBatch] = useState(initialBatch);
  const [loading, setLoading] = useState(true);
  const [students, setStudents] = useState([]);

  const isMobile = useIsMobile();

  useEffect(() => {
    const loadBatches = async () => {
      try {
        const bres = await axios.get(`${API_STUDENTS}/batches/${courseId}`);
        setBatches(bres.data?.batches || []);
      } catch (e) {
        setBatches([]);
      }
    };
    loadBatches();
  }, [courseId]);

  useEffect(() => {
    const loadStudents = async () => {
      setLoading(true);
      try {
        if (selectedBatch) {
          const r = await axios.get(`${API_STUDENTS}/batch/${selectedBatch}`);
          setStudents(r.data?.students || []);
        } else {
          const r = await axios.get(`${API_STUDENTS}/by-course/${courseId}`);
          setStudents(r.data?.students || []);
        }
      } catch (e) {
        setStudents([]);
      } finally {
        setLoading(false);
      }
    };
    loadStudents();
  }, [courseId, selectedBatch]);

  // Export functionality
  const exportStudents = () => {
    const headers = [['#', 'Name', 'Email', 'Phone', 'Batch']];
    const data = students.map((student, index) => [
      index + 1,
      student.name || '',
      student.email || '',
      student.phone || '',
      student.Batch?.name || 'All Batches'
    ]);

    const csvContent = [...headers, ...data]
      .map(row => row.map(cell => `"${cell}"`).join(','))
      .join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `students-course-${courseId}-${selectedBatch || 'all'}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  // Function to get avatar color based on index
  const getAvatarColor = (index) => {
    const colors = [
      '#667eea', '#764ba2', '#f093fb', '#f5576c', '#4facfe',
      '#43e97b', '#fa709a', '#ffecd2', '#fcb69f', '#a8edea'
    ];
    return colors[index % colors.length];
  };

  return (
    <AdminLayout>
      {/* Fullscreen fixed container */}
      <div className="fixed inset-0 overflow-y-auto pt-16 bg-gradient-to-br from-indigo-500 to-purple-600">
        <div className={`h-full overflow-auto bg-gradient-to-br from-white/95 to-gray-50/98 backdrop-blur-xl ${isMobile ? 'p-2' : 'p-8'}`}>

          {/* Header Card */}
          <div className="relative rounded-xl bg-white/90 backdrop-blur-lg border border-white/30 shadow-xl overflow-hidden mb-6">
            <div className="absolute inset-x-0 top-0 h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500" />

            <div className={`relative z-10 ${isMobile ? 'p-3' : 'p-6'}`}>
              <div className="flex flex-col md:flex-row items-center gap-4">
                {/* Avatar */}
                <div className={`${isMobile ? 'w-16 h-16' : 'w-20 h-20'} bg-gradient-to-br from-indigo-500 to-purple-600 rounded-full flex items-center justify-center shadow-lg border-4 border-white/30`}>
                  <Users className={`${isMobile ? 'w-8 h-8' : 'w-10 h-10'} text-white`} />
                </div>

                {/* Title Section */}
                <div className="flex-1 text-center md:text-left">
                  <h1 className="text-3xl font-semibold bg-clip-text text-transparent bg-gradient-to-r from-purple-600 to-blue-600 mb-1">
                    Student Allocation
                  </h1>
                  <p className={`text-gray-600 ${isMobile ? 'text-base' : 'text-lg'}`}>
                    {selectedBatch ? 'Batch Student View' : 'All Course Students'} • Course #{courseId}
                  </p>
                </div>

                {/* Action Buttons - Desktop */}
                {!isMobile && (
                  <div className="flex items-center gap-3">
                    <button
                      onClick={exportStudents}
                      disabled={loading || students.length === 0}
                      className="flex items-center gap-2 px-4 py-2 border border-white/50 bg-white/60 text-gray-700 rounded-lg font-semibold backdrop-blur-md hover:bg-white/80 hover:border-white/80 hover:-translate-y-0.5 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                      <Download size={20} />
                      Export
                    </button>
                    <button
                      onClick={() => window.location.reload()}
                      className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-lg font-semibold shadow-lg hover:shadow-xl hover:-translate-y-0.5 transition-all"
                    >
                      <RefreshCw size={20} />
                      Refresh
                    </button>
                  </div>
                )}
              </div>

              {/* Mobile Action Buttons */}
              {isMobile && (
                <div className="flex gap-2 mt-4">
                  <button className="flex-1 flex items-center justify-center gap-1 px-3 py-2 border border-gray-300 bg-white/60 text-gray-700 rounded-lg text-sm font-semibold">
                    <Filter size={16} />
                    Filters
                  </button>
                  <button
                    onClick={exportStudents}
                    disabled={loading || students.length === 0}
                    className="flex-1 flex items-center justify-center gap-1 px-3 py-2 border border-gray-300 bg-white/60 text-gray-700 rounded-lg text-sm font-semibold disabled:opacity-50"
                  >
                    <Download size={16} />
                    Export
                  </button>
                  <button
                    onClick={() => window.location.reload()}
                    className="flex-1 flex items-center justify-center gap-1 px-3 py-2 bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-lg text-sm font-semibold shadow-md"
                  >
                    <RefreshCw size={16} />
                    Refresh
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Main Content Area */}
          <div className="flex-1 flex flex-col">
            <div className="relative p-6 flex flex-col rounded-xl bg-gradient-to-br from-white to-gray-50 shadow-xl border border-white/50 overflow-visible min-h-[500px]">
              <div className="absolute inset-x-0 top-0 h-1 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-t-xl" />

              {/* Enhanced Top Controls */}
              <div className="flex items-center justify-between mb-6 pb-4 border-b border-gray-200">
                <div className="flex items-center gap-2">
                  <Filter className="text-indigo-600" size={24} />
                  <h2 className="text-xl font-bold text-gray-800">Student Filter</h2>
                </div>

                <div className="flex gap-3 items-center">
                  {/* Batch Select Dropdown */}
                  <select
                    value={selectedBatch}
                    onChange={(e) => setSelectedBatch(e.target.value)}
                    className="min-w-[280px] px-4 py-2 bg-white border-2 border-indigo-300 rounded-lg font-semibold text-gray-700 focus:outline-none focus:border-indigo-500 hover:border-indigo-400 transition-colors"
                  >
                    <option value="">All batches</option>
                    {batches.map(b => (
                      <option key={b.id} value={b.id}>
                        {b.name} - {b.code}
                      </option>
                    ))}
                  </select>

                  <span className="px-4 py-2 border-2 border-indigo-600 text-indigo-600 rounded-lg font-bold text-sm opacity-70">
                    Total: {loading ? '...' : students.length}
                  </span>
                </div>
              </div>

              {/* Content Area */}
              <div className="flex-1">
                {loading ? (
                  <div className="text-center py-12 flex flex-col items-center gap-6">
                    <div className="animate-spin rounded-full h-16 w-16 border-4 border-indigo-500 border-t-transparent"></div>
                    <div>
                      <p className="text-xl font-bold text-gray-800 mb-2">Loading Students</p>
                      <p className="text-gray-600">Fetching student data from the server...</p>
                    </div>
                  </div>
                ) : students.length === 0 ? (
                  <div className="text-center py-12 flex flex-col items-center gap-6">
                    <Users className="w-24 h-24 text-gray-400 opacity-50" />
                    <div>
                      <p className="text-2xl font-bold text-gray-800 mb-2">No Students Found</p>
                      <p className="text-gray-600">
                        {selectedBatch
                          ? 'No students are allocated to this batch yet.'
                          : 'No students are allocated to this course yet.'
                        }
                      </p>
                    </div>
                  </div>
                ) : (
                  <div className="rounded-xl shadow-lg border border-gray-100 overflow-hidden">
                    <table className="min-w-full">
                      <thead className="bg-gradient-to-r from-gray-50 to-gray-100 border-b-2 border-indigo-600">
                        <tr>
                          <th className="w-16 px-6 py-4 text-left text-sm font-black text-indigo-600">#</th>
                          <th className="px-6 py-4 text-left text-sm font-black text-indigo-600">Student Profile</th>
                          <th className="px-6 py-4 text-left text-sm font-black text-indigo-600">Contact Info</th>
                          <th className="px-6 py-4 text-left text-sm font-black text-indigo-600">Batch Info</th>
                        </tr>
                      </thead>
                      <tbody>
                        {students.map((s, i) => (
                          <tr
                            key={s.id || i}
                            className="hover:bg-indigo-50 transition-all border-b border-gray-100"
                          >
                            <td className="px-6 py-4 font-bold text-gray-600">{i + 1}</td>

                            <td className="px-6 py-4">
                              <div className="flex items-center gap-3">
                                <div
                                  className="w-11 h-11 rounded-full flex items-center justify-center text-white font-bold shadow-md"
                                  style={{ backgroundColor: getAvatarColor(i) }}
                                >
                                  {(s.name || 'S').split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2)}
                                </div>
                                <div>
                                  <p className="font-bold text-gray-800">{s.name || 'Unknown Student'}</p>
                                  <p className="text-xs text-gray-600 font-semibold">Student ID: {s.id || 'N/A'}</p>
                                </div>
                              </div>
                            </td>

                            <td className="px-6 py-4">
                              <div className="flex flex-col gap-2">
                                <div className="flex items-center gap-2">
                                  <Mail size={16} className="text-indigo-600 opacity-70" />
                                  <span className="text-sm font-semibold">{s.email || 'No email'}</span>
                                </div>
                                <div className="flex items-center gap-2">
                                  <Phone size={16} className="text-indigo-600 opacity-70" />
                                  <span className={`text-sm font-semibold ${s.phone ? 'text-gray-800' : 'text-gray-500'}`}>
                                    {s.phone || 'No phone'}
                                  </span>
                                </div>
                              </div>
                            </td>

                            <td className="px-6 py-4">
                              {s.Batch ? (
                                <span className="inline-flex items-center gap-1 px-3 py-1 bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-full text-xs font-bold shadow-md">
                                  <User size={14} />
                                  {s.Batch.name} - {s.Batch.code}
                                </span>
                              ) : (
                                <span className="inline-flex items-center px-3 py-1 border-2 border-gray-300 text-gray-600 rounded-full text-xs font-semibold">
                                  No Batch
                                </span>
                              )}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className="text-center py-4 text-gray-500 text-sm h-10 flex-shrink-0 bg-white/80 backdrop-blur-sm border-t border-gray-100 mt-4">
            {/* Footer content if needed */}
          </div>
        </div>
      </div>
    </AdminLayout>
  );
}

import React, { useEffect, useMemo, useState, useCallback } from 'react';
import {
  Users, Search, UserPlus, Layers, Plus, RefreshCw,
  Trash2, Edit, CheckCircle, X, Filter, MoreVertical,
  ChevronRight, ArrowRight, ShieldCheck, ShieldAlert
} from 'lucide-react';
import AdminLayout from './AdminLayout';
import axios from 'axios';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { clearSession } from '../utils/auth';
import { useToast } from '../context/ToastContext';

const API_COURSES = 'http://localhost:3000/api/courses/get-all-courses';
const API_BASE = 'http://localhost:3000/api/students';

const batchAPI = {
  getBatches: (courseId, config = {}) => axios.get(`${API_BASE}/batchmanagement/${courseId}`, config),
  getBatchStudents: (batchId, config = {}) => axios.get(`${API_BASE}/batch/${batchId}`, config),
  createBatch: (courseId, data, config = {}) => axios.post(`${API_BASE}/batches/${courseId}`, data, config),
  updateBatch: (batchId, data, config = {}) => axios.put(`${API_BASE}/batches/${batchId}`, data, config),
  deleteBatch: (batchId, config = {}) => axios.delete(`${API_BASE}/batches/${batchId}`, config)
};

// --- Helper Components ---

const Modal = ({ isOpen, onClose, title, children, maxWidth = 'max-w-md' }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
        />
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className={`relative w-full ${maxWidth} bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden flex flex-col max-h-[90vh]`}
        >
          <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between bg-slate-50">
            <h3 className="text-lg font-bold text-slate-800">{title}</h3>
            <button
              onClick={onClose}
              className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors"
            >
              <X size={20} />
            </button>
          </div>
          <div className="p-6 overflow-y-auto">
            {children}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const ActionButton = ({ onClick, icon: Icon, label, variant = 'primary', disabled = false, size = 'normal' }) => {
  const baseClass = 'inline-flex items-center justify-center gap-2 rounded-lg font-semibold transition-colors disabled:opacity-60 disabled:cursor-not-allowed';
  const sizeClass = size === 'small' ? 'h-9 px-3 text-xs' : 'h-11 px-4 text-sm';
  const variants = {
    primary: 'lms-btn-primary',
    secondary: 'lms-btn-secondary',
    ghost: 'inline-flex items-center justify-center gap-2 rounded-lg font-semibold text-slate-600 hover:bg-slate-100'
  };

  return (
    <button onClick={onClick} disabled={disabled} className={`${baseClass} ${sizeClass} ${variants[variant]}`}>
      {Icon && <Icon size={size === 'small' ? 14 : 18} strokeWidth={2.5} />}
      {label}
    </button>
  );
};

const BatchManagement = () => {
  const navigate = useNavigate();
  const toast = useToast();
  const [courses, setCourses] = useState([]);
  const [courseId, setCourseId] = useState('');
  const [batches, setBatches] = useState([]);
  const [groupFilter, setGroupFilter] = useState('');
  const [searchGroup, setSearchGroup] = useState('');
  const [selectedSubBatch, setSelectedSubBatch] = useState(null);
  const [batchStudents, setBatchStudents] = useState([]);
  const [loading, setLoading] = useState(false);
  const [operationLoading, setOperationLoading] = useState(false);

  const [dialogOpen, setDialogOpen] = useState(false);
  const [createMode, setCreateMode] = useState('sub-batch');
  const [editBatch, setEditBatch] = useState(null);
  const [batchForm, setBatchForm] = useState({ name: '', code: '' });

  const [onlyActive, setOnlyActive] = useState(false);

  // Mobile View State: 'groups', 'batches', 'details'
  const [mobileView, setMobileView] = useState('groups');

  const getAuthConfig = () => {
    const token = localStorage.getItem('token');
    return token ? { headers: { Authorization: `Bearer ${token}` } } : {};
  };

  const handleApiError = (error, defaultMessage) => {
    if (error?.response?.status === 401) {
      clearSession();
      toast.error('Session expired. Please log in again.');
      navigate('/login');
      return;
    }
    toast.error(error?.response?.data?.message || defaultMessage || 'Operation failed');
  };

  const loadCourses = async () => {
    try {
      const res = await axios.get(API_COURSES, getAuthConfig());
      setCourses(res.data?.courses || res.data || []);
    } catch (e) {
      handleApiError(e, 'Failed to load courses');
    }
  };

  const loadBatches = async (cid) => {
    if (!cid) {
      setBatches([]);
      setGroupFilter('');
      setSelectedSubBatch(null);
      setBatchStudents([]);
      return;
    }
    setLoading(true);
    try {
      const res = await batchAPI.getBatches(cid, getAuthConfig());
      const raw = res.data?.batches ?? res.data?.data ?? res.data ?? [];
      const arr = Array.isArray(raw) ? raw : (raw.batches || raw.data || []);
      const normalized = (arr || []).map(x => ({ ...x, is_active: !!x.is_active }));
      normalized.sort((a, b) => {
        const na = (a.name || '').toLowerCase();
        const nb = (b.name || '').toLowerCase();
        if (na === nb) return (a.code || '').toLowerCase().localeCompare((b.code || '').toLowerCase());
        return na.localeCompare(nb);
      });
      setBatches(normalized);

      // If filtering by group, ensure filtered selection is valid
      if (groupFilter && !normalized.some(b => b.name === groupFilter)) {
        setGroupFilter('');
      }
      // If sub-batch selected, re-select updated version
      if (selectedSubBatch) {
        const fresh = normalized.find(b => b.id === selectedSubBatch.id);
        if (fresh) setSelectedSubBatch(fresh);
        else {
          setSelectedSubBatch(null);
          setBatchStudents([]);
        }
      }
    } catch (e) {
      handleApiError(e, 'Failed to load batches');
      setBatches([]);
    } finally {
      setLoading(false);
    }
  };

  const loadBatchStudents = async (bid) => {
    if (!bid) {
      setBatchStudents([]);
      return;
    }
    setLoading(true);
    try {
      const res = await batchAPI.getBatchStudents(bid, getAuthConfig());
      const arr = res.data?.students || res.data?.data || res.data || [];
      const students = Array.isArray(arr) ? arr : (arr.students || arr.data || []);
      students.sort((a, b) => (a.name || '').localeCompare(b.name || ''));
      setBatchStudents(students);
    } catch (e) {
      handleApiError(e, 'Failed to load students');
      setBatchStudents([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadCourses(); }, []);
  useEffect(() => { if (courseId) loadBatches(courseId); else loadBatches(''); }, [courseId]);

  const groups = useMemo(() =>
    [...new Set(batches.map(b => b.name || '(No group)').filter(Boolean))]
      .filter(n => n.toLowerCase().includes(searchGroup.toLowerCase())),
    [batches, searchGroup]
  );

  const subbatches = useMemo(() => {
    let filtered = groupFilter
      ? batches.filter(b => (b.name || '(No group)') === groupFilter)
      : batches;
    if (onlyActive) filtered = filtered.filter(s => s.is_active);
    return filtered;
  }, [batches, groupFilter, onlyActive]);

  const getGroupColor = useCallback((groupName) => {
    const colors = [
      'text-indigo-600 bg-indigo-50 border-indigo-200',
      'text-purple-600 bg-purple-50 border-purple-200',
      'text-pink-600 bg-pink-50 border-pink-200',
      'text-cyan-600 bg-cyan-50 border-cyan-200',
      'text-emerald-600 bg-emerald-50 border-emerald-200',
      'text-orange-600 bg-orange-50 border-orange-200'
    ];
    let hash = 0;
    for (let i = 0; i < groupName.length; i++) hash = groupName.charCodeAt(i) + ((hash << 5) - hash);
    return colors[Math.abs(hash) % colors.length];
  }, []);

  const saveBatch = async () => {
    if (!batchForm.name) {
      toast.error('Batch name is required');
      return;
    }
    if (!courseId) {
      toast.error('Select a course first');
      return;
    }

    setOperationLoading(true);
    let codeToSend = batchForm.code && batchForm.code.trim() ? batchForm.code.trim() : '';
    if (createMode === 'group-only') codeToSend = `__GROUP__${Date.now()}`;

    try {
      if (editBatch && editBatch.id) {
        await batchAPI.updateBatch(editBatch.id, { name: batchForm.name, code: codeToSend }, getAuthConfig());
      } else {
        await batchAPI.createBatch(courseId, { name: batchForm.name, code: codeToSend }, getAuthConfig());
      }
      setDialogOpen(false);
      setEditBatch(null);
      setBatchForm({ name: '', code: '' });
      setCreateMode('sub-batch');
      await loadBatches(courseId);
      toast.success(editBatch ? 'Batch updated successfully' : 'Batch created successfully');
    } catch (e) {
      handleApiError(e, 'Save operation failed');
    } finally {
      setOperationLoading(false);
    }
  };

  const deleteBatch = async (b) => {
    if (!b || !b.id) return;
    if (!window.confirm(`Delete "${b.code}" from "${b.name}"?`)) return;

    setOperationLoading(true);
    try {
      await batchAPI.deleteBatch(b.id, getAuthConfig());
      if (selectedSubBatch && selectedSubBatch.id === b.id) {
        setSelectedSubBatch(null);
        setBatchStudents([]);
      }
      await loadBatches(courseId);
      toast.success('Batch deleted successfully');
    } catch (e) {
      handleApiError(e, 'Delete failed');
    } finally {
      setOperationLoading(false);
    }
  };

  const toggleActive = async (b) => {
    if (!b || !b.id) return;
    setOperationLoading(true);
    const newState = !b.is_active;
    try {
      await batchAPI.updateBatch(b.id, { is_active: newState }, getAuthConfig());
      await loadBatches(courseId);
      toast.success(newState ? 'Batch activated' : 'Batch deactivated');
    } catch (e) {
      handleApiError(e, 'Toggle failed');
    } finally {
      setOperationLoading(false);
    }
  };

  const openSubBatch = async (b) => {
    setSelectedSubBatch(b);
    await loadBatchStudents(b.id);
    setMobileView('details');
  };

  const openCreateDialog = (mode = 'sub-batch') => {
    setEditBatch(null);
    setCreateMode(mode);
    // If creating sub-batch, pre-fill current group name if selected
    setBatchForm({
      name: mode === 'sub-batch' && groupFilter ? groupFilter : '',
      code: ''
    });
    setDialogOpen(true);
  };

  // --- Render ---

  return (
    <AdminLayout>
      <div className="flex flex-col h-full bg-slate-50">
        {/* Header */}
        <div className="bg-white border-b border-slate-200 px-6 py-4 shadow-sm shrink-0">
          <div className="lms-container flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-xl bg-orange-50 text-orange-600">
                <Layers size={24} />
              </div>
              <div>
                <h1 className="text-xl font-bold text-slate-900">Batch Management</h1>
                <p className="text-slate-500 text-sm">Organize students into groups and batches</p>
              </div>
            </div>

            {/* Course Selector in Header */}
            <div className="w-full md:w-64">
              <select
                value={courseId}
                onChange={(e) => setCourseId(e.target.value)}
                className="w-full pl-3 pr-8 py-2 bg-slate-50 border border-slate-200 rounded-lg font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
              >
                <option value="">Select Course...</option>
                {courses.map(c => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* --- Main Content (3 Panes) --- */}
        <div className="flex-1 overflow-hidden">
          <div className="h-full lms-container p-4 md:p-6 grid grid-cols-1 md:grid-cols-12 gap-6">

            {/* Left Pane: Groups */}
            <div className={`md:col-span-3 flex flex-col bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden ${mobileView !== 'groups' ? 'hidden md:flex' : 'flex'}`}>
              <div className="p-4 border-b border-slate-100 bg-slate-50/50">
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-bold text-slate-700">Groups</h3>
                  <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-2 py-0.5 rounded-full">{groups.length}</span>
                </div>
                <div className="relative">
                  <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                  <input
                    type="text"
                    placeholder="Search groups..."
                    value={searchGroup}
                    onChange={e => setSearchGroup(e.target.value)}
                    className="w-full pl-8 pr-3 py-1.5 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  />
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-2 space-y-1">
                {courseId ? groups.map(g => {
                  const active = groupFilter === g;
                  const count = batches.filter(b => b.name === g).length;
                  return (
                    <button
                      key={g}
                      onClick={() => {
                        setGroupFilter(g);
                        setSelectedSubBatch(null);
                        setBatchStudents([]);
                        setMobileView('batches');
                      }}
                      className={`w-full text-left px-3 py-3 rounded-xl transition-all flex items-center justify-between group ${active ? 'bg-indigo-50 border border-indigo-100 shadow-sm' : 'hover:bg-slate-50 border border-transparent'}`}
                    >
                      <div>
                        <p className={`font-bold text-sm ${active ? 'text-indigo-700' : 'text-slate-700'}`}>{g}</p>
                        <p className="text-xs text-slate-500">{count} batches</p>
                      </div>
                      <ChevronRight size={16} className={`transition-transform ${active ? 'text-indigo-500 translate-x-1' : 'text-slate-300 group-hover:text-slate-400'}`} />
                    </button>
                  );
                }) : (
                  <div className="p-4 text-center text-slate-400 italic text-sm">Select a course first</div>
                )}
                {courseId && groups.length === 0 && (
                  <div className="p-4 text-center text-slate-400 italic text-sm">No groups found</div>
                )}
              </div>

              <div className="p-3 border-t border-slate-100">
                <ActionButton
                  label="New Group"
                  onClick={() => openCreateDialog('group-only')}
                  disabled={!courseId}
                  icon={Plus}
                  variant="secondary"
                  size="small"
                />
              </div>
            </div>

            {/* Middle Pane: Sub-Batches */}
            <div className={`md:col-span-4 flex flex-col bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden ${mobileView !== 'batches' ? 'hidden md:flex' : 'flex'}`}>
              <div className="p-4 border-b border-slate-100 bg-slate-50/50">
                <div className="flex items-center gap-2 mb-3">
                  {/* Mobile Back Button */}
                  <button onClick={() => setMobileView('groups')} className="md:hidden p-1 -ml-1 text-slate-400">
                    <ChevronRight className="rotate-180" size={20} />
                  </button>
                  <h3 className="font-bold text-slate-700 flex-1 truncate">{groupFilter || 'All Batches'}</h3>

                  <label className="flex items-center cursor-pointer">
                    <input type="checkbox" checked={onlyActive} onChange={e => setOnlyActive(e.target.checked)} className="hidden" />
                    <span className={`text-xs font-bold px-2 py-1 rounded border transition-colors ${onlyActive ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-200'}`}>Active Only</span>
                  </label>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-2 space-y-2">
                {subbatches.map(b => (
                  <div
                    key={b.id}
                    className={`relative p-3 rounded-xl border transition-all ${selectedSubBatch?.id === b.id ? 'bg-indigo-50 border-indigo-200 ring-1 ring-indigo-200 z-10' : 'bg-white border-slate-100 hover:border-slate-300 hover:shadow-sm'}`}
                  >
                    <div
                      onClick={() => openSubBatch(b)}
                      className="cursor-pointer"
                    >
                      <div className="flex justify-between items-start mb-1">
                        <span className={`text-xs font-bold px-1.5 py-0.5 rounded border ${b.is_active ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-200'}`}>
                          {b.code}
                        </span>
                        {selectedSubBatch?.id === b.id && <ArrowRight size={16} className="text-indigo-500" />}
                      </div>
                      <h4 className="font-bold text-slate-800 text-sm mb-0.5">{b.name}</h4>
                    </div>

                    <div className="flex justify-end gap-2 mt-2 pt-2 border-t border-slate-100/50">
                      <button onClick={() => toggleActive(b)} className="p-1.5 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-colors" title="Toggle Active">
                        {b.is_active ? <ShieldCheck size={14} /> : <ShieldAlert size={14} />}
                      </button>
                      <button onClick={() => { setCreateMode('sub-batch'); setBatchForm({ name: b.name, code: b.code }); setEditBatch(b); setDialogOpen(true); }} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit">
                        <Edit size={14} />
                      </button>
                      <button onClick={() => deleteBatch(b)} className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                        <Trash2 size={14} />
                      </button>
                    </div>
                  </div>
                ))}
                {subbatches.length === 0 && (
                  <div className="p-8 text-center text-slate-400 italic text-sm">No batches found</div>
                )}
              </div>

              <div className="p-3 border-t border-slate-100">
                <ActionButton
                  label="New Batch"
                  onClick={() => openCreateDialog('sub-batch')}
                  disabled={!courseId}
                  icon={Plus}
                  variant="primary"
                  size="small"
                />
              </div>
            </div>

            {/* Right Pane: Students */}
            <div className={`md:col-span-5 flex flex-col bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden ${mobileView !== 'details' ? 'hidden md:flex' : 'flex'}`}>
              <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex items-center gap-2">
                <button onClick={() => setMobileView('batches')} className="md:hidden p-1 -ml-1 text-slate-400">
                  <ChevronRight className="rotate-180" size={20} />
                </button>
                <div>
                  <h3 className="font-bold text-slate-700">{selectedSubBatch ? selectedSubBatch.code : 'Batch Details'}</h3>
                  <p className="text-xs text-slate-500">{selectedSubBatch ? `${batchStudents.length} students` : 'Select a batch to view students'}</p>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-4">
                {loading && selectedSubBatch ? (
                  <div className="flex justify-center p-8"><RefreshCw className="animate-spin text-indigo-500" /></div>
                ) : !selectedSubBatch ? (
                  <div className="text-center p-8 opacity-50">
                    <Users size={48} className="mx-auto mb-2 text-slate-300" />
                    <p className="text-sm">Select a batch from the list</p>
                  </div>
                ) : batchStudents.length === 0 ? (
                  <div className="text-center p-8 opacity-50">
                    <p className="text-sm">No students assigned to this batch</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {batchStudents.map((s, i) => (
                      <div key={s.id || i} className="flex items-center gap-3 p-3 rounded-xl border border-slate-100 hover:border-slate-200 hover:shadow-sm transition-all bg-white">
                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-xs font-bold text-slate-500">
                          {i + 1}
                        </div>
                        <div className="min-w-0 flex-1">
                          <p className="font-bold text-slate-700 text-sm truncate">{s.name}</p>
                          <p className="text-xs text-slate-500 truncate">{s.email}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>

          </div>
        </div>

      </div>

      {/* Create/Edit Modal */}
      <Modal isOpen={dialogOpen} onClose={() => setDialogOpen(false)} title={editBatch ? 'Edit Batch' : (createMode === 'group-only' ? 'New Batch Group' : 'New Sub-Batch')}>
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Group Name</label>
            <input
              type="text"
              className="lms-input"
              placeholder="e.g. 2024-2028 Batch A"
              value={batchForm.name}
              onChange={e => setBatchForm(prev => ({ ...prev, name: e.target.value }))}
            />
            <p className="text-xs text-slate-400 mt-1">This groups multiple sub-batches (theory, lab, etc.)</p>
          </div>

          {createMode !== 'group-only' && (
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Sub-Batch Code</label>
              <input
                type="text"
                className="lms-input"
                placeholder="e.g. A1, Lab-Group-1"
                value={batchForm.code}
                onChange={e => setBatchForm(prev => ({ ...prev, code: e.target.value }))}
              />
              <p className="text-xs text-slate-400 mt-1">Unique identifier for this specific batch segment</p>
            </div>
          )}

          <div className="flex justify-end gap-3 pt-4">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setDialogOpen(false)} />
            <ActionButton label="Save" variant="primary" onClick={saveBatch} disabled={!batchForm.name} />
          </div>
        </div>
      </Modal>

    </AdminLayout>
  );
};

export default BatchManagement;

import React, { useEffect, useRef, useState } from 'react';
import {
  Send, RefreshCw, MessageCircle, ArrowRight, Circle,
  Download, Filter, Search, User, Clock, Hash
} from 'lucide-react';
import axios from 'axios';
import { io } from 'socket.io-client';
import { useParams } from 'react-router-dom';
import AdminLayout from './AdminLayout';

const API_BASE = 'http://localhost:3000';
const SOCKET_URL = 'http://localhost:3000';

export default function ChatRoom() {
  const { courseId: urlCourseId } = useParams();

  // State
  const [courses, setCourses] = useState([]);
  const [loadingCourses, setLoadingCourses] = useState(true);
  const [coursesError, setCoursesError] = useState('');

  const [selectedCourse, setSelectedCourse] = useState(null);
  const [messages, setMessages] = useState([]);
  const [loadingMessages, setLoadingMessages] = useState(false);
  const [messagesError, setMessagesError] = useState('');

  const [input, setInput] = useState('');
  const [onlineUsers, setOnlineUsers] = useState(0);
  const [isConnected, setIsConnected] = useState(false);

  const endRef = useRef(null);
  const socketRef = useRef(null);
  const chatContainerRef = useRef(null);

  const token = localStorage.getItem('token') || '';
  const storedUser = (() => {
    try {
      return JSON.parse(localStorage.getItem('user') || '{}');
    } catch {
      return {};
    }
  })();

  // --- Utilities ---
  const messageKey = (m) => {
    if (!m) return '';
    if (m.id !== undefined && m.id !== null) return `id:${m.id}`;
    const uid = m.user_id ?? m.sender_id ?? m.userId ?? 'unknown';
    const txt = (m.message ?? m.msg ?? '').slice(0, 200);
    const t = m.created_at ?? m.createdAt ?? m.time ?? '';
    return `fallback:${uid}|${txt}|${t}`;
  };

  const appendMessageDedup = (msg) => {
    if (!msg) return;
    setMessages((prev) => {
      const setKeys = new Set(prev.map(messageKey));
      const k = messageKey(msg);
      if (setKeys.has(k)) return prev;
      return [...prev, msg];
    });
  };

  const formatMessageTime = (time) => {
    if (!time) return '';
    const date = new Date(time);
    const now = new Date();
    const diffMs = now - date;
    const diffMins = Math.floor(diffMs / 60000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffMs < 86400000) return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    return date.toLocaleDateString() + ' ' + date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const getRandomColor = (name) => {
    const colors = ['bg-indigo-500', 'bg-purple-500', 'bg-pink-500', 'bg-emerald-500', 'bg-amber-500', 'bg-blue-500'];
    const idx = (name || '').length % colors.length;
    return colors[idx];
  };

  // --- Fetch Courses ---
  const fetchCoursesFromBackend = async (headers) => {
    const res = await axios.get(`${API_BASE}/api/courses/get-all-courses`, { headers });
    const d = res.data;
    if (d.courses) return d.courses;
    if (Array.isArray(d)) return d;
    return [];
  };

  useEffect(() => {
    let cancelled = false;
    const loadCourses = async () => {
      setLoadingCourses(true);
      setCoursesError('');
      try {
        const headers = token ? { Authorization: `Bearer ${token}` } : {};
        const raw = await fetchCoursesFromBackend(headers);
        if (cancelled) return;
        const normalized = (raw || []).map(c => ({
          course_id: c.id ?? c.course_id ?? c.courseId ?? null,
          course_name: c.name ?? c.course_name ?? c.title ?? '',
          course_code: c.course_code ?? c.code ?? c.courseCode ?? '',
        })).filter(Boolean);

        setCourses(normalized);

        if (urlCourseId) {
          const found = normalized.find(x => String(x.course_id) === String(urlCourseId));
          if (found) setSelectedCourse(found);
          else if (normalized.length > 0) setSelectedCourse(normalized[0]);
        } else if (normalized.length > 0) {
          setSelectedCourse(normalized[0]);
        }
      } catch (err) {
        if (!cancelled) {
          setCourses([]);
          setCoursesError('Failed to load courses.');
        }
      } finally {
        if (!cancelled) setLoadingCourses(false);
      }
    };

    loadCourses();
    return () => { cancelled = true; };
  }, [urlCourseId]);

  // --- Socket Logic ---
  useEffect(() => {
    const s = io(SOCKET_URL, {
      transports: ['websocket'],
      auth: token ? { token } : undefined,
    });
    socketRef.current = s;

    s.on('connect', () => {
      setIsConnected(true);
      if (selectedCourse?.course_id) {
        s.emit('joinCourse', selectedCourse.course_id);
      }
    });

    s.on('disconnect', () => setIsConnected(false));
    s.on('connect_error', () => setIsConnected(false));
    s.on('userCountUpdate', (count) => setOnlineUsers(count));

    s.on('chatHistory', (hist) => {
      if (Array.isArray(hist)) {
        setMessages((prev) => {
          const existing = new Set(prev.map(messageKey));
          const merged = [...prev];
          hist.forEach((m) => {
            if (!existing.has(messageKey(m))) merged.push(m);
          });
          return merged.sort((a, b) => new Date(a.created_at || a.createdAt || 0) - new Date(b.created_at || b.createdAt || 0));
        });
      }
    });

    s.on('newCourseMessage', (msg) => appendMessageDedup(msg));

    return () => {
      s.disconnect();
      socketRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (!selectedCourse || !socketRef.current) return;
    if (socketRef.current.connected) {
      socketRef.current.emit('joinCourse', selectedCourse.course_id);
    }
  }, [selectedCourse, socketRef.current]);

  // --- Load Messages ---
  useEffect(() => {
    if (!selectedCourse) {
      setMessages([]);
      return;
    }

    let cancelled = false;
    const loadMessages = async () => {
      setLoadingMessages(true);
      setMessagesError('');
      try {
        const headers = token ? { Authorization: `Bearer ${token}` } : {};
        const res = await axios.get(`${API_BASE}/api/chats/course/${selectedCourse.course_id}`, { headers });
        if (!cancelled) {
          setMessages(Array.isArray(res.data.messages || res.data) ? (res.data.messages || res.data) : []);
        }
        if (socketRef.current?.connected) {
          socketRef.current.emit('joinCourse', selectedCourse.course_id);
        }
      } catch (err) {
        if (!cancelled) {
          setMessages([]);
          setMessagesError('Could not sync history.');
        }
      } finally {
        if (!cancelled) setLoadingMessages(false);
      }
    };

    loadMessages();
    return () => {
      cancelled = true;
      if (socketRef.current?.connected) {
        socketRef.current.emit('leaveCourse', selectedCourse?.course_id);
      }
    };
  }, [selectedCourse?.course_id]);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // --- Send Message ---
  const handleSend = async (e) => {
    e?.preventDefault();
    if (!selectedCourse) return;
    const txt = (input || '').trim();
    if (!txt) return;

    try {
      const headers = token ? { Authorization: `Bearer ${token}` } : {};

      // Optimistic append if socket is live
      if (socketRef.current?.connected) {
        socketRef.current.emit('sendMessage', {
          courseId: selectedCourse.course_id,
          message: txt,
          userId: storedUser.id,
          senderName: storedUser.name || 'Admin',
          senderRole: storedUser.role || 'admin'
        });
        setInput('');
      } else {
        // REST fallback
        const res = await axios.post(
          `${API_BASE}/api/chats/course/${selectedCourse.course_id}`,
          { message: txt },
          { headers }
        );
        const created = res.data.data ?? res.data.message ?? res.data;
        appendMessageDedup(created);
        setInput('');
      }
    } catch (err) {
      setMessagesError('Failed to send message.');
    }
  };

  const resolveSenderName = (m, isMe) => {
    if (isMe) return 'You';
    return m.sender_name || m.senderName || m.User?.name || m.user?.name || 'Unknown';
  };

  return (
    <AdminLayout>
      <div className="h-[calc(100vh-100px)] flex flex-col bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-200">

        {/* Top Header Bar */}
        <div className="bg-white border-b border-slate-100 p-4 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white shadow-md">
              <MessageCircle size={20} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-800">Course Chat</h1>
              <p className="text-xs text-slate-500 font-medium">
                {isConnected ? <span className="text-emerald-500 flex items-center gap-1"><Circle size={6} fill="currentColor" /> Live</span> : <span className="text-rose-500">Connecting...</span>}
                {selectedCourse && ` • ${selectedCourse.course_name}`}
              </p>
            </div>
          </div>

          <div className="flex gap-2">
            <button onClick={() => window.location.reload()} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors">
              <RefreshCw size={20} />
            </button>
          </div>
        </div>

        <div className="flex flex-1 overflow-hidden">

          {/* Sidebar - Course List */}
          <div className="w-80 bg-slate-50 border-r border-slate-200 flex flex-col hidden md:flex shrink-0">
            <div className="p-4 border-b border-slate-200">
              <h2 className="font-bold text-slate-700 mb-2 px-1">Courses</h2>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="text"
                  placeholder="Search courses..."
                  className="w-full pl-9 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                />
              </div>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1">
              {loadingCourses ? (
                <div className="p-4 text-center text-slate-400 text-sm">Loading...</div>
              ) : courses.map(course => (
                <button
                  key={course.course_id}
                  onClick={() => setSelectedCourse(course)}
                  className={`w-full text-left p-3 rounded-xl transition-all flex items-center gap-3 group ${selectedCourse?.course_id === course.course_id
                      ? 'bg-white shadow-md border border-indigo-100'
                      : 'hover:bg-slate-200/50'
                    }`}
                >
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold shrink-0 ${selectedCourse?.course_id === course.course_id
                      ? 'bg-indigo-600 text-white'
                      : 'bg-slate-200 text-slate-500 group-hover:bg-indigo-100 group-hover:text-indigo-600'
                    }`}>
                    {course.course_code?.substring(0, 2) || <Hash size={16} />}
                  </div>
                  <div className="overflow-hidden">
                    <h3 className={`font-bold text-sm truncate ${selectedCourse?.course_id === course.course_id ? 'text-indigo-700' : 'text-slate-700'}`}>
                      {course.course_name}
                    </h3>
                    <p className="text-xs text-slate-400 font-mono truncate">{course.course_code}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>

          {/* Main Chat Area */}
          <div className="flex-1 flex flex-col bg-slate-100/50 relative">

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 custom-scrollbar" ref={chatContainerRef}>
              {loadingMessages ? (
                <div className="flex justify-center py-10"><RefreshCw className="animate-spin text-indigo-400" /></div>
              ) : !selectedCourse ? (
                <div className="flex flex-col items-center justify-center h-full text-slate-400">
                  <MessageCircle size={48} className="mb-4 opacity-50" />
                  <p>Select a course to start chatting</p>
                </div>
              ) : messages.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-slate-400">
                  <p>No messages yet. Be the first to say hello!</p>
                </div>
              ) : (
                messages.map((m, i) => {
                  const myId = String(storedUser.id || '');
                  const msgUserId = String(m.user_id ?? m.sender_id ?? m.userId ?? '');
                  const isMe = msgUserId && myId && msgUserId === myId;
                  const name = resolveSenderName(m, isMe);

                  return (
                    <div key={m.id || i} className={`flex gap-3 ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                      {!isMe && (
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold text-white shadow-sm shrink-0 ${getRandomColor(name)}`}>
                          {name[0]}
                        </div>
                      )}

                      <div className={`flex flex-col max-w-[75%] ${isMe ? 'items-end' : 'items-start'}`}>
                        <div className="flex items-center gap-2 mb-1 px-1">
                          {!isMe && <span className="text-xs font-bold text-slate-600">{name}</span>}
                          <span className="text-[10px] text-slate-400 flex items-center gap-1">
                            {formatMessageTime(m.created_at || m.createdAt)}
                          </span>
                        </div>

                        <div className={`px-4 py-2.5 rounded-2xl shadow-sm text-sm leading-relaxed ${isMe
                            ? 'bg-indigo-600 text-white rounded-tr-none'
                            : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none'
                          }`}>
                          {m.message || m.msg}
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
              <div ref={endRef} />
            </div>

            {/* Input Area */}
            {selectedCourse && (
              <div className="p-4 bg-white border-t border-slate-200">
                <form onSubmit={handleSend} className="flex gap-2 items-end max-w-4xl mx-auto">
                  <div className="flex-1 bg-slate-100 rounded-2xl p-2 border border-transparent focus-within:border-indigo-300 focus-within:bg-white focus-within:ring-4 focus-within:ring-indigo-100 transition-all">
                    <input
                      type="text"
                      value={input}
                      onChange={e => setInput(e.target.value)}
                      placeholder={`Message #${selectedCourse.course_name}...`}
                      className="w-full bg-transparent border-none focus:ring-0 px-3 py-1.5 text-slate-700 placeholder:text-slate-400"
                    />
                  </div>
                  <button
                    type="submit"
                    disabled={!input.trim()}
                    className="p-3 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:shadow-none"
                  >
                    <Send size={20} />
                  </button>
                </form>
              </div>
            )}

          </div>
        </div>
      </div>
    </AdminLayout>
  );
}

// src/pages/CodingPage.jsx
import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useParams, useNavigate } from 'react-router-dom';

// Judge0 Configuration - FIXED
// Use environment variable with fallback
const JUDGE0_API_URL = import.meta.env.VITE_JUDGE0_URL || 'http://localhost:2358';
const RAPIDAPI_KEY = import.meta.env.VITE_RAPIDAPI_KEY || null;
const RAPIDAPI_HOST = import.meta.env.VITE_RAPIDAPI_HOST || 'judge0-ce.p.rapidapi.com';

// Use your backend URL for submissions (not used for routes here, we keep original hardcoded routes)
const BACKEND_API_URL = import.meta.env.VITE_API_URL || 'http://localhost:3000';

const JUDGE0_SUBMISSIONS_URL = `${JUDGE0_API_URL}/submissions`;
const JUDGE0_SUBMISSIONS_BATCH_URL = `${JUDGE0_API_URL}/submissions/batch`;

// Helper function to get Judge0 headers (supports both self-hosted and RapidAPI)
const getJudge0Headers = () => {
  const headers = {
    'Content-Type': 'application/json',
  };
  
  // Add RapidAPI headers if using RapidAPI
  if (RAPIDAPI_KEY && JUDGE0_API_URL.includes('rapidapi.com')) {
    headers['X-RapidAPI-Key'] = RAPIDAPI_KEY;
    headers['X-RapidAPI-Host'] = RAPIDAPI_HOST;
  }
  
  return headers;
};

const ACKS = [
  'I will not switch tabs or applications during the exam.',
  'I will not use copy/paste or external help.',
  'I understand the exam runs in fullscreen and exiting it will be treated as a violation.',
  'I will not use forbidden keys (Alt, Ctrl, Fn, Tab, Esc, F1–F12).',
  'I understand code may be auto-submitted when time for a question expires.',
];

// ✅ Single consistent mapping: DB language_id → Judge0 language_id + display name
const LANGUAGE_MAPPING = {
  62: { name: 'Java',       judge0Id: 62 },
  70: { name: 'Python 2',   judge0Id: 70 }, // Python 2.7
  71: { name: 'Python 3',   judge0Id: 71 }, // Python 3.8
  50: { name: 'C',          judge0Id: 50 },
  54: { name: 'C++',        judge0Id: 54 },
  63: { name: 'JavaScript', judge0Id: 63 },
  51: { name: 'C#',         judge0Id: 51 },
  60: { name: 'Go',         judge0Id: 60 },
  78: { name: 'Kotlin',     judge0Id: 78 },
  68: { name: 'PHP',        judge0Id: 68 },
};

const findLangName = (id) => {
  if (id === undefined || id === null) return 'Unknown';
  const mapping = LANGUAGE_MAPPING[id];
  if (mapping && mapping.name) return mapping.name;
  return `Language ID: ${id}`;
};

const formatJudgeResult = (res = {}, expected = '') => {
  const statusMessage = res.status?.description || 'Unknown Status';
  const statusId = res.status?.id || res.status_id || 0;
  const stdout = res.stdout ?? '';
  const compile_output = res.compile_output ?? '';
  const stderr = res.stderr ?? '';
  const time = res.time ?? '';
  const memory = res.memory ?? '';
  const message = res.message ?? '';

  let parts = [];

  console.log("🔍 Status ID check:", statusId);

  // Show status first
  parts.push(`Status: ${statusMessage}${statusId ? ` (ID: ${statusId})` : ''}`);

  if (compile_output) parts.push(`Compiler Output:\n${compile_output}`);
  if (stderr) parts.push(`Error Output:\n${stderr}`);

  parts.push(`Expected Output:\n${expected || '(no expected output)'}`);
  parts.push(`Actual Output:\n${stdout || '(no output)'}`);

  if (time) parts.push(`Time: ${time}s`);
  if (memory) parts.push(`Memory: ${memory}KB`);

  return {
    displayText: parts.join('\n\n'),
    stdout,
    compile_output,
    stderr,
    statusMessage,
    statusId,
    time,
    memory,
    raw: res
  };
};

const CodingPage = () => {
  const { courseId } = useParams();
  const navigate = useNavigate();
  const timerRef = useRef();

  const [questions, setQuestions] = useState([]);
  const [codes, setCodes] = useState({});
  const [results, setResults] = useState({});
  const [compiling, setCompiling] = useState({});
  const [submittedQuestions, setSubmittedQuestions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [pageError, setPageError] = useState('');
  const [exitLoading, setExitLoading] = useState(false);

  // Exam security states
  const [started, setStarted] = useState(false);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [violations, setViolations] = useState([]);
  const [escModal, setEscModal] = useState(false);
  const [locked, setLocked] = useState(false);
  const [fullscreen, setFullscreen] = useState(false);
  const [errorMsg, setErrorMsg] = useState([]);
  const [ackState, setAckState] = useState(() => ACKS.map(() => false));
  const [showWarning, setShowWarning] = useState(false);
  const [violationLimit, setViolationLimit] = useState(3);
  const [showFinalModal, setShowFinalModal] = useState(false);
  const [totalQuestions, setTotalQuestions] = useState(0);

  // Violation popup state
  const [showViolationPopup, setShowViolationPopup] = useState(false);
  const [remainingViolations, setRemainingViolations] = useState(null);
  const violationPopupTimeoutRef = useRef(null);

  // Judge0 custom input states
  const [useCustomInput, setUseCustomInput] = useState(false);
  const [customStdin, setCustomStdin] = useState('');

  // Student id extraction
  const studentId = (() => {
    try {
      const token = localStorage.getItem('token');
      if (!token) return null;
      const [, payload] = token.split('.');
      const decoded = JSON.parse(window.atob(payload));
      return decoded.id || decoded.student_id;
    } catch {
      return null;
    }
  })();

  // Fullscreen helpers
  const goFullScreen = (elem) => {
    if (elem.requestFullscreen) elem.requestFullscreen();
    else if (elem.webkitRequestFullscreen) elem.webkitRequestFullscreen();
    else if (elem.mozRequestFullScreen) elem.mozRequestFullScreen();
    else if (elem.msRequestFullscreen) elem.msRequestFullscreen();
    setFullscreen(true);
  };

  const exitFullScreen = () => {
    if (document.exitFullscreen) document.exitFullscreen();
    else if (document.webkitExitFullscreen) document.webkitExitFullscreen();
    else if (document.mozCancelFullScreen) document.mozCancelFullScreen();
    else if (document.msExitFullscreen) document.msExitFullscreen();
    setFullscreen(false);
  };

  // Violation logging
  const handleViolation = (reason) => {
    const timestamp = new Date().toLocaleTimeString();
    setViolations(prev => {
      const newV = [...prev, { reason, time: timestamp }];
      const limit = Math.max(0, Number(violationLimit || 3));
      const remaining = Math.max(0, limit - newV.length);
      setRemainingViolations(remaining);

      if (violationPopupTimeoutRef.current) {
        clearTimeout(violationPopupTimeoutRef.current);
        violationPopupTimeoutRef.current = null;
      }
      setShowViolationPopup(true);
      violationPopupTimeoutRef.current = setTimeout(() => {
        setShowViolationPopup(false);
        violationPopupTimeoutRef.current = null;
      }, 4000);

      if (newV.length === Math.max(0, limit - 1)) setShowWarning(true);
      if (newV.length >= Math.max(1, limit)) setShowFinalModal(true);
      return newV;
    });
  };

  // Cleanup
  useEffect(() => {
    return () => {
      if (violationPopupTimeoutRef.current) {
        clearTimeout(violationPopupTimeoutRef.current);
        violationPopupTimeoutRef.current = null;
      }
    };
  }, []);

  // Log Judge0 configuration on component mount
  useEffect(() => {
    console.log('🔧 ========== Judge0 Configuration ==========');
    console.log('📍 Judge0 API URL:', JUDGE0_API_URL);
    console.log('🔗 Submissions URL:', JUDGE0_SUBMISSIONS_URL);
    console.log('🔑 RapidAPI Key:', RAPIDAPI_KEY ? `${RAPIDAPI_KEY.substring(0, 10)}...` : 'Not set');
    console.log('🌐 RapidAPI Host:', RAPIDAPI_HOST);
    console.log('✅ Using RapidAPI:', JUDGE0_API_URL.includes('rapidapi.com'));
    console.log('📋 Headers:', getJudge0Headers());
    console.log('===========================================');
  }, []);

  const forceExitExam = () => navigate('/student/dashboard');

  // Security handlers
  useEffect(() => {
    if (!started) return;

    const handleContextMenu = (e) => {
      e.preventDefault();
      handleViolation('Right click / context menu');
    };

    const handleBlur = () => {
      handleViolation('Window lost focus / minimized');
      forceExitExam();
    };

    const handleFullscreen = () => {
      if (!document.fullscreenElement && !escModal) {
        setLocked(true);
        setEscModal(true);
        handleViolation('Exited fullscreen');
      }
    };

    const forbiddenKeys = [
      'Alt', 'Control', 'Tab', 'Fn',
      ...Array.from({ length: 12 }, (_, i) => 'F' + (i + 1))
    ];

    const handleKeydown = (e) => {
      if (locked) {
        e.preventDefault();
        return false;
      }

      if (e.key === 'Escape' || e.key === 'Esc' || e.key === 'Meta') {
        e.preventDefault();
        setLocked(true);
        setEscModal(true);
        return false;
      }

      if ((e.ctrlKey || e.metaKey) && ['c','v','x'].includes(e.key.toLowerCase())) {
        handleViolation(`Copy/Paste/Cut detected: ${e.key}`);
        e.preventDefault();
        return false;
      }

      if (forbiddenKeys.includes(e.key) || e.altKey || e.ctrlKey || e.metaKey) {
        handleViolation(`Forbidden key: ${e.key}`);
        e.preventDefault();
        return false;
      }
    };

    window.addEventListener('contextmenu', handleContextMenu);
    window.addEventListener('blur', handleBlur);
    document.addEventListener('fullscreenchange', handleFullscreen);
    window.addEventListener('keydown', handleKeydown, true);

    return () => {
      window.removeEventListener('contextmenu', handleContextMenu);
      window.removeEventListener('blur', handleBlur);
      document.removeEventListener('fullscreenchange', handleFullscreen);
      window.removeEventListener('keydown', handleKeydown, true);
    };
  }, [started, escModal, locked, violationLimit]);

  useEffect(() => {
    document.body.style.pointerEvents = locked ? 'none' : '';
    document.body.style.userSelect = locked ? 'none' : '';
    return () => {
      document.body.style.pointerEvents = '';
      document.body.style.userSelect = '';
    };
  }, [locked]);

  // Timer
  useEffect(() => {
    if (!started || questions.length === 0 || currentIdx >= questions.length) return;
    clearInterval(timerRef.current);
    const q = questions[currentIdx];
    const seconds = (Number(q.duration) || 10) * 60;
    setTimeLeft(seconds);
    timerRef.current = setInterval(() => setTimeLeft(t => t - 1), 1000);
    return () => clearInterval(timerRef.current);
  }, [currentIdx, questions, started]);

  useEffect(() => {
    if (timeLeft <= 0 && started && questions.length > 0 && currentIdx < questions.length) {
      (async () => {
        await handleAutoSubmit();
      })();
    }
  }, [timeLeft]);

  // Map question object → Judge0 language_id
  const getQuestionLanguageId = (q) => {
    if (!q) return null;

    const src = q.question ?? q.raw ?? q;

    const candidates = [
      src.language_id,
      src.languageId,
      src.language,
      src.lang_id,
      q.language_id,
      q.languageId,
      q.language,
      (src.Question && src.Question.language_id),
      (src.question && src.question.language_id),
    ];

    for (const c of candidates) {
      if (c !== undefined && c !== null) {
        const rawId = Number(c);
        const mapping = LANGUAGE_MAPPING[rawId];
        // ⭐ Map DB ID → Judge0 ID if present
        return mapping?.judge0Id || rawId;
      }
    }

    return null;
  };

  // ----------------- Judge0 Integration -----------------
  const sendToJudge0 = async ({ source, stdin = '', language_id }) => {
    console.log('🚀 ========== Judge0 Execution Started ==========');
    console.log('📍 Judge0 API URL:', JUDGE0_API_URL);
    console.log('🔑 Using RapidAPI:', JUDGE0_API_URL.includes('rapidapi.com'));
    console.log('📋 Request Details:', { 
      language_id, 
      source_length: source.length, 
      stdin_length: stdin.length,
      headers: getJudge0Headers()
    });
    
    try {
      console.log('📤 Step 1: Submitting code to Judge0...');
      console.log('Submitting to Judge0:', { language_id, source_length: source.length, stdin_length: stdin.length });

      const submissionData = {
        source_code: source,
        language_id: language_id,
        stdin: stdin,
        expected_output: null,
        cpu_time_limit: 5,
        memory_limit: 128000,
        stack_limit: 64000,
      };

      // Create submission
      console.log('📡 Step 2: Sending POST request to:', JUDGE0_SUBMISSIONS_URL);
      console.log('📦 Submission payload:', {
        language_id: submissionData.language_id,
        source_code_length: submissionData.source_code.length,
        stdin: submissionData.stdin,
        cpu_time_limit: submissionData.cpu_time_limit,
        memory_limit: submissionData.memory_limit
      });
      
      const createResponse = await axios.post(JUDGE0_SUBMISSIONS_URL, submissionData, {
        headers: getJudge0Headers(),
        timeout: 10000,
      });

      const token = createResponse.data.token;
      console.log('✅ Step 3: Submission created successfully!');
      console.log('🎫 Token received:', token);
      console.log('📊 Full response:', createResponse.data);

      // Poll for result
      console.log('⏳ Step 4: Starting to poll for execution result...');
      let result = null;
      let attempts = 0;
      const maxAttempts = 30;

      while (attempts < maxAttempts) {
        if (attempts > 0) {
          const delay = Math.min(1000 * (1 + attempts * 0.3), 2000);
          console.log(`⏸️  Waiting ${delay}ms before next poll attempt...`);
          await new Promise(resolve => setTimeout(resolve, delay));
        }

        try {
          const pollUrl = `${JUDGE0_SUBMISSIONS_URL}/${token}`;
          console.log(`🔍 Step 4.${attempts + 1}: Polling attempt ${attempts + 1}/${maxAttempts} - GET ${pollUrl}`);
          
          const resultResponse = await axios.get(pollUrl, {
            headers: getJudge0Headers(),
            timeout: 5000,
          });

          result = resultResponse.data;
          const statusId = result.status?.id || result.status_id;
          const statusDesc = result.status?.description || 'Unknown';
          
          console.log(`📊 Poll attempt ${attempts + 1} response:`, {
            statusId,
            statusDescription: statusDesc,
            hasStdout: !!result.stdout,
            hasStderr: !!result.stderr,
            hasCompileOutput: !!result.compile_output,
            time: result.time,
            memory: result.memory
          });
          console.log(`Poll attempt ${attempts + 1}: Status ID = ${statusId}, Description = ${statusDesc}`);

          // Status IDs: 1 = In Queue, 2 = Processing, others = Complete/Error
          if (result.status && result.status.id !== 1 && result.status.id !== 2) {
            console.log('✅ Step 5: Processing complete!');
            console.log('📋 Final result:', {
              status: result.status,
              stdout: result.stdout,
              stderr: result.stderr,
              compile_output: result.compile_output,
              time: result.time,
              memory: result.memory
            });
            console.log('Processing complete:', result);
            break;
          } else {
            console.log(`⏳ Still processing... (Status: ${statusDesc})`);
          }
        } catch (error) {
          console.warn(`⚠️  Error fetching result (attempt ${attempts + 1}), retrying...`, error.message);
          console.warn(`Error fetching result (attempt ${attempts + 1}), retrying...`, error.message);
          if (error.code === 'ECONNREFUSED' || error.code === 'ETIMEDOUT') {
            console.log('🔄 Connection issue detected, will retry...');
            // retry
          } else {
            console.error('❌ Unexpected error during polling:', error);
          }
        }

        attempts++;
      }

      if (!result) {
        console.error('❌ Step 6: Timeout - No result received after', maxAttempts, 'attempts');
        throw new Error('Timeout waiting for Judge0 result after 30 seconds');
      }

      if (result.status && result.status.id === 13) {
        console.error('⚠️  Step 6: Judge0 returned Internal Error:', {
          status: result.status,
          stderr: result.stderr,
          compile_output: result.compile_output,
          message: result.message
        });
        console.error('Judge0 returned Internal Error:', {
          status: result.status,
          stderr: result.stderr,
          compile_output: result.compile_output,
          message: result.message
        });
      }

      console.log('✅ Step 6: Judge0 execution completed successfully');
      console.log('📊 Final Judge0 result:', result);
      console.log('🏁 ========== Judge0 Execution Ended ==========');
      return result;

    } catch (error) {
      console.error('❌ ========== Judge0 Execution Failed ==========');
      console.error('🚨 Judge0 submission error:', error);
      console.error('📋 Error details:', {
        message: error.message,
        code: error.code,
        response: error.response?.data,
        status: error.response?.status,
        url: error.config?.url,
        method: error.config?.method,
        headers: error.config?.headers
      });
      console.error('Error details:', {
        message: error.message,
        code: error.code,
        response: error.response?.data,
        status: error.response?.status
      });

      if (error.code === 'ECONNREFUSED') {
        throw new Error('Judge0 server is not running. Please ensure Docker is running and Judge0 containers are started.');
      } else if (error.response) {
        const errorData = error.response.data;
        const errorMsg = typeof errorData === 'string' ? errorData : (errorData?.error || JSON.stringify(errorData));
        throw new Error(`Judge0 API error (${error.response.status}): ${errorMsg}`);
      } else if (error.request) {
        throw new Error('Cannot connect to Judge0 server. Check if the service is running on port 2358.');
      } else {
        throw new Error(`Judge0 error: ${error.message}`);
      }
    }
  };

  // Test Judge0 connection
  const testJudge0Connection = async () => {
    console.log('🔌 Testing Judge0 connection...');
    console.log('📍 Testing URL:', `${JUDGE0_API_URL}/languages`);
    console.log('🔑 Headers:', getJudge0Headers());
    
    try {
      const response = await axios.get(`${JUDGE0_API_URL}/languages`, { 
        headers: getJudge0Headers(),
        timeout: 5000 
      });
      console.log('✅ Judge0 connection test: SUCCESS');
      console.log('📊 Languages available:', response.data?.length || 0);
      console.log('Judge connection test:', response.data);
      return true;
    } catch (error) {
      console.error('❌ Judge0 connection test: FAILED');
      console.error('🚨 Error details:', {
        message: error.message,
        code: error.code,
        response: error.response?.data,
        status: error.response?.status
      });
      console.error('Judge connection test failed:', error);
      return false;
    }
  };

  const handleCompile = async (qid) => {
    console.log('🔨 ========== Compile Request Started ==========');
    console.log('📝 Question ID:', qid);
    setCompiling(c => ({ ...c, [qid]: true }));
    setResults(r => ({ ...r, [qid]: 'Compiling...' }));

    try {
      console.log('🔌 Testing Judge0 connection before compile...');
      const isConnected = await testJudge0Connection();
      if (!isConnected) {
        setResults(prev => ({
          ...prev,
          [qid]: 'Error: Cannot connect to Judge0 server. Please ensure Docker is running and Judge0 is started on port 2358.'
        }));
        setCompiling(c => ({ ...c, [qid]: false }));
        return;
      }

      const code = codes[qid];
      if (!code || !code.trim()) {
        setResults(prev => ({ ...prev, [qid]: 'Error: Code is empty. Please write some code before running.' }));
        setCompiling(c => ({ ...c, [qid]: false }));
        return;
      }

      const currentQuestion = questions.find(q => q.id === qid);
      const langForQuestion = getQuestionLanguageId(currentQuestion);

      if (!langForQuestion) {
        setResults(prev => ({ ...prev, [qid]: `This question does not have an assigned language. Contact your instructor.` }));
        setCompiling(c => ({ ...c, [qid]: false }));
        return;
      }

      console.log('📤 Sending code to Judge0 for compilation...');
      const res = await sendToJudge0({
        source: code,
        stdin: useCustomInput ? customStdin : (currentQuestion?.sample_input || ''),
        language_id: langForQuestion
      });

      console.log('✅ Compilation result received');
      const formatted = formatJudgeResult(res, currentQuestion.sample_output);
      console.log('📋 Formatted result:', formatted);
      setResults(prev => ({ ...prev, [qid]: formatted.displayText }));
      console.log('🏁 ========== Compile Request Completed ==========');
    } catch (err) {
      console.error('❌ ========== Compile Request Failed ==========');
      console.error('Compile error:', err);
      setResults(prev => ({
        ...prev,
        [qid]: `Compile/Run Error: ${err.message}\n\nPlease ensure:\n1. Docker is running\n2. Judge0 is started: docker run -d -p 2358:2358 judge0/judge0:1.13.0\n3. Port 2358 is available`
      }));
    }
    setCompiling(c => ({ ...c, [qid]: false }));
  };

  const handleRun = async (qid, sample_input) => {
    console.log('▶️  ========== Run Request Started ==========');
    console.log('📝 Question ID:', qid);
    console.log('📥 Sample input:', sample_input);
    setCompiling(c => ({ ...c, [qid]: true }));
    setResults(r => ({ ...r, [qid]: 'Running...' }));

    try {
      const code = codes[qid];
      if (!code || !code.trim()) {
        setResults(prev => ({ ...prev, [qid]: 'Error: Code is empty. Please write some code before running.' }));
        setCompiling(c => ({ ...c, [qid]: false }));
        return;
      }

      const currentQuestion = questions.find(q => q.id === qid);
      const langForQuestion = getQuestionLanguageId(currentQuestion);

      if (!langForQuestion) {
        setResults(prev => ({ ...prev, [qid]: `This question does not have an assigned language. Contact your instructor.` }));
        setCompiling(c => ({ ...c, [qid]: false }));
        return;
      }

      const stdin = useCustomInput ? customStdin : (sample_input || '');
      console.log('📤 Sending code to Judge0 for execution...');
      console.log('📥 Using input:', stdin);
      const res = await sendToJudge0({
        source: code,
        stdin,
        language_id: langForQuestion
      });

      console.log('✅ Execution result received');
      const formatted = formatJudgeResult(res, currentQuestion.sample_output);
      console.log('📋 Formatted result:', formatted);
      setResults(prev => ({ ...prev, [qid]: formatted.displayText }));
      console.log('🏁 ========== Run Request Completed ==========');
    } catch (err) {
      console.error('❌ ========== Run Request Failed ==========');
      console.error('Run error:', err);
      setResults(prev => ({
        ...prev,
        [qid]: `Run Error: ${err.message}\n\nPlease check if Judge0 is running properly.`
      }));
    }
    setCompiling(c => ({ ...c, [qid]: false }));
  };

  const handleSubmit = async (qid, sample_input, sample_output) => {
    setCompiling(c => ({ ...c, [qid]: true }));
    setResults(r => ({ ...r, [qid]: 'Submitting...' }));

    try {
      const code = codes[qid];
      if (!code || !code.trim()) {
        setResults(prev => ({ ...prev, [qid]: 'Error: Code is empty. Please write some code before submitting.' }));
        setCompiling(c => ({ ...c, [qid]: false }));
        return;
      }

      const currentQuestion = questions.find(q => q.id === qid);
      const langForQuestion = getQuestionLanguageId(currentQuestion);

      if (!langForQuestion) {
        setResults(prev => ({ ...prev, [qid]: `Cannot submit: no language assigned to this question.` }));
        setCompiling(c => ({ ...c, [qid]: false }));
        return;
      }

      const stdin = useCustomInput ? customStdin : (sample_input || '');
      console.log('📤 ========== Submit Request Started ==========');
      console.log('📝 Question ID:', qid);
      console.log('📥 Using input:', stdin);
      console.log('📤 Sending code to Judge0 for submission...');
      const judgeResp = await sendToJudge0({
        source: code,
        stdin,
        language_id: langForQuestion
      });
      console.log('✅ Submission result received from Judge0');

      const formatted = formatJudgeResult(judgeResp, currentQuestion.sample_output);
      const statusMessage = judgeResp.status ? judgeResp.status.description : 'Unknown Status';

      const token = localStorage.getItem('token');

      // ✅ Keep your original route exactly
      await axios.post(
        'http://localhost:3000/api/submissions/submit',
        {
          code,
          language_id: Number(langForQuestion),
          question_id: qid,
          course_id: courseId,
          student_id: studentId,
          jwt_token: token,
          sample_input: stdin,
          sample_output: currentQuestion.sample_output,
          judge_result: judgeResp
        },
        { headers: { Authorization: token ? `Bearer ${token}` : '' } }
      );

      // Mark as submitted
      setSubmittedQuestions(prev => [...new Set([...prev, qid])]);

      // Remove submitted question
      const newQuestions = questions.filter(q => q.id !== qid);
      setQuestions(newQuestions);

      setCodes(prev => {
        const next = { ...prev };
        delete next[qid];
        return next;
      });

      setCurrentIdx((prevIdx) => {
        if (newQuestions.length === 0) return 0;
        return prevIdx > newQuestions.length - 1 ? Math.max(0, newQuestions.length - 1) : prevIdx;
      });

      setResults(prev => ({
        ...prev,
        [qid]: `✅ Submission Complete!\nJudge0 Status: ${statusMessage}\n\n${formatted.displayText}`
      }));
    } catch (err) {
      console.error('Submission error:', err);
      setResults(prev => ({
        ...prev,
        [qid]: `Submission Error: ${err.response?.data?.message || err.message}\n\nCode was saved but Judge0 execution failed.`
      }));
    }
    setCompiling(c => ({ ...c, [qid]: false }));
  };

  const handleAutoSubmit = async () => {
    const q = questions[currentIdx];
    if (!q) {
      if (currentIdx + 1 < questions.length) setCurrentIdx(currentIdx + 1);
      else handleFinalSubmit();
      return;
    }
    await handleSubmit(q.id, q.sample_input, q.sample_output);
    if (currentIdx + 1 < questions.length) setCurrentIdx(currentIdx + 1);
    else handleFinalSubmit();
  };

  const handleFinalSubmit = async () => {
    const currentQ = questions[currentIdx];
    if (currentQ) {
      await handleSubmit(currentQ.id, currentQ.sample_input, currentQ.sample_output);
    }
    exitFullScreen();
    navigate('/student/dashboard');
  };

  // Data fetching
  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setPageError('');
      try {
        const token = localStorage.getItem('token');
        const headers = token ? { Authorization: `Bearer ${token}` } : {};

        // ✅ Keep your original routes
        const qResp = await axios.get(
          `http://localhost:3000/api/submissions/student-questions/${courseId}`,
          { headers }
        );

        let fetchedQuestions = [];
        if (qResp && qResp.data) {
          if (Array.isArray(qResp.data)) fetchedQuestions = qResp.data;
          else if (Array.isArray(qResp.data.questions)) fetchedQuestions = qResp.data.questions;
          else if (Array.isArray(qResp.data.data)) fetchedQuestions = qResp.data.data;
        }
        fetchedQuestions = Array.isArray(fetchedQuestions) ? fetchedQuestions : [];

        // Normalize questions
        const normalized = fetchedQuestions.map(q => {
          const src = q.question ?? q;
          const id = src.id ?? q.id;
          const language_id = getQuestionLanguageId(q) ?? null;
          const duration = src.duration ?? q.duration ?? 10;
          const sample_input = src.sample_input ?? src.stdin ?? q.sample_input ?? '';
          const sample_output = src.sample_output ?? src.stdout ?? q.sample_output ?? '';
          const title = src.title ?? q.title ?? 'Untitled';
          const description = src.description ?? q.description ?? '';
          const score = src.score ?? q.score ?? null;
          return {
            ...q,
            id,
            title,
            description,
            sample_input,
            sample_output,
            duration,
            language_id,
            score,
            raw: src,
          };
        });

        setQuestions(normalized);
        setCodes(Object.fromEntries(normalized.map(q => [q.id, ''])));
        setResults({});
        setSubmittedQuestions([]);
        setTotalQuestions(normalized.length);

        // Course details for violation limit
        try {
          const courseResp = await axios.get(
            `http://localhost:3000/api/courses/get-course/${courseId}`,
            { headers }
          );
          const courseData = courseResp?.data?.course ? courseResp.data.course : courseResp.data;
          if (courseData && typeof courseData.allowed_violations !== 'undefined') {
            setViolationLimit(Number(courseData.allowed_violations) || 3);
          } else {
            setViolationLimit(3);
          }
        } catch (err) {
          setViolationLimit(3);
        }

        // Test Judge0 connection on load
        const isJudge0Connected = await testJudge0Connection();
        if (!isJudge0Connected) {
          console.warn('Judge0 is not connected. Code execution will fail.');
        }

      } catch (err) {
        console.error('Could not load questions:', err);
        setPageError(`Could not load questions. (${err.response?.data?.message || err.message})`);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [courseId]);

  const handleExit = () => {
    setExitLoading(true);
    setEscModal(true);
    exitFullScreen();
    setTimeout(() => navigate('/student/dashboard'), 300);
  };

  const handleEscContinue = () => {
    setEscModal(false);
    setLocked(false);
    setExitLoading(false);
    setTimeout(() => goFullScreen(document.documentElement), 100);
  };

  const handleEscFinalSubmit = () => {
    setEscModal(false);
    setLocked(true);
    handleFinalSubmit();
  };

  // --- UI & render ---
  if (!started) {
    return (
      <div style={{
        position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        backgroundColor: '#f4fafd',
        padding: 16,
      }}>
        <div style={{
          width: '100%', maxWidth: 1100, margin: '0 auto', backgroundColor: '#fff',
          padding: '2rem', borderRadius: 12, boxShadow: '0 6px 30px rgba(0,0,0,0.08)'
        }}>
          <h2 style={{ color: '#1976d2', marginBottom: 12, textAlign: 'center' }}>Exam Instructions & Acknowledgements</h2>
          <p style={{ color: '#333', marginBottom: 12 }}>
            Read the following carefully. You must acknowledge all items to start the exam.
          </p>

          <ul style={{ listStyle: 'none', padding: 0, marginBottom: 18 }}>
            {ACKS.map((text, i) => (
              <li key={i} style={{ marginBottom: 10, display: 'flex', alignItems: 'center', gap: 12 }}>
                <input
                  type="checkbox"
                  checked={ackState[i]}
                  onChange={() => setAckState(prev => prev.map((v, idx) => idx === i ? !v : v))}
                />
                <span style={{ color: '#111' }}>{text}</span>
              </li>
            ))}
          </ul>

          <div style={{ display: 'flex', gap: 12, alignItems: 'center', justifyContent: 'center' }}>
            <button
              onClick={() => setAckState(ACKS.map(() => true))}
              style={{
                backgroundColor: '#e2e4ecff', border: 'none', padding: '8px 14px', borderRadius: 6, cursor: 'pointer'
              }}
            >
              Acknowledge All
            </button>

            <button
              onClick={() => {
                if (ackState.every(Boolean)) {
                  goFullScreen(document.documentElement);
                  setStarted(true);
                }
              }}
              disabled={!ackState.every(Boolean)}
              style={{
                backgroundColor: ackState.every(Boolean) ? '#32bb5fff' : '#36be24da',
                color: '#0b0c0bff',
                border: 'none',
                padding: '10px 18px',
                borderRadius: 8,
                cursor: ackState.every(Boolean) ? 'pointer' : 'not-allowed',
                fontWeight: 700
              }}
            >
              Start Exam
            </button>

            <button
              onClick={() => navigate('/student/dashboard')}
              style={{
                backgroundColor: '#f2f3f6ff',
                border: '1px solid #0100005f',
                padding: '10px 16px',
                borderRadius: 8,
                cursor: 'pointer'
              }}
            >
              Cancel
            </button>
          </div>

          <p style={{ marginTop: 12, color: '#666', fontSize: 13, textAlign: 'center' }}>
            Total visible questions for you: <strong>{totalQuestions}</strong>
          </p>
        </div>
      </div>
    );
  }

  if (loading) return <div style={{ padding: 20 }}>Loading questions.</div>;
  if (pageError) return <div style={{ color: 'red', padding: 20 }}>{pageError}</div>;
  if (!studentId) return <div style={{ color: 'red', padding: 20 }}>You must log in to attempt this exam.</div>;

  if (questions.length === 0) {
    return (
      <div style={{ padding: '1rem', textAlign: 'center', fontWeight: 'bold' }}>
        ✅ You have submitted all visible questions for this course or no toggled questions are available.
        <br />
        <button
          onClick={() => navigate('/student/dashboard')}
          style={{
            marginTop: 16,
            padding: '10px 24px',
            fontWeight: 600,
            fontSize: 16,
            borderRadius: 6,
            border: 'none',
            backgroundColor: '#1976d2',
            color: '#fff',
            cursor: 'pointer',
          }}
        >
          Go to Dashboard
        </button>
      </div>
    );
  }

  const currentQuestion = questions && questions.length > 0 && currentIdx >= 0 && currentIdx < questions.length
    ? questions[currentIdx]
    : null;

  if (!currentQuestion) {
    return (
      <div style={{ padding: 20, textAlign: 'center' }}>
        Loading question...
      </div>
    );
  }

  const minutes = Math.floor(Math.max(0, timeLeft) / 60);
  const seconds = Math.max(0, timeLeft) % 60;

  const currentQuestionLangId = getQuestionLanguageId(currentQuestion) ?? null;
  const currentQuestionLangName = currentQuestionLangId ? findLangName(currentQuestionLangId) : 'Not assigned';

  return (
    <div style={{
      minHeight: '100vh',
      width: '100vw',
      backgroundColor: '#f4fafd',
      color: '#111',
      paddingBottom: 32,
      paddingTop: 20,
      boxSizing: 'border-box',
    }}>
      {/* Sticky header */}
      <header style={{
        position: 'sticky', top: 0, zIndex: 10,
        backgroundColor: '#0b2376', color: '#fff',
        padding: '10px 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <h3 style={{ margin: 0, fontSize: 18 }}>Coding Exam</h3>
          <div style={{ padding: '6px 10px', background: '#ffc107', color: '#000', borderRadius: 20, fontWeight: 700 }}>
            Time left: {minutes}:{String(seconds).padStart(2, '0')}
          </div>
          <div style={{ marginLeft: 12, opacity: 0.9 }}>
            Question {currentIdx + 1} / {questions.length}
          </div>
        </div>

        <div>
          <button onClick={handleExit} disabled={exitLoading} style={{
            padding: '6px 12px', marginLeft: 8, background: '#fff', color: '#0b2376', borderRadius: 6, border: 'none', cursor: 'pointer'
          }}>
            {exitLoading ? 'Exiting.' : 'Exit'}
          </button>
        </div>
      </header>

      {/* Two column layout */}
      <div style={{ display: 'flex', gap: 16, padding: '18px', maxWidth: 1400, margin: '0 auto' }}>
        {/* LEFT PANEL */}
        <aside style={{
          width: '40%', background: '#fff', borderRadius: 8, padding: 18, boxShadow: '0 6px 18px rgba(3,102,214,0.06)', overflowY: 'auto', maxHeight: '75vh'
        }}>
          <div style={{ marginBottom: 12 }}>
            <h2 style={{ margin: 0, color: '#0b2376' }}>{currentQuestion.title}</h2>
            <div style={{ marginTop: 8, color: '#333', fontSize: 13 }}>
              <strong>Course:</strong> {courseId}
            </div>
            <div style={{ marginTop: 6, color: '#333', fontSize: 13 }}>
              <strong>Language:</strong> {currentQuestionLangName}
            </div>
            <div style={{ marginTop: 6, color: '#333', fontSize: 13 }}>
              <strong>Score:</strong> {currentQuestion.score ?? 'N/A'}
            </div>
          </div>

          <div style={{ marginTop: 12, color: '#222' }} dangerouslySetInnerHTML={{ __html: currentQuestion.description || '' }} />

          {currentQuestion.sample_input && (
            <>
              <div style={{ marginTop: 14, fontWeight: 700 }}>Sample Input</div>
              <pre style={{ background: '#f6f8ff', padding: 10, borderRadius: 6, fontFamily: 'monospace' }}>
                {currentQuestion.sample_input}
              </pre>
            </>
          )}

          {currentQuestion.sample_output && (
            <>
              <div style={{ marginTop: 10, fontWeight: 700 }}>Sample Output</div>
              <pre style={{ background: '#f6f8ff', padding: 10, borderRadius: 6, fontFamily: 'monospace' }}>
                {currentQuestion.sample_output}
              </pre>
            </>
          )}

          {currentQuestion.explanation && (
            <>
              <div style={{ marginTop: 10, fontWeight: 700 }}>Explanation</div>
              <div style={{ marginTop: 6 }}>{currentQuestion.explanation}</div>
            </>
          )}
        </aside>

        {/* RIGHT PANEL */}
        <section style={{ width: '60%', display: 'flex', flexDirection: 'column', gap: 12 }}>
          {/* Quick jump */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
            {questions.map((_, idx) => (
              <button
                key={idx}
                onClick={() => setCurrentIdx(idx)}
                style={{
                  width: 36, height: 36, borderRadius: '50%',
                  background: idx === currentIdx ? '#1976d2' : '#e6eefc',
                  color: idx === currentIdx ? '#fff' : '#0b2376', border: 'none', cursor: 'pointer'
                }}
                title={`Go to question ${idx + 1}`}
              >
                {idx + 1}
              </button>
            ))}
            <div style={{ marginLeft: 'auto', fontSize: 13, color: '#333' }}>
              {submittedQuestions.length} attempted / {totalQuestions} total
            </div>
          </div>

          {/* Editor card */}
          <div style={{ background: '#fff', borderRadius: 8, padding: 12, boxShadow: '0 6px 18px rgba(3,102,214,0.06)', display: 'flex', flexDirection: 'column', gap: 12 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, justifyContent: 'space-between' }}>
              <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                <div style={{ padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontWeight: 700, background: '#f3f4f6' }}>
                  {currentQuestionLangName}
                </div>
                <div style={{ color: '#666', fontSize: 13 }}>Compiler</div>
              </div>

              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <input type="checkbox" checked={useCustomInput} onChange={e => setUseCustomInput(e.target.checked)} />
                  <span style={{ fontSize: 13 }}>Use Custom Input</span>
                </label>
              </div>
            </div>

            <textarea
              value={codes[currentQuestion.id] ?? ''}
              onChange={e => setCodes(prev => ({ ...prev, [currentQuestion.id]: e.target.value }))}
              style={{
                width: '100%', minHeight: 420, fontFamily: 'monospace',
                fontSize: 14, padding: 12, borderRadius: 6, border: '1px solid #dbeafe', boxSizing: 'border-box'
              }}
              placeholder="// Write your solution here"
            />

            {useCustomInput && (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                <div style={{ fontWeight: 700 }}>Custom Input</div>
                <textarea
                  value={customStdin}
                  onChange={e => setCustomStdin(e.target.value)}
                  style={{ minHeight: 80, fontFamily: 'monospace', padding: 8, borderRadius: 6, border: '1px solid #e6eefc' }}
                  placeholder="Enter input that will be passed to your program when running/submitting"
                />
              </div>
            )}

            <div style={{ minHeight: 120, background: '#f7fafc', border: '1px solid #e6eefc', padding: 10, borderRadius: 6, fontFamily: 'monospace', whiteSpace: 'pre-wrap', color: '#0b2376' }}>
              {typeof results[currentQuestion.id] === 'string'
                ? results[currentQuestion.id]
                : (results[currentQuestion.id] ? results[currentQuestion.id] : 'Output / compiler messages will appear here.')}
            </div>

            <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
              <button
                onClick={() => handleCompile(currentQuestion.id)}
                disabled={!!compiling[currentQuestion.id]}
                style={{
                  padding: '10px 16px', borderRadius: 6, border: '2px solid #1976d2', background: '#fff', color: '#1976d2', fontWeight: 700, cursor: 'pointer'
                }}
              >
                {compiling[currentQuestion.id] ? 'Compiling...' : 'Compile & Test'}
              </button>

              <button
                onClick={() => handleRun(currentQuestion.id, currentQuestion.sample_input)}
                disabled={!!compiling[currentQuestion.id]}
                style={{
                  padding: '10px 16px', borderRadius: 6, border: '2px solid #1976d2', background: '#def0fe', color: '#1976d2', fontWeight: 700, cursor: 'pointer'
                }}
              >
                {compiling[currentQuestion.id] ? 'Running...' : 'Run'}
              </button>

              <button
                onClick={() => handleSubmit(currentQuestion.id, currentQuestion.sample_input, currentQuestion.sample_output)}
                disabled={!!compiling[currentQuestion.id]}
                style={{
                  padding: '10px 16px', borderRadius: 6, background: '#0b66c3', color: '#fff', border: 'none', fontWeight: 700, cursor: 'pointer'
                }}
              >
                {compiling[currentQuestion.id] ? 'Submitting.' : 'Submit Code'}
              </button>

              <div style={{ marginLeft: 'auto', display: 'flex', gap: 8 }}>
                <button
                  onClick={() => { setCodes(prev => ({ ...prev, [currentQuestion.id]: '' })); setResults(prev => ({ ...prev, [currentQuestion.id]: '' })); }}
                  style={{ padding: '8px 12px', borderRadius: 6, border: '1px solid #e2e8f0', background: '#fff', cursor: 'pointer' }}
                >
                  Clear
                </button>
              </div>
            </div>
          </div>

          {/* Prev / Next and Finish */}
          <div style={{ display: 'flex', justifyContent: 'space-between', gap: 8 }}>
            <div>
              <button
                disabled={currentIdx === 0}
                onClick={() => setCurrentIdx(i => i - 1)}
                style={{ padding: '8px 12px', borderRadius: 6, cursor: currentIdx === 0 ? 'not-allowed' : 'pointer' }}
              >
                Previous
              </button>
            </div>

            <div style={{ display: 'flex', gap: 8 }}>
              <button
                disabled={currentIdx === questions.length - 1}
                onClick={() => setCurrentIdx(i => i + 1)}
                style={{ padding: '8px 12px', borderRadius: 6, cursor: currentIdx === questions.length - 1 ? 'not-allowed' : 'pointer' }}
              >
                Next
              </button>

              <button
                onClick={handleFinalSubmit}
                style={{ padding: '8px 12px', borderRadius: 6, background: '#0b66c3', color: '#fff', cursor: 'pointer' }}
              >
                Finish Exam
              </button>
            </div>
          </div>
        </section>
      </div>

      {/* Violations UI */}
      {violations.length > 0 && (
        <div style={{ maxWidth: 1400, margin: '12px auto', padding: 12, background: '#fff3f2', borderRadius: 8, border: '1px solid #fde2e2' }}>
          <strong style={{ color: '#b71c1c' }}>Security Warnings</strong>
          <ul>
            {violations.map((v, i) => <li key={i}>{v.time} — {v.reason}</li>)}
          </ul>
          <div style={{ marginTop: 8, color: '#333', fontSize: 13 }}>
            Allowed violations for this course: <strong>{violationLimit ?? 3}</strong>
          </div>
        </div>
      )}

      {/* Violation Remaining Popup */}
      {showViolationPopup && (
        <div style={{
          position: 'fixed',
          right: 20,
          top: 80,
          zIndex: 12000,
          background: '#fff',
          border: '1px solid #fbcaca',
          boxShadow: '0 8px 30px rgba(0,0,0,0.15)',
          padding: '12px 16px',
          borderRadius: 8,
          minWidth: 240
        }}>
          <div style={{ fontWeight: 800, color: '#b71c1c', marginBottom: 6 }}>Security Violation</div>
          <div style={{ fontSize: 14, color: '#333' }}>
            You committed a violation. Remaining allowed violations: <strong>{remainingViolations !== null ? remainingViolations : (violationLimit ?? 3)}</strong>
          </div>
          <div style={{ marginTop: 10, textAlign: 'right' }}>
            <button onClick={() => { setShowViolationPopup(false); if (violationPopupTimeoutRef.current) { clearTimeout(violationPopupTimeoutRef.current); violationPopupTimeoutRef.current = null; } }} style={{ padding: '6px 10px', borderRadius: 6, border: 'none', background: '#1976d2', color: '#fff', cursor: 'pointer' }}>OK</button>
          </div>
        </div>
      )}

      {/* showWarning modal */}
      {showWarning && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ background: '#fff', padding: 20, borderRadius: 8, maxWidth: 420 }}>
            <h3 style={{ marginTop: 0, color: '#b71c1c' }}>Warning</h3>
            <p>You are one violation away from automatic submission. Please avoid further violations.</p>
            <div style={{ textAlign: 'right' }}>
              <button onClick={() => setShowWarning(false)} style={{ padding: '8px 12px' }}>Continue</button>
            </div>
          </div>
        </div>
      )}

      {/* showFinalModal */}
      {showFinalModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ background: '#fff', padding: 20, borderRadius: 8, maxWidth: 420 }}>
            <h3 style={{ marginTop: 0, color: '#b71c1c' }}>Exam Ended</h3>
            <p>You exceeded the maximum number of violations. Your exam will be submitted now.</p>
            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
              <button onClick={handleFinalSubmit} style={{ padding: '8px 12px', background: '#1976d2', color: '#fff', borderRadius: 6 }}>Submit & Exit</button>
            </div>
          </div>
        </div>
      )}

      {/* ESC modal */}
      {escModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ background: '#fff', padding: 20, borderRadius: 8, maxWidth: 420 }}>
            <h4 style={{ marginBottom: '1rem', color: '#1976d2' }}>You pressed Esc / exited fullscreen</h4>
            <p>Do you want to submit your code now or continue (re-enter fullscreen)?</p>
            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
              <button onClick={handleEscFinalSubmit} style={{ padding: '10px 16px', backgroundColor: '#dc3545', color: '#fff', borderRadius: 6 }}>Final Submit</button>
              <button onClick={handleEscContinue} style={{ padding: '10px 16px', backgroundColor: '#28a745', color: '#fff', borderRadius: 6 }}>Continue</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CodingPage;

import React, { useState, useEffect, useCallback } from 'react';
import {
  Search, Plus, Filter, Download, RefreshCw, Layers, Edit, Trash2,
  Users, CheckCircle, XCircle, MoreVertical, BookOpen, AlertCircle,
  ChevronLeft, ChevronRight, X, UserPlus, Fingerprint
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import axios from 'axios';
import AdminLayout from './AdminLayout';

// --- API Endpoints ---
const API_COURSES = 'http://localhost:3000/api/courses/getActiveandInactiveCourses';
const API_FACULTIES = 'http://localhost:3000/api/v1/users/faculties';

// --- Components ---

const Modal = ({ isOpen, onClose, title, children, footer }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
        />
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className="relative w-full max-w-xl bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden flex flex-col max-h-[90vh]"
        >
          <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between bg-slate-50">
            <h3 className="text-lg font-bold text-slate-800">{title}</h3>
            <button onClick={onClose} className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors">
              <X size={20} />
            </button>
          </div>
          <div className="p-6 overflow-y-auto custom-scrollbar">
            {children}
          </div>
          {footer && (
            <div className="px-6 py-4 border-t border-slate-100 bg-slate-50 flex justify-end gap-3">
              {footer}
            </div>
          )}
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const ToggleSwitch = ({ checked, onChange, disabled }) => (
  <button
    onClick={() => !disabled && onChange(!checked)}
    className={`relative w-12 h-6 rounded-full transition-colors duration-200 ${checked ? 'bg-emerald-500' : 'bg-slate-300'} ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
  >
    <span
      className={`absolute top-1 left-1 bg-white w-4 h-4 rounded-full shadow-sm transition-transform duration-200 ${checked ? 'translate-x-6' : 'translate-x-0'}`}
    />
  </button>
);

const Toast = ({ message, type = 'success', onClose }) => {
  useEffect(() => { const t = setTimeout(onClose, 4000); return () => clearTimeout(t); }, [onClose]);
  const bg = type === 'success' ? 'bg-emerald-500' : type === 'error' ? 'bg-rose-500' : 'bg-amber-500';
  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 20 }} className={`fixed bottom-6 right-6 z-50 px-6 py-3 rounded-xl shadow-lg flex items-center gap-3 text-white font-bold ${bg}`}>
      <span>{message}</span>
      <button onClick={onClose}><X size={16} /></button>
    </motion.div>
  );
};

export default function CourseManagement() {
  // State
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [nameFilter, setNameFilter] = useState('');
  const [showInactive, setShowInactive] = useState(false);
  const [toast, setToast] = useState(null);

  // Pagination
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);

  // Dialogs
  const [openAdd, setOpenAdd] = useState(false);
  const [openEdit, setOpenEdit] = useState(false);
  const [openAssign, setOpenAssign] = useState(false);

  // Forms
  const [courseForm, setCourseForm] = useState({ name: '', course_code: '', description: '', is_active: true, allowed_violations: 3 });
  const [editingId, setEditingId] = useState(null);

  // Assign Faculty
  const [assignCourseId, setAssignCourseId] = useState(null);
  const [faculties, setFaculties] = useState([]);
  const [selectedFacultyIds, setSelectedFacultyIds] = useState([]);

  const showToast = (msg, type = 'success') => setToast({ msg, type });

  const getAuthHeader = useCallback(() => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  }, []);

  // Fetch Data
  const fetchCourses = async () => {
    setLoading(true);
    try {
      const res = await axios.get(API_COURSES, { headers: getAuthHeader() });
      const payload = res.data || {};
      const all = Array.isArray(payload) ? payload : (Array.isArray(payload.courses) ? payload.courses : []);
      setCourses(all);
    } catch (err) {
      showToast('Failed to load courses', 'error');
    } finally {
      setLoading(false);
    }
  };

  const fetchFaculties = async () => {
    try {
      const res = await axios.get(API_FACULTIES, { headers: getAuthHeader() });
      const list = (res.data?.faculties || []).map((f) => ({ ...f, id: Number(f.id) }));
      setFaculties(list);
    } catch (err) {
      console.warn('fetchFaculties', err);
    }
  };

  useEffect(() => { fetchCourses(); fetchFaculties(); }, [getAuthHeader]);

  // Derived State
  const filteredCourses = courses.filter(c => {
    const matchesName = (c.name || '').toLowerCase().includes(nameFilter.toLowerCase());
    const matchesStatus = showInactive ? !c.is_active : !!c.is_active;
    return matchesName && matchesStatus;
  });

  // No pagination as per request
  const paginatedCourses = filteredCourses;
  // const totalPages = Math.ceil(filteredCourses.length / rowsPerPage); // Unused now

  // Handlers
  const handleAddCourse = async () => {
    try {
      await axios.post(`http://localhost:3000/api/courses/create-course`, {
        name: courseForm.name,
        course_code: courseForm.course_code,
        description: courseForm.description,
        is_active: !!courseForm.is_active,
        allowed_violations: Number(courseForm.allowed_violations ?? 3),
      }, { headers: getAuthHeader() });
      setOpenAdd(false);
      showToast('Course added successfully');
      fetchCourses();
    } catch (err) {
      showToast(err.response?.data?.message || 'Add failed', 'error');
    }
  };

  const handleEditCourse = async () => {
    try {
      await axios.put(`http://localhost:3000/api/courses/update-course/${editingId}`, {
        name: courseForm.name,
        course_code: courseForm.course_code,
        description: courseForm.description,
        is_active: !!courseForm.is_active,
        allowed_violations: Number(courseForm.allowed_violations ?? 3),
      }, { headers: getAuthHeader() });
      setOpenEdit(false);
      setEditingId(null);
      showToast('Course updated successfully');
      fetchCourses();
    } catch (err) {
      showToast(err.response?.data?.message || 'Update failed', 'error');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure? This cannot be undone.")) return;
    try {
      await axios.delete(`http://localhost:3000/api/courses/delete-course/${id}`, { headers: getAuthHeader() });
      showToast('Course deleted', 'success');
      fetchCourses();
    } catch (err) {
      showToast('Delete failed', 'error');
    }
  };

  const handleToggleStatus = async (course) => {
    const newStatus = !course.is_active;
    // Optimistic update
    setCourses(prev => prev.map(c => c.id === course.id ? { ...c, is_active: newStatus } : c));
    try {
      await axios.put(`http://localhost:3000/api/courses/update-course/${course.id}`, {
        is_active: newStatus,
        allowed_violations: course.allowed_violations
      }, { headers: getAuthHeader() });
      showToast(`Course ${newStatus ? 'activated' : 'deactivated'}`);
    } catch (err) {
      fetchCourses(); // revert
      showToast('Status update failed', 'error');
    }
  };

  const openAssignModal = async (course) => {
    setAssignCourseId(course.id);
    setSelectedFacultyIds([]);
    setOpenAssign(true);
    try {
      const res = await axios.get(`http://localhost:3000/api/courses/${course.id}/with-faculties`, { headers: getAuthHeader() });
      const current = (res.data?.course?.Faculties || []).map((f) => Number(f.id));
      setSelectedFacultyIds(current);
    } catch (err) { }
  };

  const handleAssignSave = async () => {
    try {
      await axios.post(`http://localhost:3000/api/courses/${assignCourseId}/assign-faculties`, { facultyIds: selectedFacultyIds }, { headers: getAuthHeader() });
      setOpenAssign(false);
      showToast('Faculties assigned successfully');
    } catch (err) {
      showToast('Assignment failed', 'error');
    }
  };

  const toggleFacultySelection = (fid) => {
    setSelectedFacultyIds(prev => prev.includes(fid) ? prev.filter(id => id !== fid) : [...prev, fid]);
  };

  // Render Helpers
  const renderCourseForm = () => (
    <div className="space-y-4">
      <div>
        <label className="block text-sm font-bold text-slate-700 mb-1">Course Name</label>
        <input className="lms-input" value={courseForm.name} onChange={e => setCourseForm({ ...courseForm, name: e.target.value })} placeholder="e.g. Data Structures" />
      </div>
      <div>
        <label className="block text-sm font-bold text-slate-700 mb-1">Course Code</label>
        <input className="lms-input" value={courseForm.course_code} onChange={e => setCourseForm({ ...courseForm, course_code: e.target.value })} placeholder="e.g. CS101" />
      </div>
      <div>
        <label className="block text-sm font-bold text-slate-700 mb-1">Description</label>
        <textarea className="w-full px-3.5 py-3 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-100 focus:border-blue-500 min-h-[100px]" value={courseForm.description} onChange={e => setCourseForm({ ...courseForm, description: e.target.value })} placeholder="Course details..." />
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-bold text-slate-700 mb-1">Allowed Violations</label>
          <input type="number" className="lms-input" value={courseForm.allowed_violations} onChange={e => setCourseForm({ ...courseForm, allowed_violations: e.target.value })} />
        </div>
        <div className="flex items-center gap-3 pt-6">
          <ToggleSwitch checked={courseForm.is_active} onChange={v => setCourseForm({ ...courseForm, is_active: v })} />
          <span className="text-sm font-bold text-slate-700">Active Course</span>
        </div>
      </div>
    </div>
  );

  return (
    <AdminLayout disableScroll={true}>
      <div className="flex flex-col h-full bg-slate-50 overflow-hidden relative">
        <AnimatePresence>
          {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}
        </AnimatePresence>

        {/* Fixed Header & Controls Section */}
        <div className="flex-none px-4 md:px-8 py-6 space-y-6 bg-slate-50 z-10">
          <div className="lms-container space-y-6">

            {/* Header */}
            <div className="lms-card p-6 relative overflow-hidden">
              <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
                <div className="flex items-center gap-6">
                  <div className="w-14 h-14 rounded-xl bg-blue-50 text-blue-700 border border-blue-100 flex items-center justify-center">
                    <BookOpen size={26} />
                  </div>
                  <div>
                    <h1 className="text-2xl font-bold text-slate-800 tracking-tight mb-1">Course Management</h1>
                    <p className="text-slate-500">Create, assign and manage academic courses</p>
                  </div>
                </div>
                <button
                  onClick={() => {
                    fetchCourses();
                    fetchFaculties();
                  }}
                  className="p-3 bg-white border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-50 hover:border-slate-300 transition-all shadow-sm"
                >
                  <RefreshCw size={20} />
                </button>
              </div>
            </div>

            {/* Controls */}
            <div className="lms-card p-4 flex flex-col md:flex-row items-center justify-between gap-4">
              <div className="flex items-center gap-3 w-full md:w-auto bg-slate-50 p-1 rounded-xl border border-slate-200">
                <button
                  onClick={() => { setShowInactive(false); setPage(0); }}
                  className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${!showInactive ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Active Courses
                </button>
                <button
                  onClick={() => { setShowInactive(true); setPage(0); }}
                  className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${showInactive ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Inactive
                </button>
              </div>

              <div className="flex items-center gap-4 w-full md:w-auto">
                <div className="relative w-full md:w-64">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                  <input
                    type="text"
                    placeholder="Search courses..."
                    className="lms-input pl-10 pr-4"
                    value={nameFilter}
                    onChange={e => setNameFilter(e.target.value)}
                  />
                </div>
                <button
                  onClick={() => {
                    setCourseForm({ name: '', course_code: '', description: '', is_active: true, allowed_violations: 3 });
                    setOpenAdd(true);
                  }}
                  className="lms-btn-primary"
                >
                  <Plus size={20} />
                  Add Course
                </button>
              </div>
            </div>

          </div>
        </div>

        {/* Scrollable Table Area */}
        <div className="flex-1 overflow-y-auto custom-scrollbar">
          <div className="lms-container pb-8">
