import React, { useEffect, useRef, useState } from 'react';
import {
  Send, ArrowLeft, RefreshCw, AlertCircle, User, MessageSquare
} from 'lucide-react';
import axios from 'axios';
import { io } from 'socket.io-client';
import { useParams, useNavigate } from 'react-router-dom';
import FacultyNavbar from './FacultyNavbar';

const API_BASE = 'http://localhost:3000';
const SOCKET_URL = 'http://localhost:3000';

export default function FacultyChatView() {
  const { courseId } = useParams();
  const navigate = useNavigate();

  const [course, setCourse] = useState(null);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState('');
  const [text, setText] = useState('');

  const socketRef = useRef(null);
  const endRef = useRef(null);

  const token = localStorage.getItem('token') || '';
  const storedUser = (() => { try { return JSON.parse(localStorage.getItem('user') || '{}'); } catch { return {}; } })();

  // API & Socket Logic
  useEffect(() => {
    let cancelled = false;
    const load = async () => {
      setLoading(true);
      setErr('');
      try {
        const headers = token ? { Authorization: `Bearer ${token}` } : {};

        // Fetch metadata
        const cRes = await axios.get(`${API_BASE}/api/courses/get-course/${courseId}`, { headers }).catch(() => null);
        if (cRes && cRes.data) {
          const raw = cRes.data.course ?? cRes.data.data ?? cRes.data;
          if (!cancelled) {
            setCourse({
              course_id: raw.id ?? raw.course_id,
              course_name: raw.name ?? raw.course_name,
              course_code: raw.course_code ?? raw.code
            });
          }
        } else if (!cancelled) {
          setCourse({ course_id: courseId, course_name: `Course ${courseId}`, course_code: '' });
        }

        // Load messages
        const res = await axios.get(`${API_BASE}/api/chats/course/${courseId}/faculty`, { headers });
        const msgs = res.data.messages ?? res.data.data ?? res.data ?? [];
        if (!cancelled) setMessages(Array.isArray(msgs) ? msgs : []);

      } catch (e) {
        console.error('FacultyChatView load error', e?.response?.data || e.message);
        if (!cancelled) {
          setErr(e?.response?.data?.message || e.message || 'Failed to load chat');
          setMessages([]);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    };

    load();
    return () => { cancelled = true; };
  }, [courseId, token]);

  useEffect(() => {
    const s = io(SOCKET_URL, { transports: ['websocket'], auth: token ? { token } : undefined });
    socketRef.current = s;

    s.on('connect', () => {
      s.emit('joinCourse', courseId);
    });

    s.on('newCourseMessage', (msg) => {
      if (String(msg.course_id) === String(courseId)) {
        setMessages(prev => {
          const has = prev.some(p => (p.id && msg.id && p.id === msg.id) || (p.message === msg.message && p.created_at === msg.created_at));
          return has ? prev : [...prev, msg];
        });
      }
    });

    s.on('chatHistory', (hist) => {
      if (Array.isArray(hist)) setMessages(hist);
    });

    return () => { try { s.emit('leaveCourse', courseId); s.disconnect(); } catch (e) { } };
  }, [courseId, token]);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    const txt = (text || '').trim();
    if (!txt) return;
    try {
      const headers = token ? { Authorization: `Bearer ${token}` } : {};

      // Optimistic Update can be tricky if we don't know the exact structure expected by backend or if backend adds timestamps.
      // But we can rely on standard REST response or Socket event.
      // For now, let's just trigger REST and let the socket event or response update the UI.

      const res = await axios.post(`${API_BASE}/api/chats/course/${courseId}/faculty`, { message: txt }, { headers });

      const created = res.data.data ?? res.data.message ?? res.data ?? null;
      if (created) {
        setMessages(prev => {
          const has = prev.some(p => p.id === created.id);
          return has ? prev : [...prev, created];
        });
      }
      setText('');
    } catch (e) {
      console.error('send error', e?.response?.data || e.message);
      // Fallback emit
      try {
        if (socketRef.current && socketRef.current.connected) {
          socketRef.current.emit('sendMessage', {
            courseId,
            message: txt,
            userId: storedUser.id,
            senderName: storedUser.name || storedUser.email
          });
          setText('');
        }
      } catch (ee) { console.warn('socket fallback failed', ee); }
    }
  };

  const getInitials = (name) => (name || 'U').split(' ').map(s => s[0]).slice(0, 2).join('').toUpperCase();

  return (
    <>
      <FacultyNavbar />
      <div className="min-h-screen bg-slate-50 pt-20 pb-12 px-4 md:px-8">
        <div className="max-w-4xl mx-auto h-[calc(100vh-140px)] flex flex-col bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-200">

          {/* Header */}
          <div className="bg-white border-b border-slate-100 p-4 flex items-center justify-between shrink-0 z-10">
            <div className="flex items-center gap-4">
              <button onClick={() => navigate(-1)} className="p-2 -ml-2 text-slate-400 hover:text-slate-700 hover:bg-slate-100 rounded-lg transition-colors">
                <ArrowLeft size={20} />
              </button>
              <div>
                <h1 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  {course ? course.course_name : `Course ${courseId}`}
                  <span className="px-2 py-0.5 rounded-md bg-indigo-50 text-indigo-700 text-xs font-bold border border-indigo-100 hidden md:inline-block">
                    Chat
                  </span>
                </h1>
                <p className="text-xs text-slate-400 font-medium">
                  {loading ? 'Connecting...' : `${messages.length} messages`}
                </p>
              </div>
            </div>
          </div>

          {/* Chat Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-6 bg-slate-50/50 space-y-4 custom-scrollbar relative">
            {loading ? (
              <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-2">
                <RefreshCw className="animate-spin" size={24} />
                <span className="text-sm font-medium">Loading conversation...</span>
              </div>
            ) : err ? (
              <div className="flex items-center justify-center h-full">
                <div className="bg-rose-50 text-rose-600 px-4 py-3 rounded-xl border border-rose-100 flex items-center gap-2">
                  <AlertCircle size={20} />
                  {err}
                </div>
              </div>
            ) : messages.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-slate-400 opacity-60">
                <MessageSquare size={48} className="mb-2" />
                <p>No messages yet. Start the conversation!</p>
              </div>
            ) : (
              messages.map((m, i) => {
                const name = m.sender_name ?? (m.Sender && m.Sender.name) ?? 'Unknown';
                const time = m.created_at ?? m.createdAt ?? '';
                const isMe = String(m.user_id || m.userId) === String(storedUser.id);

                return (
                  <div key={m.id || i} className={`flex gap-3 ${isMe ? 'flex-row-reverse' : 'items-start'}`}>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold text-white shrink-0 shadow-sm ${isMe ? 'bg-indigo-600' : 'bg-slate-400'
                      }`}>
                      {isMe ? <User size={14} /> : getInitials(name)}
                    </div>

                    <div className={`flex flex-col max-w-[80%] ${isMe ? 'items-end' : 'items-start'}`}>
                      {!isMe && (
                        <span className="text-[10px] font-bold text-slate-500 mb-1 ml-1">{name}</span>
                      )}
                      <div className={`px-4 py-2 text-sm leading-relaxed shadow-sm ${isMe
                          ? 'bg-indigo-600 text-white rounded-2xl rounded-tr-none'
                          : 'bg-white text-slate-700 border border-slate-200 rounded-2xl rounded-tl-none'
                        }`}>
                        {m.message}
                      </div>
                      <span className="text-[10px] text-slate-400 mt-1 px-1">
                        {time ? new Date(time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                      </span>
                    </div>
                  </div>
                );
              })
            )}
            <div ref={endRef} />
          </div>

          {/* Input Area */}
          <div className="p-4 bg-white border-t border-slate-200">
            <div className="flex gap-2 items-end">
              <div className="flex-1 bg-slate-100 rounded-2xl p-2 border border-transparent focus-within:border-indigo-300 focus-within:bg-white focus-within:ring-4 focus-within:ring-indigo-100 transition-all">
                <input
                  type="text"
                  placeholder="Type your message..."
                  value={text}
                  onChange={e => setText(e.target.value)}
                  onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
                  className="w-full bg-transparent border-none focus:ring-0 px-3 py-1 text-slate-700 placeholder:text-slate-400 max-h-32 overflow-y-auto"
                />
              </div>
              <button
                onClick={handleSend}
                disabled={!text.trim()}
                className="p-3 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:shadow-none"
              >
                <Send size={20} />
              </button>
            </div>
          </div>

        </div>
      </div>
    </>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import FacultyNavbar from './FacultyNavbar';
import { useNavigate } from 'react-router-dom';
import {
  PieChart, BookOpen, ClipboardList, MessageCircle, Search, LayoutDashboard, Download, Filter, RefreshCw,
  TrendingUp, Users, FileText, ChevronDown, MessageSquare
} from 'lucide-react';
import { motion } from 'framer-motion';

const API = 'http://localhost:3000/api';

const COLORS = ['#6366f1', '#06b6d4', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899'];
const PALETTE = ['#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#64748b'];

const readNum = (obj, ...keys) => {
  if (!obj) return 0;
  for (const k of keys) {
    if (obj[k] !== undefined && obj[k] !== null && obj[k] !== '') {
      const n = Number(obj[k]);
      return Number.isFinite(n) ? n : 0;
    }
  }
  return 0;
};

function Donut({ data = {}, size = 120, subtitle = '' }) {
  const entries = Object.entries(data || {});
  const total = Math.max(entries.reduce((s, [, v]) => s + (Number(v) || 0), 0), 1);

  let acc = 0;
  const stops = entries
    .map(([k, v], i) => {
      const start = (acc / total) * 100;
      acc += Number(v) || 0;
      const end = (acc / total) * 100;
      return `${PALETTE[i % PALETTE.length]} ${start}% ${end}%`;
    })
    .join(', ');
  const gradient = entries.length ? `conic-gradient(${stops})` : 'transparent';

  return (
    <div className="flex items-center gap-4">
      <div style={{ width: size, height: size }} className="relative shrink-0">
        <div
          className="w-full h-full rounded-full shadow-inner transition-transform duration-300 hover:scale-105"
          style={{ background: gradient }}
        />
        <div
          className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 rounded-full bg-white flex flex-col items-center justify-center text-center shadow-lg"
          style={{ width: size * 0.56, height: size * 0.56 }}
        >
          <div className="text-lg font-bold text-slate-800 leading-none">
            {entries.reduce((s, [, v]) => s + (Number(v) || 0), 0)}
          </div>
          <div className="text-[10px] text-slate-500 font-semibold mt-0.5">{subtitle}</div>
        </div>
      </div>
      <div className="flex-1 min-w-0">
        {entries.length === 0 ? (
          <p className="text-xs text-slate-400">No data available</p>
        ) : (
          entries.map(([k, v], i) => (
            <div key={k} className="flex items-center gap-2 mb-1.5 last:mb-0">
              <div className="w-2.5 h-2.5 rounded-full shrink-0" style={{ background: PALETTE[i % PALETTE.length] }} />
              <span className="text-xs text-slate-500 font-medium truncate flex-1">{k}</span>
              <span className="text-xs text-slate-800 font-bold">{v}</span>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

function AreaSpark({ points = [], height = 100, color = '#3b82f6' }) {
  if (!points || points.length === 0) return <p className="text-xs text-slate-400">No activity recorded</p>;

  const w = Math.max(240, points.length * 18);
  const h = height;
  const min = Math.min(...points.map(p => p.y));
  const max = Math.max(...points.map(p => p.y));
  const range = Math.max(max - min, 1);
  const step = w / Math.max(points.length - 1, 1);

  const pathD = points
    .map((p, i) => {
      const x = i * step;
      const y = h - ((p.y - min) / range) * (h - 6) - 3;
      return `${i === 0 ? 'M' : 'L'} ${x.toFixed(2)} ${y.toFixed(2)}`;
    })
    .join(' ');
  const areaD = `${pathD} L ${w} ${h} L 0 ${h} Z`;

  return (
    <div className="w-full overflow-hidden rounded-xl bg-slate-50 border border-slate-100">
      <svg viewBox={`0 0 ${w} ${h}`} width="100%" height={h} preserveAspectRatio="none">
        <defs>
          <linearGradient id="areaGradient" x1="0%" y1="0%" x2="0%" y2="100%">
            <stop offset="0%" stopColor={color} stopOpacity="0.3" />
            <stop offset="100%" stopColor={color} stopOpacity="0.05" />
          </linearGradient>
        </defs>
        <path d={areaD} fill="url(#areaGradient)" />
        <path d={pathD} stroke={color} strokeWidth="2.5" fill="none" strokeLinejoin="round" strokeLinecap="round" />
      </svg>
    </div>
  );
}

function CourseBarList({ items = [], maxWidth = 420, labelKey = 'label', valueKey = 'value', heightPer = 28 }) {
  const max = Math.max(...(items.map(i => Number(i[valueKey] || 0))), 1);

