}

export default function FacultyDashboard() {
  const navigate = useNavigate();
  const [courses, setCourses] = useState([]);
  const [loadingCourses, setLoadingCourses] = useState(false);
  const [recentSubs, setRecentSubs] = useState([]);
  const [loadingSubs, setLoadingSubs] = useState(false);
  const [summary, setSummary] = useState(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [rangeFilter, setRangeFilter] = useState('7');
  const [chats, setChats] = useState([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const token = useMemo(() => localStorage.getItem('token') || null, []);
  const headers = useMemo(() => (token ? { Authorization: `Bearer ${token}` } : {}), [token]);

  useEffect(() => {
    fetchCourses();
    fetchSummary();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (courses.length) fetchChats();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [courses]);

  useEffect(() => {
    if (courses.length > 0) fetchRecentSubmissions();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [courses, rangeFilter]);

  async function fetchCourses() {
    setLoadingCourses(true);
    try {
      const res = await axios.get(`${API}/courses/faculty-courses`, { headers });
      const list = Array.isArray(res.data?.courses) ? res.data.courses : [];
      const missing = list.filter(c => (c.submissionCount === undefined || c.submissionCount === null)).slice(0, 6);
      await Promise.all(missing.map(async (c) => {
        try {
          const r = await axios.get(`${API}/submissions/faculty/course/${c.id}`, { headers });
          const subs = Array.isArray(r.data?.submissions) ? r.data.submissions : (r.data?.data || []);
          c.submissionCount = subs.length;
          c._fetchedSubmissions = subs;
        } catch (e) {
          c.submissionCount = 0;
        }
      }));
      setCourses(list);
    } catch (err) {
      console.error('fetchCourses error', err?.response?.data || err.message);
      setCourses([]);
    } finally {
      setLoadingCourses(false);
    }
  }

  async function fetchSummary() {
    setLoadingSummary(true);
    try {
      const res = await axios.get(`${API}/submissions/faculty/summary`, { headers });
      setSummary(res.data || null);
    } catch (err) {
      console.warn('fetchSummary failed', err?.response?.data || err.message);
      setSummary(null);
    } finally {
      setLoadingSummary(false);
    }
  }

  async function fetchRecentSubmissions() {
    setLoadingSubs(true);
    try {
      const list = [];
      const sampleCourses = courses.slice(0, 8);
      for (const c of sampleCourses) {
        try {
          const res = await axios.get(`${API}/submissions/faculty/course/${c.id}`, { headers });
          const subs = Array.isArray(res.data?.submissions) ? res.data.submissions : (res.data?.data || []);
          for (const s of subs) list.push({ ...s, course_name: c.name, course_id: c.id });
        } catch (e) {
          console.debug('single course subs fetch failed for', c.id, e?.message || e);
        }
      }
      const parsed = list
        .map(s => ({ ...s, createdAt: s.createdAt || s.created_at || new Date().toISOString() }))
        .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
      const days = Number(rangeFilter || 7);
      const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - days);
      const sliced = parsed.filter(s => new Date(s.createdAt) >= cutoff).slice(0, 200);
      setRecentSubs(sliced);
    } catch (err) {
      console.error('fetchRecentSubmissions error', err);
      setRecentSubs([]);
    } finally {
      setLoadingSubs(false);
    }
  }

  async function fetchChats() {
    try {
      const sample = courses.slice(0, 8);
      const out = [];
      await Promise.all(sample.map(async (c) => {
        try {
          const r = await axios.get(`${API}/chats/course/${c.id}/faculty`, { headers });
          const payload = r.data || {};
          const msgs = Array.isArray(payload.chats) ? payload.chats
            : Array.isArray(payload.messages) ? payload.messages
              : Array.isArray(payload.threads) ? payload.threads
                : Array.isArray(payload.data) ? payload.data
                  : [];
          const count = msgs.length;
          const last = count > 0 ? (msgs[count - 1].text || msgs[count - 1].message || msgs[count - 1].body || '') : '';
          out.push({ courseId: c.id, courseName: c.name, count, lastMessage: String(last).slice(0, 80) });
        } catch (e) {
          out.push({ courseId: c.id, courseName: c.name, count: 0, lastMessage: '' });
        }
      }));
      setChats(out);
    } catch (err) {
      console.error('fetchChats error', err);
      setChats([]);
    }
  }

  const totalCourses = courses.length;
  const totalStudents = courses.reduce((s, c) => s + readNum(c, 'studentCount', 'count', 'students'), 0);
  const totalSubmissions = courses.reduce((s, c) => s + readNum(c, 'submissionCount', 'submissions'), 0);
  const avgPerCourse = totalCourses ? Math.round(totalSubmissions / totalCourses) : 0;

  const statusCounts = useMemo(() => {
    if (summary && summary.courseStatus) return summary.courseStatus;
    const m = {};
    (courses || []).forEach(c => {
      const st = (c.status || c.course_status || c.state || 'Active').toString();
      m[st] = (m[st] || 0) + 1;
    });
    return m;
  }, [courses, summary]);

  const groupedSeries = useMemo(() => {
    if (summary && Array.isArray(summary.courses)) {
      const submissions = { name: 'Submissions', values: (summary.courses || []).slice(0, 6).map(s => ({ label: s.name || s.course_name, value: s.submissionsCount || s.submissions || 0 })) };
      const students = { name: 'Students', values: (summary.courses || []).slice(0, 6).map(s => ({ label: s.name || s.course_name, value: s.studentCount || s.students || 0 })) };
      return [submissions, students];
    }
    const sorted = courses.slice().sort((a, b) => readNum(b, 'submissionCount', 'submissions') - readNum(a, 'submissionCount', 'submissions')).slice(0, 6);
    const submissions = { name: 'Submissions', values: sorted.map(c => ({ label: c.name || `C${c.id}`, value: readNum(c, 'submissionCount', 'submissions') })) };
    const students = { name: 'Students', values: sorted.map(c => ({ label: c.name || `C${c.id}`, value: readNum(c, 'studentCount', 'count') })) };
    return [submissions, students];
  }, [courses, summary]);

  const areaTimeseries = useMemo(() => {
    if (summary && Array.isArray(summary.timeseries)) {
      return summary.timeseries.slice(-9).map(t => ({ x: (t.date || '').slice(5), y: Number(t.total_submissions || t.count || t.value || 0) }));
    }
    const map = {};
    const now = new Date();
    for (let i = 8; i >= 0; i--) {
      const d = new Date(now);
      d.setDate(now.getDate() - i);
      map[d.toISOString().slice(0, 10)] = 0;
    }
    courses.forEach(c => {
      const date = c.last_submission_date || c.lastSubmission || c.updatedAt || c.updated_at;
      if (!date) return;
      const k = new Date(date).toISOString().slice(0, 10);
      if (map[k] === undefined) map[k] = 0;
      map[k] += readNum(c, 'submissionCount', 'submissions');
    });
    return Object.keys(map).sort().map(k => ({ x: k.slice(5), y: map[k] || 0 }));
  }, [courses, summary]);

  const refreshAll = async () => { await fetchCourses(); await fetchSummary(); await fetchRecentSubmissions(); await fetchChats(); };

  return (
    <>
      <FacultyNavbar />
      <div className="fixed inset-0 top-16 overflow-auto lms-page-bg">
      <div className="lms-container py-6 md:py-8 min-h-full">

        {/* Header */}
        <div className="relative mb-8 rounded-2xl bg-white border border-slate-200 shadow-sm overflow-hidden">
          <div className="p-6 md:p-7 relative z-10 flex flex-col md:flex-row items-center gap-5">
            <div className="w-16 h-16 rounded-xl bg-blue-50 border border-blue-100 flex items-center justify-center">
              <LayoutDashboard size={30} className="text-blue-700" />
            </div>

            <div className="text-center md:text-left flex-1">
              <h1 className="text-3xl md:text-4xl font-bold text-slate-900 mb-2">
                Faculty Dashboard
              </h1>
              <p className="text-slate-500 text-base md:text-lg">
                Course management & analytics overview
              </p>
            </div>

            <div className="flex gap-3">
              <div className="relative">
                <button
                  onClick={() => setIsFilterOpen(!isFilterOpen)}
                    className="lms-btn-secondary h-11 px-4 text-slate-600 flex items-center gap-2"
                >
                  <Filter size={20} />
                  <span>{rangeFilter} Days</span>
                  <ChevronDown size={14} />
                </button>
                {isFilterOpen && (
                  <div className="absolute right-0 top-full mt-2 w-48 bg-white rounded-xl shadow-xl border border-slate-100 py-2 z-20">
                    {[7, 14, 30, 90].map(days => (
                      <button
                        key={days}
                        onClick={() => { setRangeFilter(String(days)); setIsFilterOpen(false); }}
                        className={`w-full text-left px-4 py-2 hover:bg-slate-50 text-sm font-semibold ${String(days) === rangeFilter ? 'text-blue-600' : 'text-slate-600'}`}
                      >
                        Last {days} Days
                      </button>
                    ))}
                  </div>
                )}
              </div>
              <button
                onClick={refreshAll}
                className="lms-btn-primary px-6 text-white flex items-center gap-2"
              >
                <RefreshCw size={20} className={loadingSummary ? "animate-spin" : ""} />
                <span className="hidden md:inline">Refresh</span>
              </button>
            </div>
          </div>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
          <StatCard
            title="Total Courses"
            value={totalCourses}
            icon={<BookOpen />}
            color="#6366f1"
            loading={loadingSummary}
            subtitle="Assigned"
          />
          <StatCard
            title="Total Students"
            value={totalStudents}
            icon={<Users />}
            color="#ec4899"
            loading={loadingSummary}
            subtitle="Enrolled"
          />
          <StatCard
            title="Submissions"
            value={totalSubmissions}
            icon={<TrendingUp />}
            color="#0ea5e9"
            loading={loadingSummary}
            subtitle="Total"
          />
          <StatCard
            title="Avg per Course"
            value={avgPerCourse}
            icon={<MessageCircle />}
            color="#10b981"
            loading={loadingSummary}
            subtitle="Submissions"
          />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 xl:grid-cols-4 gap-6">

          {/* Left Column: Course Status & Submissions Trend */}
          <div className="lg:col-span-1 space-y-6">
            {/* Status */}
            <div className="lms-card p-6">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2.5 rounded-xl bg-purple-100 text-purple-600">
                  <ClipboardList size={24} />
                </div>
                <h3 className="text-lg font-bold text-slate-800">Status</h3>
              </div>
              <Donut data={statusCounts} subtitle="Courses" size={140} />
            </div>

            {/* Recent Subs Preview */}
            <div className="lms-card p-6 flex flex-col h-[400px]">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2.5 rounded-xl bg-blue-100 text-blue-600">
                  <FileText size={24} />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-slate-800">Activity</h3>
                  <p className="text-xs text-slate-500 font-bold">Recent Submissions</p>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 pr-1">
                {loadingSubs ? (
                  <div className="text-center py-6 text-slate-400">Loading...</div>
                ) : recentSubs.length === 0 ? (
                  <div className="text-center py-6 text-slate-400 italic">No recent activity</div>
                ) : (
                  recentSubs.map((s, i) => (
                    <div key={s.id || i} className="p-3 bg-white rounded-xl border border-slate-100 shadow-sm hover:border-blue-200 transition-colors">
                      <div className="flex justify-between items-start mb-1">
                        <span className="text-xs font-bold text-slate-700 truncate max-w-[70%]">{s.student_name || s.studentName}</span>
                        <span className="text-[10px] font-medium text-slate-400">{new Date(s.createdAt).toLocaleDateString()}</span>
                      </div>
                      <div className="text-[10px] text-slate-500 font-medium truncate mb-2">{s.course_name}</div>
                      <div className="flex items-center gap-2">
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${s.verdict === 'Accepted' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                          {s.verdict || 'Pending'}
                        </span>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>

          {/* Middle Column: Detailed Stats */}
          <div className="lg:col-span-1 xl:col-span-2 space-y-6">
            {/* Sparkline */}
            <div className="lms-card p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <div className="p-2.5 rounded-xl bg-emerald-100 text-emerald-600">
                    <TrendingUp size={24} />
                  </div>
                  <h3 className="text-lg font-bold text-slate-800">Submission Trend</h3>
                </div>
                <span className="text-xs font-bold text-slate-500 bg-slate-100 px-2 py-1 rounded">Last 9 Days</span>
              </div>
              <div className="h-[150px]">
                <AreaSpark points={areaTimeseries} height={150} color="#10b981" />
              </div>
            </div>

            {/* Students & Submissions Bar Lists */}
            <div className="lms-card p-6 min-h-[300px]">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2.5 rounded-xl bg-orange-100 text-orange-600">
                  <LayoutDashboard size={24} />
                </div>
                <h3 className="text-lg font-bold text-slate-800">Top Courses Performance</h3>
              </div>

              <div className="space-y-6">
                <div>
                  <h4 className="text-xs font-black uppercase text-slate-400 mb-3 ml-1">Highest Submissions</h4>
                  <CourseBarList items={groupedSeries[0].values} />
                </div>
                <div>
                  <h4 className="text-xs font-black uppercase text-slate-400 mb-3 ml-1">Highest Enrollment</h4>
                  <CourseBarList items={groupedSeries[1].values} />
                </div>
              </div>
            </div>
          </div>

          {/* Right Column: Messages & Quick Actions */}
          <div className="lg:col-span-1 space-y-6">
            {/* Messages */}
            <div className="lms-card p-6 flex flex-col h-[500px]">
              <div className="flex items-center gap-3 mb-4">
                <div className="p-2.5 rounded-xl bg-pink-100 text-pink-600">
                  <MessageSquare size={24} />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-slate-800">Messages</h3>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3">
                {chats.length === 0 ? (
                  <div className="text-center py-6 text-slate-400 text-sm">No new messages</div>
                ) : (
                  chats.map((chat, i) => (
                    <div key={i} className="bg-white p-3 rounded-xl border border-slate-100 hover:border-pink-200 transition-colors cursor-pointer group" onClick={() => navigate(`/faculty/course/${chat.courseId}/chat`)}>
                      <div className="flex justify-between items-start mb-1">
                        <span className="text-xs font-bold text-slate-700 truncate">{chat.courseName}</span>
                        {chat.count > 0 && (
                          <span className="flex items-center justify-center min-w-[18px] h-[18px] px-1 bg-pink-500 text-white text-[10px] font-bold rounded-full">
                            {chat.count}
                          </span>
                        )}
                      </div>
                      <p className="text-[11px] text-slate-500 line-clamp-2 max-w-full">
                        {chat.lastMessage || 'No preview'}
                      </p>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>

        </div>
      </div>
    </div>
    </>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  RefreshCw, BarChart2, Search, Printer, Calendar, Hash, Mail,
  CheckCircle, XCircle, Clock, ChevronDown, ChevronUp, Download, Filter,
  ArrowLeft, FileText, Code, Globe, User
} from 'lucide-react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import FacultyNavbar from './FacultyNavbar';
import { motion, AnimatePresence } from 'framer-motion';

const API = 'http://localhost:3000/api';

const formatDateKey = (iso) => {
  if (!iso) return 'Unknown Date';
  const d = new Date(iso);
  if (isNaN(d.getTime())) return 'Unknown Date';
  return d.toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' });
};

// --- Reusable Components ---

const Modal = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" />
        <motion.div initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 20 }} className="relative w-full max-w-4xl bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
          <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <h3 className="text-lg font-bold text-slate-800">{title}</h3>
            <button onClick={onClose} className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors">
              <XCircle size={20} />
            </button>
          </div>
          <div className="p-0 overflow-y-auto custom-scrollbar bg-slate-50">
            {children}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const StatusBadge = ({ status }) => {
  const s = (status || '').toLowerCase();
  if (s === 'success' || s === 'accepted' || s === 'passed') return <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-emerald-100 text-emerald-700 border border-emerald-200"><CheckCircle size={12} /> Accepted</span>;
  if (s === 'error' || s === 'failed' || s === 'rejected') return <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-rose-100 text-rose-700 border border-rose-200"><XCircle size={12} /> Failed</span>;
  if (s === 'pending') return <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-amber-100 text-amber-700 border border-amber-200"><Clock size={12} /> Pending</span>;
  return <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200">{status}</span>;
};

const ScoreBadge = ({ score }) => {
  const num = Number(score);
  let colorClass = 'bg-rose-100 text-rose-700 border-rose-200';
  if (num >= 90) colorClass = 'bg-emerald-100 text-emerald-700 border-emerald-200';
  else if (num >= 70) colorClass = 'bg-amber-100 text-amber-700 border-amber-200';
  else if (num >= 50) colorClass = 'bg-orange-100 text-orange-700 border-orange-200';

  return (
    <span className={`inline-flex items-center justify-center px-2.5 py-1 rounded-full text-xs font-bold border ${colorClass}`}>
      {score} pts
    </span>
  );
};

export default function FacultyEvaluate() {
  const { courseId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const headers = useMemo(() => (token ? { Authorization: `Bearer ${token}` } : {}), [token]);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [batches, setBatches] = useState([]);
  const [allSubmissions, setAllSubmissions] = useState([]);
  const [courseInfo, setCourseInfo] = useState({ id: courseId, name: '', course_code: '' });

  const [activeTab, setActiveTab] = useState('all'); // 'all', 'unassigned', or batchId

  // Scores Modal
  const [scoreModalOpen, setScoreModalOpen] = useState(false);
  const [scoreBatch, setScoreBatch] = useState(null);
  const [scoreRows, setScoreRows] = useState([]);
  const [scoreLoading, setScoreLoading] = useState(false);

  useEffect(() => {
    if (courseId) fetchBatchesAndSubmissions();
  }, [courseId]);

  const fetchBatchesAndSubmissions = async () => {
    setLoading(true);
    try {
      // 1. Batches
      const bRes = await axios.get(`${API}/students/batches/${courseId}`, { headers });
      const bList = (bRes.data?.batches || []).map(b => ({
        id: b.id, name: b.name, code: b.code, count: b.studentCount ?? b.count
      }));
      setBatches(bList);

      // 2. Submissions
      const sRes = await axios.get(`${API}/submissions/faculty/course/${courseId}`, { headers });
      const raw = sRes.data?.submissions || [];
      const course = sRes.data?.course || {};

      setCourseInfo({
        id: course.id || courseId,
        name: course.name || '',
        course_code: course.course_code || ''
      });

      setAllSubmissions(raw);
    } catch (err) {
      setError('Failed to load data. Please try refreshing.');
    } finally {
      setLoading(false);
    }
  };

  // Grouping Logic
  const filteredSubmissions = useMemo(() => {
    if (activeTab === 'all') return allSubmissions;
    if (activeTab === 'unassigned') {
      return allSubmissions.filter(s => {
        const sbs = s.student_batches || s.Student?.Batches || [];
        return !sbs.length;
      });
    }
    return allSubmissions.filter(s => {
      const sbs = s.student_batches || s.Student?.Batches || [];
      return sbs.some(b => String(b.id || b) === String(activeTab));
    });
  }, [allSubmissions, activeTab]);

  const groupedByDate = useMemo(() => {
    const groups = {};
    filteredSubmissions.forEach(s => {
      const d = formatDateKey(s.createdAt);
      if (!groups[d]) groups[d] = [];
      groups[d].push(s);
    });
    // Sort dates desc
    return Object.entries(groups).sort((a, b) => new Date(b[0]) - new Date(a[0]));
  }, [filteredSubmissions]);

  // Batch Stats
  const batchStats = useMemo(() => {
    const stats = { total: allSubmissions.length, unassigned: 0, batches: {} };
    allSubmissions.forEach(s => {
      const sbs = s.student_batches || s.Student?.Batches || [];
      if (!sbs.length) stats.unassigned++;
      else sbs.forEach(b => {
        const bid = b.id || b;
        stats.batches[bid] = (stats.batches[bid] || 0) + 1;
      });
    });
    return stats;
  }, [allSubmissions]);

  const openScores = async (batch) => {
    setScoreBatch(batch);
    setScoreModalOpen(true);
    setScoreLoading(true);
    try {
      const batchSubs = allSubmissions.filter(s =>
        (s.student_batches || s.Student?.Batches || []).some(b => String(b.id || b) === String(batch.id))
      );

      const totals = {};
      batchSubs.forEach(s => {
        const sid = s.student_id ?? s.Student?.id;
        if (!sid) return;
        if (!totals[sid]) totals[sid] = {
          id: sid,
          name: s.student_name ?? s.Student?.name ?? 'Unknown',
          email: s.student_email ?? s.Student?.email,
          total: 0
        };
        totals[sid].total += Number(s.score || 0);
      });

      setScoreRows(Object.values(totals).sort((a, b) => b.total - a.total));
    } catch (e) {
      setScoreRows([]);
    } finally {
      setScoreLoading(false);
    }
  };

  return (
    <>
      <FacultyNavbar />
      <div className="min-h-screen bg-slate-50 pt-20 pb-12 px-4 md:px-8">
        <div className="max-w-7xl mx-auto space-y-6">

          {/* Header */}
          <div className="bg-white rounded-3xl p-8 relative overflow-hidden shadow-xl border border-white/50">
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>
            <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
              <div className="flex items-center gap-6">
                <button onClick={() => navigate('/faculty/view-submissions')} className="p-3 bg-white border border-slate-200 rounded-xl hover:bg-slate-50 text-slate-500 transition-colors">
                  <ArrowLeft size={24} />
                </button>
                <div>
                  <h1 className="text-3xl font-black text-slate-800 tracking-tight mb-1">{courseInfo.name || 'Loading...'}</h1>
                  <p className="text-slate-500 font-medium text-lg flex items-center gap-2">
                    <span className="font-mono bg-indigo-50 text-indigo-700 px-2 py-0.5 rounded-lg border border-indigo-100 text-sm font-bold">{courseInfo.course_code}</span>
                    Manage Submissions & Grades
                  </p>
                </div>
              </div>
              <button onClick={fetchBatchesAndSubmissions} className="p-3 bg-white border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-50 hover:border-slate-300 transition-all shadow-sm">
                <RefreshCw size={20} />
              </button>
            </div>
          </div>

          {/* Tabs */}
          <div className="flex overflow-x-auto gap-3 py-2 custom-scrollbar">
            <button
              onClick={() => setActiveTab('all')}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold whitespace-nowrap transition-all border ${activeTab === 'all' ? 'bg-slate-800 text-white border-slate-800 shadow-lg' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}
            >
              <span className={`flex items-center justify-center w-6 h-6 rounded-full text-xs ${activeTab === 'all' ? 'bg-white/20 text-white' : 'bg-slate-100 text-slate-500'}`}>{batchStats.total}</span>
              All Submissions
            </button>

            {batches.map(b => (
              <div key={b.id} className="relative group">
                <button
                  onClick={() => setActiveTab(String(b.id))}
                  className={`flex items-center gap-2 px-5 py-2.5 pr-12 rounded-xl font-bold whitespace-nowrap transition-all border ${String(activeTab) === String(b.id) ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}
                >
                  <span className={`flex items-center justify-center w-6 h-6 rounded-full text-xs ${String(activeTab) === String(b.id) ? 'bg-white/20 text-white' : 'bg-slate-100 text-slate-500'}`}>{batchStats.batches[b.id] || 0}</span>
                  {b.code || b.name}
                </button>
                <button
                  onClick={(e) => { e.stopPropagation(); openScores(b); }}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 rounded-lg hover:bg-black/10 text-current transition-colors opacity-60 hover:opacity-100"
                  title="View Batch Scores"
                >
                  <BarChart2 size={16} />
                </button>
              </div>
            ))}

            <button
              onClick={() => setActiveTab('unassigned')}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold whitespace-nowrap transition-all border ${activeTab === 'unassigned' ? 'bg-slate-800 text-white border-slate-800 shadow-lg' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}
            >
              <span className={`flex items-center justify-center w-6 h-6 rounded-full text-xs ${activeTab === 'unassigned' ? 'bg-white/20 text-white' : 'bg-slate-100 text-slate-500'}`}>{batchStats.unassigned}</span>
              Unassigned
            </button>
          </div>

          {/* Content */}
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20">
              <RefreshCw className="animate-spin text-indigo-600 mb-4" size={40} />
              <p className="text-slate-500 font-bold">Loading submissions...</p>
            </div>
          ) : filteredSubmissions.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-slate-300">
              <FileText className="text-slate-300 mb-4" size={64} />
              <h3 className="text-xl font-bold text-slate-600">No Submissions Found</h3>
              <p className="text-slate-400">There are no submissions for this selection.</p>
            </div>
          ) : (
            <div className="space-y-6">
              {groupedByDate.map(([date, dateSubs]) => (
                <div key={date} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
                  <div className="px-6 py-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between">
                    <div className="flex items-center gap-2 font-bold text-slate-700">
                      <Calendar size={18} className="text-indigo-600" />
                      {date}
                    </div>
                    <span className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-xs font-bold text-slate-500">
                      {dateSubs.length} Submissions
                    </span>
                  </div>

                  <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                    {dateSubs.map(s => (
                      <div key={s.id} className="p-4 rounded-xl border border-slate-100 hover:border-indigo-200 bg-white hover:shadow-md transition-all group">
                        <div className="flex items-start justify-between mb-3">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-indigo-500 to-purple-500 flex items-center justify-center text-white font-bold text-sm shadow-md">
                              {s.student_name?.[0] || 'S'}
                            </div>
                            <div>
                              <h4 className="font-bold text-slate-800 text-sm">{s.student_name || 'Unknown'}</h4>
                              <p className="text-xs text-slate-500">{s.student_email}</p>
                            </div>
                          </div>
                          <ScoreBadge score={s.score} />
                        </div>

                        <div className="space-y-2 mb-3">
                          <div className="flex items-center gap-2 text-sm font-medium text-slate-700">
                            <Code size={16} className="text-indigo-500" />
                            <span className="truncate flex-1" title={s.question_title}>{s.question_title}</span>
                          </div>
                          <div className="flex gap-2">
                            <span className="px-2 py-0.5 bg-slate-100 text-slate-600 text-xs font-bold rounded border border-slate-200">
                              Lang: {s.language_id}
                            </span>
                            <StatusBadge status={s.status} />
                          </div>
                        </div>

                        {s.output && (
                          <div className="bg-slate-900 rounded-lg p-3 relative group/code">
                            <div className="absolute top-2 right-2 opacity-0 group-hover/code:opacity-100 transition-opacity">
                              <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Output</div>
                            </div>
                            <pre className="text-xs text-emerald-400 font-mono overflow-x-auto custom-scrollbar max-h-24">
                              {s.output}
                            </pre>
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Scores Modal */}
      <Modal isOpen={scoreModalOpen} onClose={() => setScoreModalOpen(false)} title={`Batch Scores: ${scoreBatch?.code || 'View'}`}>
        {scoreLoading ? (
          <div className="p-12 flex justify-center"><RefreshCw className="animate-spin text-indigo-600" size={32} /></div>
        ) : (
          <table className="w-full text-left">
            <thead className="bg-slate-100 text-slate-500 text-xs uppercase font-bold sticky top-0">
              <tr>
                <th className="px-6 py-3">Rank</th>
                <th className="px-6 py-3">Student</th>
                <th className="px-6 py-3 text-right">Total Score</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {scoreRows.map((r, i) => (
                <tr key={r.id}>
                  <td className="px-6 py-3 font-mono text-slate-400 font-bold">#{i + 1}</td>
                  <td className="px-6 py-3">
                    <p className="font-bold text-slate-700 text-sm">{r.name}</p>
                    <p className="text-xs text-slate-400">{r.email}</p>
                  </td>
                  <td className="px-6 py-3 text-right font-bold text-indigo-600">{r.total}</td>
                </tr>
              ))}
              {scoreRows.length === 0 && (
                <tr><td colSpan="3" className="px-6 py-8 text-center text-slate-400">No scores recorded yet.</td></tr>
              )}
            </tbody>
          </table>
        )}
      </Modal>

    </>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Search, UserPlus, RefreshCw, Edit, Trash2, X, Mail, Phone, Shield } from 'lucide-react';
import AdminLayout from './AdminLayout';
import axios from 'axios';
import { motion, AnimatePresence } from 'framer-motion';
import { useToast } from '../context/ToastContext';

const API_BASE = 'http://localhost:3000/api/v1/users';

const Modal = ({ isOpen, onClose, title, children, maxWidth = 'max-w-md' }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/50 backdrop-blur-sm"
        />
        <motion.div
          initial={{ opacity: 0, scale: 0.98, y: 12 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.98, y: 12 }}
          className={`relative w-full ${maxWidth} bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden flex flex-col max-h-[90vh]`}
        >
          <div className="px-6 py-4 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
            <h3 className="text-lg font-semibold text-slate-800">{title}</h3>
            <button
              onClick={onClose}
              className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-md hover:bg-slate-100 transition-colors"
            >
              <X size={18} />
            </button>
          </div>
          <div className="p-6 overflow-y-auto">{children}</div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const ActionButton = ({ onClick, icon: Icon, label, variant = 'primary', disabled = false }) => {
  const variants = {
    primary: 'lms-btn-primary',
    secondary: 'lms-btn-secondary',
  };

  return (
    <button onClick={onClick} disabled={disabled} className={variants[variant]}>
      {Icon && <Icon size={18} />}
      {label}
    </button>
  );
};

const FacultyManagement = () => {
  const toast = useToast();
  const [faculties, setFaculties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [openAdd, setOpenAdd] = useState(false);
  const [openEdit, setOpenEdit] = useState(false);
  const [facultyForm, setFacultyForm] = useState({ name: '', email: '', phone: '', password: '' });
  const [editingId, setEditingId] = useState(null);

  const fetchFaculties = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const res = await axios.get(`${API_BASE}/faculties`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setFaculties(res.data.faculties || []);
    } catch (error) {
      console.error('Failed to fetch faculties:', error);
      setFaculties([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchFaculties();
  }, []);

  const filteredFaculties = useMemo(() => {
    const term = searchQuery.toLowerCase();
    return faculties.filter((faculty) => {
      const name = String(faculty?.name || '').toLowerCase();
      const email = String(faculty?.email || '').toLowerCase();
      const phone = String(faculty?.phone || '').toLowerCase();
      return name.includes(term) || email.includes(term) || phone.includes(term);
    });
  }, [faculties, searchQuery]);

  const handleAddFaculty = async () => {
    try {
      const token = localStorage.getItem('token');
      await axios.post(`${API_BASE}/add-faculty`, facultyForm, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setOpenAdd(false);
      setFacultyForm({ name: '', email: '', phone: '', password: '' });
      fetchFaculties();
      toast.success('Faculty added successfully');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to add faculty');
    }
  };

  const openEditDialog = (faculty) => {
    setFacultyForm({
      name: faculty.name || '',
      email: faculty.email || '',
      phone: faculty.phone || '',
      password: '',
    });
    setEditingId(faculty.id);
    setOpenEdit(true);
  };

  const handleUpdateFaculty = async () => {
    try {
      const token = localStorage.getItem('token');
      await axios.put(`${API_BASE}/faculties/update/${editingId}`, facultyForm, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setOpenEdit(false);
      setEditingId(null);
      fetchFaculties();
      toast.success('Faculty updated successfully');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update faculty');
    }
  };

  const handleDeleteFaculty = async (facultyId) => {
    if (!window.confirm('Are you sure you want to delete this faculty member?')) return;
    try {
      const token = localStorage.getItem('token');
      await axios.delete(`${API_BASE}/faculties/delete/${facultyId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchFaculties();
      toast.success('Faculty deleted successfully');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to delete faculty');
    }
  };

  return (
    <AdminLayout>
      <div className="flex flex-col h-full lms-page-bg">
        <div className="mb-6 bg-white border-b border-slate-200 px-6 py-6 shadow-sm">
          <div className="lms-container flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-700 flex items-center justify-center border border-blue-100">
                <Shield size={24} />
              </div>
              <div>
                <h1 className="text-2xl font-bold text-slate-900">Faculty Management</h1>
                <p className="text-slate-500">Manage faculty members and permissions</p>
              </div>
            </div>
            <ActionButton icon={UserPlus} label="Add Faculty" variant="primary" onClick={() => setOpenAdd(true)} />
          </div>
        </div>

        <div className="flex-1 overflow-auto pb-8">
          <div className="lms-container space-y-6">
            <div className="lms-card p-5">
              <div className="relative max-w-lg">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input
                  type="text"
                  placeholder="Search faculty by name, email, or phone"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="lms-input pl-11"
                />
              </div>
            </div>

            <div className="lms-card overflow-hidden min-h-[400px]">
              {loading ? (
                <div className="flex flex-col items-center justify-center py-20">
                  <RefreshCw className="animate-spin text-blue-700 mb-3" size={32} />
                  <p className="text-slate-500">Loading faculty list...</p>
                </div>
              ) : filteredFaculties.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-center">
                  <h3 className="text-lg font-semibold text-slate-700 mb-1">No faculty found</h3>
                  <p className="text-slate-500">Try adjusting your search query.</p>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full">
                    <thead>
                      <tr className="bg-slate-50 border-b border-slate-200">
                        <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Faculty</th>
                        <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Contact</th>
                        <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Status</th>
                        <th className="px-6 py-4 text-right text-xs font-semibold text-slate-500 uppercase tracking-wider">Actions</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {filteredFaculties.map((faculty) => (
                        <tr key={faculty.id} className="hover:bg-slate-50/70 transition-colors group">
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="flex items-center gap-4">
                              <div className="w-10 h-10 rounded-full bg-blue-700 text-white flex items-center justify-center text-sm font-semibold">
                                {faculty.name ? faculty.name.charAt(0).toUpperCase() : 'F'}
                              </div>
                              <div>
                                <div className="text-sm font-semibold text-slate-900">{faculty.name}</div>
                                <div className="text-xs text-slate-500">ID: {faculty.id}</div>
                              </div>
                            </div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="flex flex-col gap-1">
                              <div className="flex items-center gap-2 text-sm text-slate-700">
                                <Mail size={14} className="text-slate-400" />
                                {faculty.email}
                              </div>
                              <div className="flex items-center gap-2 text-xs text-slate-500">
                                <Phone size={14} className="text-slate-400" />
                                {faculty.phone || 'No phone number'}
                              </div>
                            </div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-emerald-50 text-emerald-700 text-xs font-semibold border border-emerald-100">
                              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                              Active
                            </span>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-right">
                            <div className="flex items-center justify-end gap-2 opacity-70 group-hover:opacity-100 transition-opacity">
                              <button
                                onClick={() => openEditDialog(faculty)}
                                className="p-2 text-blue-700 hover:bg-blue-50 rounded-md transition-colors"
                                title="Edit faculty"
                              >
                                <Edit size={17} />
                              </button>
                              <button
                                onClick={() => handleDeleteFaculty(faculty.id)}
                                className="p-2 text-red-700 hover:bg-red-50 rounded-md transition-colors"
                                title="Delete faculty"
                              >
                                <Trash2 size={17} />
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      <Modal isOpen={openAdd} onClose={() => setOpenAdd(false)} title="Add Faculty Member">
        <form
          className="space-y-4"
          onSubmit={(e) => {
            e.preventDefault();
            handleAddFaculty();
          }}
        >
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Full Name</label>
            <input type="text" required className="lms-input" value={facultyForm.name} onChange={(e) => setFacultyForm({ ...facultyForm, name: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Email</label>
            <input type="email" required className="lms-input" value={facultyForm.email} onChange={(e) => setFacultyForm({ ...facultyForm, email: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Phone</label>
            <input type="text" className="lms-input" value={facultyForm.phone} onChange={(e) => setFacultyForm({ ...facultyForm, phone: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Password</label>
            <input type="password" required autoComplete="new-password" className="lms-input" value={facultyForm.password} onChange={(e) => setFacultyForm({ ...facultyForm, password: e.target.value })} />
          </div>
          <div className="flex justify-end gap-3 pt-2">
            <button type="button" onClick={() => setOpenAdd(false)} className="lms-btn-secondary">Cancel</button>
            <button type="submit" disabled={!facultyForm.name || !facultyForm.email || !facultyForm.password} className="lms-btn-primary">Add Faculty</button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={openEdit} onClose={() => setOpenEdit(false)} title="Edit Faculty Member">
        <form
          className="space-y-4"
          onSubmit={(e) => {
            e.preventDefault();
            handleUpdateFaculty();
          }}
        >
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Full Name</label>
            <input type="text" required className="lms-input" value={facultyForm.name} onChange={(e) => setFacultyForm({ ...facultyForm, name: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Email</label>
            <input type="email" required className="lms-input" value={facultyForm.email} onChange={(e) => setFacultyForm({ ...facultyForm, email: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Phone</label>
            <input type="text" className="lms-input" value={facultyForm.phone} onChange={(e) => setFacultyForm({ ...facultyForm, phone: e.target.value })} />
          </div>
          <div className="p-3 bg-amber-50 rounded-lg border border-amber-200 text-sm text-amber-800">
            Leave password blank to keep the current password.
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">New Password (Optional)</label>
            <input type="password" autoComplete="new-password" className="lms-input" value={facultyForm.password} onChange={(e) => setFacultyForm({ ...facultyForm, password: e.target.value })} placeholder="********" />
          </div>
          <div className="flex justify-end gap-3 pt-2">
            <button type="button" onClick={() => setOpenEdit(false)} className="lms-btn-secondary">Cancel</button>
            <button type="submit" className="lms-btn-primary">Save Changes</button>
          </div>
        </form>
      </Modal>
    </AdminLayout>
  );
};

export default FacultyManagement;

