const useIsMobile = () => {
  const [mobile, setMobile] = useState(window.innerWidth <= 600);
  useEffect(() => {
    const onResize = () => setMobile(window.innerWidth <= 600);
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);
  return mobile;
};

