import React, { useEffect, useState, useRef } from 'react';
import {
  Plus, RefreshCw, Edit, Trash2, Code, Send,
  MessageCircle, Users, Award, FileText, CheckCircle,
  X, ChevronDown, Monitor, Search, Lock, Unlock, Hash
} from 'lucide-react';
import axios from 'axios';
import { useParams } from 'react-router-dom';
import { io } from 'socket.io-client';
import FacultyNavbar from './FacultyNavbar';
import { motion, AnimatePresence } from 'framer-motion';

const API = 'http://localhost:3000/api';
const SOCKET_URL = 'http://localhost:3000';

const LANGUAGES = [
  { id: 62, name: 'Java', color: '#f89820', icon: '☕' },
  { id: 71, name: 'Python', color: '#3776ab', icon: '🐍' },
  { id: 63, name: 'JavaScript', color: '#f7df1e', icon: '⚡' },
  { id: 54, name: 'C++', color: '#00599c', icon: '⚙️' },
  { id: 50, name: 'C', color: '#a8b9cc', icon: '🔧' },
  { id: 70, name: 'Python3', color: '#3776ab', icon: '🐍' },
];

// --- Reuseable Components ---

const Modal = ({ isOpen, onClose, title, children, maxWidth = 'max-w-md' }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
        />
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className={`relative w-full ${maxWidth} bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]`}
        >
          <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <h3 className="text-lg font-bold text-slate-800">{title}</h3>
            <button
              onClick={onClose}
              className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors"
            >
              <X size={20} />
            </button>
          </div>
          <div className="p-6 overflow-y-auto">
            {children}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const ActionButton = ({ onClick, icon: Icon, label, variant = 'primary', disabled = false, size = 'normal', fullWidth = false }) => {
  const baseClass = "flex items-center justify-center gap-2 rounded-xl font-bold transition-all duration-300 transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none";
  const sizeClass = size === 'small' ? 'px-3 py-1.5 text-xs' : 'px-4 py-2 text-sm';
  const widthClass = fullWidth ? 'w-full' : '';
  const variants = {
    primary: "bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-lg shadow-indigo-500/25 hover:shadow-indigo-500/40 hover:-translate-y-0.5",
    secondary: "bg-white text-slate-700 border border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm",
    ghost: "bg-transparent text-slate-500 hover:text-indigo-600 hover:bg-indigo-50",
    danger: "bg-red-50 text-red-600 border border-red-100 hover:bg-red-100"
  };

  return (
    <button onClick={onClick} disabled={disabled} className={`${baseClass} ${sizeClass} ${widthClass} ${variants[variant]}`}>
      {Icon && <Icon size={size === 'small' ? 14 : 18} strokeWidth={2.5} />}
      {label}
    </button>
  );
};

export default function ManageQuestions() {
  const { courseId } = useParams();
  const token = localStorage.getItem('token') || '';
  const headers = token ? { Authorization: `Bearer ${token}` } : {};

  const [batches, setBatches] = useState([]);
  const [selectedTab, setSelectedTab] = useState(0);
  const [questions, setQuestions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [toggling, setToggling] = useState({});

  const [openDialog, setOpenDialog] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({
    title: '', description: '', sample_input: '', sample_output: '', language_id: LANGUAGES[0].id, score: 100,
  });
  const [saving, setSaving] = useState(false);

  const selectedBatchId = selectedTab === 0 ? null : batches[selectedTab - 1]?.id;
  const chatIndex = batches.length + 1;

  // --- Logic Helpers ---

  const getScore = (q) => {
    if (!q) return null;
    const candidates = [q.score, q.raw?.score, q.raw?.points, q.raw?.marks];
    for (const c of candidates) {
      if (c != null && !isNaN(c)) return Number(c);
    }
    return null;
  };

  const fetchAll = async () => {
    setLoading(true);
    try {
      const bRes = await axios.get(`${API}/students/batches/${courseId}`, { headers }).catch(() => ({ data: { batches: [] } }));
      setBatches(bRes.data?.batches || []);

      let qRes;
      try { qRes = await axios.get(`${API}/questions/bank/${courseId}?includeBatches=1`, { headers }); }
      catch {
        try { qRes = await axios.get(`${API}/questions/course/${courseId}`, { headers }); }
        catch { qRes = { data: [] }; }
      }

      const raw = Array.isArray(qRes.data) ? qRes.data : (qRes.data?.questions || qRes.data?.data || []);
      const normalized = raw.map(q => {
        const r = q.question || q;
        return {
          id: r.id ?? r.question_id ?? r._id,
          title: r.title,
          description: r.description,
          sample_input: r.sample_input,
          sample_output: r.sample_output,
          language_id: r.language_id ?? r.languageId ?? LANGUAGES[0].id,
          language: r.language,
          score: r.score ?? r.points ?? r.marks ?? 100,
          raw: r,
          batch_states: q.batch_states || q.batchStates || {}
        };
      }).filter(Boolean);

      setQuestions(normalized);
      setSelectedTab(0);
    } catch (err) {
      console.error(err);
      alert('Failed to load data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { if (courseId) fetchAll(); }, [courseId]);

  const handleToggle = async (questionId, batchId, currentEnabled) => {
    const key = `${questionId}_${batchId}`;
    setToggling(prev => ({ ...prev, [key]: true }));
    try {
      await axios.post(`${API}/questions/${questionId}/batch/${batchId}/toggle`, {}, { headers });
      setQuestions(prev => prev.map(q => {
        if (String(q.id) !== String(questionId)) return q;
        const bs = { ...q.batch_states };
        bs[batchId] = { ...bs[batchId], enabled: !currentEnabled, toggled_at: new Date().toISOString() };
        return { ...q, batch_states: bs };
      }));
    } catch {
      alert('Toggle failed');
    } finally {
      setToggling(prev => { const n = { ...prev }; delete n[key]; return n; });
    }
  };

  const handleSave = async () => {
    if (!form.title || !form.language_id) return alert('Fill required fields');
    setSaving(true);
    try {
      const payload = {
        title: form.title, description: form.description,
        sample_input: form.sample_input, sample_output: form.sample_output,
        language_id: Number(form.language_id), score: Number(form.score),
        course_id: Number(courseId)
      };
      if (editing) {
        await axios.put(`${API}/questions/update/${editing}`, payload, { headers });
      } else {
        await axios.post(`${API}/questions/add`, payload, { headers });
      }
      setOpenDialog(false);
      setEditing(null);
      await fetchAll();
    } catch (e) { alert('Save failed'); }
    finally { setSaving(false); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete question?')) return;
    try {
      await axios.delete(`${API}/questions/delete/${id}`, { headers });
      await fetchAll();
    } catch { alert('Delete failed'); }
  };

  // --- Chat Logic ---
  const [chatMessages, setChatMessages] = useState([]);
  const [chatInput, setChatInput] = useState('');
  const chatEndRef = useRef(null);
  const socketRef = useRef(null);
  const storedUser = JSON.parse(localStorage.getItem('user') || '{}');

  useEffect(() => {
    const s = io(SOCKET_URL, { transports: ['websocket'], auth: token ? { token } : undefined });
    socketRef.current = s;
    s.on('newCourseMessage', (msg) => {
      if (selectedTab === chatIndex && String(msg.course_id || msg.courseId) === String(courseId)) {
        setChatMessages(prev => [...prev, msg].filter((v, i, a) => a.findIndex(t => (t.id === v.id) || (t.message === v.message && t.created_at === v.created_at)) === i));
      }
    });
    s.on('chatHistory', h => Array.isArray(h) && setChatMessages(h));
    return () => s.disconnect();
  }, [token, courseId, selectedTab, chatIndex]);

  useEffect(() => {
    if (selectedTab === chatIndex) {
      if (socketRef.current) socketRef.current.emit('joinCourse', courseId);
      axios.get(`${API}/chats/course/${courseId}/faculty`, { headers })
        .then(res => setChatMessages(res.data.messages || res.data.data || []))
        .catch(() => setChatMessages([]));
    } else {
      if (socketRef.current) socketRef.current.emit('leaveCourse', courseId);
    }
  }, [selectedTab, courseId, chatIndex]);

  useEffect(() => chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }), [chatMessages]);

  const sendMessage = async () => {
    if (!chatInput.trim()) return;
    try {
      await axios.post(`${API}/chats/course/${courseId}/faculty`, {
        message: chatInput, userId: storedUser.id, senderName: storedUser.name, senderRole: storedUser.role || 'faculty'
      }, { headers });
      setChatInput('');
    } catch { alert('Message failed'); }
  };

  // --- Render Helpers ---

  const getLangStyles = (lid) => {
    const l = LANGUAGES.find(x => x.id === Number(lid)) || LANGUAGES[0];
    return { color: l.color, name: l.name, icon: l.icon };
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans">
      <FacultyNavbar />

      <div className="max-w-7xl mx-auto px-4 md:px-6 py-8">

        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-slate-900 to-slate-700 mb-2">
              Question Management
            </h1>
            <p className="text-slate-500 font-medium">Create questions, manage batch access, and discuss with students.</p>
          </div>
          {selectedTab !== chatIndex && (
            <ActionButton
              label="New Question"
              icon={Plus}
              onClick={() => { setEditing(null); setForm({ title: '', description: '', sample_input: '', sample_output: '', language_id: LANGUAGES[0].id, score: 100 }); setOpenDialog(true); }}
            />
          )}
        </div>

        {/* Tabs Navigation */}
        <div className="flex overflow-x-auto pb-1 mb-8 gap-2 border-b border-slate-200 hide-scrollbar">
          <button
            onClick={() => setSelectedTab(0)}
            className={`px-4 py-2 rounded-t-xl font-bold whitespace-nowrap transition-all border-b-2 ${selectedTab === 0 ? 'border-indigo-500 text-indigo-600 bg-indigo-50/50' : 'border-transparent text-slate-500 hover:text-indigo-500 hover:bg-slate-50'}`}
          >
            <div className="flex items-center gap-2">
              <Code size={18} /> All Questions <span className="text-xs bg-slate-200 px-1.5 py-0.5 rounded-full text-slate-600">{questions.length}</span>
            </div>
          </button>
          {batches.map((b, i) => (
            <button
              key={b.id}
              onClick={() => setSelectedTab(i + 1)}
              className={`px-4 py-2 rounded-t-xl font-bold whitespace-nowrap transition-all border-b-2 ${selectedTab === i + 1 ? 'border-purple-500 text-purple-600 bg-purple-50/50' : 'border-transparent text-slate-500 hover:text-purple-500 hover:bg-slate-50'}`}
            >
              <div className="flex items-center gap-2">
                <Users size={18} /> {b.name} <span className="text-xs font-mono opacity-70">{b.code}</span>
              </div>
            </button>
          ))}
          <button
            onClick={() => setSelectedTab(chatIndex)}
            className={`px-4 py-2 rounded-t-xl font-bold whitespace-nowrap transition-all border-b-2 ${selectedTab === chatIndex ? 'border-emerald-500 text-emerald-600 bg-emerald-50/50' : 'border-transparent text-slate-500 hover:text-emerald-500 hover:bg-slate-50'}`}
          >
            <div className="flex items-center gap-2">
              <MessageCircle size={18} /> Q&A Room
            </div>
          </button>
        </div>

        {/* Content Area */}
        {loading ? (
          <div className="flex justify-center items-center py-20"><RefreshCw className="animate-spin text-indigo-500" size={40} /></div>
        ) : selectedTab === chatIndex ? (
          /* Chat UI */
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden h-[600px] flex flex-col">
            <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
              <h3 className="font-bold text-slate-700 flex items-center gap-2"><MessageCircle className="text-emerald-500" size={20} /> Course Discussion</h3>
              <span className="text-xs text-slate-400 font-mono">Live Socket Connection</span>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30">
              {chatMessages.length === 0 && <div className="text-center text-slate-400 py-10 italic">No messages yet. Start the conversation!</div>}
              {chatMessages.map((m, i) => {
                const isMe = m.user_id === storedUser.id || m.senderName === storedUser.name;
                return (
                  <div key={i} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[80%] rounded-2xl px-4 py-3 shadow-sm ${isMe ? 'bg-indigo-600 text-white rounded-br-none' : 'bg-white border border-slate-200 text-slate-700 rounded-bl-none'}`}>
                      {!isMe && <p className="text-xs font-bold text-indigo-500 mb-1">{m.senderName} <span className="opacity-50 font-normal">({m.senderRole})</span></p>}
                      <p className="text-sm leading-relaxed whitespace-pre-wrap">{m.message}</p>
                      <p className={`text-[10px] mt-1 text-right ${isMe ? 'text-indigo-200' : 'text-slate-400'}`}>{new Date(m.created_at || m.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                    </div>
                  </div>
                );
              })}
              <div ref={chatEndRef} />
            </div>
            <div className="p-4 bg-white border-t border-slate-200 flex gap-3">
              <input
                type="text"
                value={chatInput}
                onChange={e => setChatInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && sendMessage()}
                placeholder="Type your message..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <button onClick={sendMessage} className="p-3 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl transition-colors shadow-lg shadow-emerald-500/30"><Send size={20} /></button>
            </div>
          </div>
        ) : (
          /* Questions Grid */
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {questions.length === 0 && <div className="col-span-full text-center py-20 text-slate-400">No questions found. Add one to get started.</div>}
            {questions.map((q) => {
              const { color, icon, name } = getLangStyles(q.language_id);
              const batchId = batches[selectedTab - 1]?.id;
              const bState = batchId ? (q.batch_states?.[batchId] || { enabled: false }) : null;
              const enabledCount = Object.values(q.batch_states || {}).filter(s => s.enabled).length;

              return (
                <motion.div
                  layout
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  key={q.id}
                  className={`group relative bg-white rounded-2xl border transition-all hover:-translate-y-1 hover:shadow-xl flex flex-col h-full ${batchId && bState?.enabled ? 'border-emerald-200 shadow-emerald-100' : 'border-slate-200 shadow-sm'}`}
                >
                  {/* Card Header */}
                  <div className="p-5 flex items-start gap-4">
                    <div className="w-12 h-12 rounded-xl flex items-center justify-center text-xl shadow-inner shrink-0" style={{ backgroundColor: `${color}15`, color }}>
                      {icon}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1">
                        <span className="text-xs font-bold uppercase tracking-wider" style={{ color }}>{name}</span>
                        <span className="flex items-center gap-1 text-xs font-bold text-slate-500 bg-slate-100 px-2 py-0.5 rounded-md">
                          <Award size={12} /> {q.score} pts
                        </span>
                      </div>
                      <h3 className="font-bold text-slate-800 leading-tight line-clamp-2 mb-1" title={q.title}>{q.title}</h3>
                    </div>
                  </div>

                  {/* Body */}
                  <div className="px-5 pb-4 flex-1">
                    <div className="bg-slate-50 rounded-xl p-3 border border-slate-100 mb-3">
                      <p className="text-xs text-slate-600 line-clamp-3 font-medium">{q.description}</p>
                    </div>
                    {q.sample_input && (
                      <div className="mb-2">
                        <span className="text-[10px] uppercase font-bold text-slate-400">Sample Input</span>
                        <code className="block bg-slate-900 text-slate-200 text-xs p-2 rounded-lg mt-1 font-mono truncate">{q.sample_input}</code>
                      </div>
                    )}
                  </div>

                  {/* Actions / Toggle */}
                  <div className="p-4 border-t border-slate-100 bg-slate-50/50 rounded-b-2xl flex items-center justify-between">
                    {selectedTab === 0 ? (
                      <>
                        <div className="flex items-center gap-1">
                          <span className={`w-2.5 h-2.5 rounded-full ${enabledCount > 0 ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`} />
                          <span className="text-xs font-bold text-slate-500">{enabledCount} batches active</span>
                        </div>
                        <div className="flex gap-1">
                          <button onClick={() => { setEditing(q.id); setForm({ ...q, language_id: q.language_id }); setOpenDialog(true); }} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"><Edit size={16} /></button>
                          <button onClick={() => handleDelete(q.id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"><Trash2 size={16} /></button>
                        </div>
                      </>
                    ) : (
                      <>
                        <div className="flex flex-col">
                          <span className={`text-xs font-bold ${bState.enabled ? 'text-emerald-600' : 'text-slate-400'}`}>
                            {bState.enabled ? 'ACTIVE' : 'INACTIVE'}
                          </span>
                          {bState.toggled_at && <span className="text-[10px] text-slate-400">{new Date(bState.toggled_at).toLocaleDateString()}</span>}
                        </div>
                        <label className="relative inline-flex items-center cursor-pointer">
                          <input
                            type="checkbox"
                            className="sr-only peer"
                            checked={!!bState.enabled}
                            onChange={() => handleToggle(q.id, batchId, bState.enabled)}
                            disabled={toggling[`${q.id}_${batchId}`]}
                          />
                          <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-emerald-500"></div>
                        </label>
                      </>
                    )}
                  </div>
                </motion.div>
              );
            })}
          </div>
        )}
      </div>

      {/* Add/Edit Modal */}
      <Modal isOpen={openDialog} onClose={() => setOpenDialog(false)} title={editing ? "Edit Question" : "Add New Question"} maxWidth="max-w-2xl">
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2">
              <label className="block text-sm font-bold text-slate-700 mb-1">Question Title</label>
              <input className="w-full px-4 py-2 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="e.g. Reverse a String" />
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Language</label>
              <select className="w-full px-4 py-2 border rounded-xl outline-none bg-white" value={form.language_id} onChange={e => setForm({ ...form, language_id: e.target.value })}>
                {LANGUAGES.map(l => <option key={l.id} value={l.id}>{l.icon} {l.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Score Points</label>
              <input type="number" className="w-full px-4 py-2 border rounded-xl outline-none" value={form.score} onChange={e => setForm({ ...form, score: e.target.value })} />
            </div>
            <div className="col-span-2">
              <label className="block text-sm font-bold text-slate-700 mb-1">Description</label>
              <textarea className="w-full px-4 py-2 border rounded-xl outline-none h-32" value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} placeholder="Full problem statement..." />
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Sample Input</label>
              <textarea className="w-full px-4 py-2 border rounded-xl outline-none font-mono text-sm bg-slate-50" value={form.sample_input} onChange={e => setForm({ ...form, sample_input: e.target.value })} rows={3} />
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Sample Output</label>
              <textarea className="w-full px-4 py-2 border rounded-xl outline-none font-mono text-sm bg-slate-50" value={form.sample_output} onChange={e => setForm({ ...form, sample_output: e.target.value })} rows={3} />
            </div>
          </div>
          <div className="flex justify-end gap-3 pt-4 border-t border-slate-100">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setOpenDialog(false)} />
            <ActionButton label={saving ? "Saving..." : "Save Question"} onClick={handleSave} disabled={saving} />
          </div>
        </div>
      </Modal>

    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Play,
  GraduationCap,
  FileQuestion,
  ClipboardList,
  Trophy,
  RefreshCw,
  LayoutDashboard,
  AlertCircle
} from 'lucide-react';
import axios from 'axios';
import StudentNavbar from './StudentNavbar';
import { motion } from 'framer-motion';

const StudentDashboard = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const fetchCourses = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem('token');
      const headers = token ? { Authorization: `Bearer ${token}` } : {};
      const resp = await axios.get('http://localhost:3000/api/students/courses-with-exams', { headers });

      const list = Array.isArray(resp.data.courses) ? resp.data.courses : [];
      const normalized = list.map((c) => ({
        course_id: c.course_id ?? c.id ?? null,
        course_name: c.course_name ?? c.name ?? '',
        course_code: c.course_code ?? c.code ?? '',
        hasExam: !!(c.hasExam === true || c.hasExam === 1 || c.hasExam === '1' || c.hasExam === 'true'),
      }));
      setCourses(normalized);
    } catch (err) {
      console.error('StudentDashboard fetch error', err?.response?.data || err.message);
      setError('Failed to fetch courses. Please login again.');
      setCourses([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCourses();
  }, []);

  const getCourseColor = (index) => {
    const colors = [
      'bg-blue-700',
      'bg-emerald-600',
      'bg-cyan-600',
      'bg-amber-600',
      'bg-violet-600',
      'bg-rose-600',
      'bg-slate-700',
      'bg-indigo-700'
    ];
    return colors[index % colors.length];
  };

  const getCourseIcon = (index) => {
    const icons = [GraduationCap, FileQuestion, ClipboardList, Trophy];
    return icons[index % icons.length];
  };

  return (
    <>
      <StudentNavbar />
      <div className="fixed inset-0 top-16 overflow-auto lms-page-bg">
        <div className="lms-container py-6 md:py-8 min-h-full">

          {/* Header Card */}
          <div className="relative mb-8 rounded-2xl bg-white border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-6 md:p-7 relative z-10 flex flex-col md:flex-row items-center gap-5">
              <div className="w-16 h-16 rounded-xl bg-blue-50 border border-blue-100 flex items-center justify-center">
                <LayoutDashboard size={30} className="text-blue-700" />
              </div>

              <div className="text-center md:text-left flex-1">
                <h1 className="text-3xl md:text-4xl font-bold text-slate-900 mb-2">
                  Student Dashboard
                </h1>
                <p className="text-slate-500 text-base md:text-lg">
                  Track courses and take exams
                </p>
              </div>

              <div className="flex gap-4">
                <button
                  onClick={fetchCourses}
                  className="lms-btn-primary px-6 text-white flex items-center gap-2"
                >
                  <RefreshCw size={20} className={loading ? "animate-spin" : ""} />
                  <span className="hidden md:inline">Refresh</span>
                </button>
              </div>
            </div>
          </div>

          {/* Stats Summary */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
            <div className="lms-card p-6 flex flex-col items-center justify-center">
              <div className="text-4xl font-black text-indigo-600 mb-1">{courses.length}</div>
              <div className="text-sm font-bold text-slate-500 uppercase tracking-wide">Total Courses</div>
            </div>
            <div className="lms-card p-6 flex flex-col items-center justify-center">
              <div className="text-4xl font-black text-emerald-500 mb-1">{courses.filter(c => c.hasExam).length}</div>
              <div className="text-sm font-bold text-slate-500 uppercase tracking-wide">Exams Available</div>
            </div>
            <div className="lms-card p-6 flex flex-col items-center justify-center">
              <div className="text-4xl font-black text-orange-500 mb-1">{courses.filter(c => !c.hasExam).length}</div>
              <div className="text-sm font-bold text-slate-500 uppercase tracking-wide">Upcoming Exams</div>
            </div>
          </div>

          {/* Courses Grid */}
          {loading ? (
            <div className="flex flex-col items-center justify-center py-16 gap-4">
              <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
              <p className="text-slate-500 font-medium">Loading your courses...</p>
            </div>
          ) : error ? (
            <div className="bg-red-50 rounded-2xl p-8 border border-red-100 text-center max-w-2xl mx-auto">
              <AlertCircle size={48} className="text-red-500 mx-auto mb-4" />
              <h3 className="text-xl font-bold text-red-700 mb-2">Something went wrong</h3>
              <p className="text-red-600 mb-6">{error}</p>
              <button
                onClick={fetchCourses}
                className="px-6 py-2 rounded-xl bg-red-600 text-white font-bold hover:bg-red-700 transition-colors"
              >
                Try Again
              </button>
            </div>
          ) : courses.length === 0 ? (
            <div className="lms-card p-12 text-center">
              <GraduationCap size={64} className="text-slate-300 mx-auto mb-4" />
              <h3 className="text-2xl font-bold text-slate-700 mb-2">No Courses Found</h3>
              <p className="text-slate-500">You haven't been allocated to any courses yet.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {courses.map((course, index) => {
                const id = course.course_id ?? course.id;
                const name = course.course_name ?? course.name;
                const code = course.course_code ?? course.code;
                const available = !!course.hasExam;
                const CourseIcon = getCourseIcon(index);
                const gradientClass = getCourseColor(index);

                return (
                  <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: index * 0.05 }}
                    key={id ?? `${code}-${index}`}
                    className="group relative bg-white rounded-xl shadow-sm hover:shadow-md transition-all duration-200 overflow-hidden border border-slate-200"
                  >
                    <div className={`absolute top-0 left-0 right-0 h-1 ${gradientClass}`} />

                    <div className="p-6">
                      <div className="flex justify-between items-start mb-4">
                        <div className={`w-12 h-12 rounded-lg ${gradientClass} flex items-center justify-center text-white shadow-sm`}>
                          <CourseIcon size={28} />
                        </div>
                        {available ? (
                          <span className="px-3 py-1 bg-emerald-50 text-emerald-700 text-xs font-semibold rounded-full border border-emerald-200">
                            Exam Ready
                          </span>
                        ) : (
                          <span className="px-3 py-1 bg-slate-100 text-slate-500 text-xs font-semibold rounded-full border border-slate-200">
                            No Exam
                          </span>
                        )}
                      </div>

                      <div className="mb-6">
                        <h3 className="text-lg font-bold text-slate-800 leading-tight mb-1 line-clamp-2 min-h-[3rem]">
                          {name}
                        </h3>
                        <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                          {code}
                        </p>
                      </div>

                      <button
                        onClick={() => available && navigate(`/student/exam/${id}`)}
                        disabled={!available}
                        className={`w-full py-3 px-4 rounded-lg flex items-center justify-center gap-2 font-semibold transition-all duration-200 ${available
                            ? `${gradientClass} text-white shadow-sm hover:brightness-95`
                            : 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200'
                          }`}
                      >
                        {available ? (
                          <>
                            <Play size={18} fill="currentColor" />
                            Start Exam
                          </>
                        ) : (
                          <>
                            <GraduationCap size={18} />
                            No Exam
                          </>
                        )}
                      </button>
                    </div>
                  </motion.div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </>
  );
};

export default StudentDashboard;

import React, { useEffect, useMemo, useState } from 'react';
import {
  Users, Search, UserPlus, Upload, FileText, Filter, RefreshCw,
  MoreVertical, Edit, Trash2, CheckCircle, X, ChevronDown, Mail, Phone,
  Globe, Download, ArrowRight, Smartphone
} from 'lucide-react';
import AdminLayout from './AdminLayout';
import axios from 'axios';
import { motion, AnimatePresence } from 'framer-motion';
import { useToast } from '../context/ToastContext';
import Skeleton from '../components/Skeleton';
import Pagination from '../components/Pagination';

const API_BASE = 'http://localhost:3000/api';
const API_COURSES = `${API_BASE}/courses/get-all-courses`;
const API_STUDENTS = `${API_BASE}/students`;

// --- Components ---

const Modal = ({ isOpen, onClose, title, children, maxWidth = 'max-w-md' }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
        />
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className={`relative w-full ${maxWidth} bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden flex flex-col max-h-[90vh]`}
        >
          <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between bg-slate-50">
            <h3 className="text-lg font-bold text-slate-800">{title}</h3>
            <button
              onClick={onClose}
              className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors"
            >
              <X size={20} />
            </button>
          </div>
          <div className="p-6 overflow-y-auto">
            {children}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const ActionButton = ({ onClick, icon: Icon, label, variant = 'primary', disabled = false }) => {
  const baseClass = 'inline-flex items-center justify-center gap-2 h-11 px-4 rounded-lg font-semibold transition-colors disabled:opacity-60 disabled:cursor-not-allowed';
  const variants = {
    primary: 'lms-btn-primary',
    secondary: 'lms-btn-secondary',
    danger: 'inline-flex items-center justify-center gap-2 h-11 px-4 rounded-lg font-semibold text-red-700 bg-red-50 border border-red-200 hover:bg-red-100',
    ghost: 'inline-flex items-center justify-center gap-2 h-11 px-4 rounded-lg font-semibold text-slate-600 hover:bg-slate-100'
  };

  return (
    <button onClick={onClick} disabled={disabled} className={`${baseClass} ${variants[variant]}`}>
      {Icon && <Icon size={18} strokeWidth={2.5} />}
      {label}
    </button>
  );
};

const StudentManagement = () => {
  // core data
  const [courses, setCourses] = useState([]);
  const [courseId, setCourseId] = useState('');
  const [batches, setBatches] = useState([]);
  const [students, setStudents] = useState([]);
  const [selectedBatchName, setSelectedBatchName] = useState('');
  const [batchNames, setBatchNames] = useState([]);
  const [batchCodesForName, setBatchCodesForName] = useState([]);
  const [selectedBatchCode, setSelectedBatchCode] = useState('');
  const [selectedBatchId, setSelectedBatchId] = useState('');

  // UI / dialogs
  const [loading, setLoading] = useState(false);
  const [openAdd, setOpenAdd] = useState(false);
  const [openUpload, setOpenUpload] = useState(false);
  const [openEdit, setOpenEdit] = useState(false);

  // forms
  const [addForm, setAddForm] = useState({ name: '', email: '', phone: '' });
  const [editForm, setEditForm] = useState({ id: null, name: '', email: '', phone: '' });
  const [uploadFile, setUploadFile] = useState(null);
  const [templateFile, setTemplateFile] = useState(null);
  const [templateMeta, setTemplateMeta] = useState(null);
  const [templateLoading, setTemplateLoading] = useState(false);
  const [templateUploading, setTemplateUploading] = useState(false);
  const [phoneError, setPhoneError] = useState({ add: false, edit: false });

  // search/snack
  const [searchQuery, setSearchQuery] = useState('');

  // global search dialog
  const [searchDialogOpen, setSearchDialogOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [selectedSearchStudent, setSelectedSearchStudent] = useState(null);
  const [selectedStudentBatches, setSelectedStudentBatches] = useState([]);
  const [searchLoading, setSearchLoading] = useState(false);
  const [globalStudentsCache, setGlobalStudentsCache] = useState([]);

  const authHeader = useMemo(() => {
    const t = localStorage.getItem('token');
    return t ? { Authorization: `Bearer ${t}` } : {};
  }, []);

  // Validation
  const validatePhone = (phone) => {
    return /^\d{10}$/.test(phone) && /^[6-9]/.test(phone);
  }

  const handleAddPhoneChange = (e) => {
    const val = e.target.value;
    if (val === '' || /^[0-9]+$/.test(val)) {
      setAddForm(prev => ({ ...prev, phone: val }));
      setPhoneError(prev => ({ ...prev, add: val.length > 0 && !validatePhone(val) }));
    }
  };

  const handleEditPhoneChange = (e) => {
    const val = e.target.value;
    if (val === '' || /^[0-9]+$/.test(val)) {
      setEditForm(prev => ({ ...prev, phone: val }));
      setPhoneError(prev => ({ ...prev, edit: val.length > 0 && !validatePhone(val) }));
    }
  };

  // ---------- loaders ----------
  const loadCourses = async () => {
    try {
      const res = await axios.get(API_COURSES, { headers: authHeader });
      setCourses(res.data?.courses || []);
    } catch (err) {
      console.error('loadCourses', err);
      setCourses([]);
    }
  };

  const loadBatchesForCourse = async (cid) => {
    if (!cid) {
      setBatches([]);
      setBatchNames([]);
      setBatchCodesForName([]);
      setSelectedBatchName('');
      setSelectedBatchCode('');
      setSelectedBatchId('');
      return;
    }
    try {
      const res = await axios.get(`${API_STUDENTS}/batches/${cid}`, { headers: authHeader });
      const arr = res.data?.batches || [];
      arr.sort((a, b) => (a.code || '').toLowerCase().localeCompare((b.code || '').toLowerCase()));
      setBatches(arr);
      const names = Array.from(new Set(arr.map(x => x.name || '').filter(Boolean)));
      setBatchNames(names);
      setSelectedBatchName('');
      setSelectedBatchCode('');
      setSelectedBatchId('');
      setBatchCodesForName([]);
    } catch (err) {
      console.error('loadBatchesForCourse', err);
    }
  };

  const fetchStudentsForBatchId = async (batch) => {
    if (!batch || !batch.id) return [];
    try {
      const res = await axios.get(`${API_STUDENTS}/batch/${batch.id}`, { headers: authHeader });
      const arr = res.data?.students || [];
      const withBatch = arr.map((s) => {
        const existingBatches = Array.isArray(s.batches) ? s.batches.slice() : [];
        const has = existingBatches.some(b => String(b.id) === String(batch.id) || b.code === batch.code);
        if (!has) existingBatches.push({ id: batch.id, name: batch.name || '', code: batch.code || '' });
        return { ...s, batches: existingBatches };
      });
      return withBatch;
    } catch (err) {
      console.error('fetchStudentsForBatchId', batch, err);
      return [];
    }
  };

  const loadStudents = async (cid, batchIdParam = '') => {
    if (!cid) {
      setStudents([]);
      return;
    }
    setLoading(true);
    try {
      if (batchIdParam) {
        const batch = batches.find(b => String(b.id) === String(batchIdParam)) || { id: batchIdParam, name: '', code: '' };
        const studentsForBatch = await fetchStudentsForBatchId(batch);
        setStudents(studentsForBatch);
        return;
      }

      if (selectedBatchName) {
        const matching = batches.filter(b => (b.name || '') === selectedBatchName);
        if (matching.length === 0) {
          setStudents([]);
          return;
        }
        const allArrays = await Promise.all(matching.map(b => fetchStudentsForBatchId(b)));
        const map = new Map();
        for (const arr of allArrays) {
          for (const s of arr) {
            const key = s.id != null ? `id:${s.id}` : `email:${(s.email || '').toLowerCase()}`;
            if (!map.has(key)) {
              map.set(key, { ...s, batches: Array.isArray(s.batches) ? s.batches.slice() : [] });
            } else {
              const existing = map.get(key);
              const existCodes = new Set((existing.batches || []).map(b => b.code));
              for (const nb of (s.batches || [])) {
                if (!existCodes.has(nb.code)) existing.batches.push(nb);
              }
              map.set(key, existing);
            }
          }
        }
        const combined = Array.from(map.values());
        setStudents(combined);
        return;
      }

      if (batches && batches.length > 0) {
        const allArrays = await Promise.all(batches.map(b => fetchStudentsForBatchId(b)));
        const map = new Map();
        for (const arr of allArrays) {
          for (const s of arr) {
            const key = s.id != null ? `id:${s.id}` : `email:${(s.email || '').toLowerCase()}`;
            if (!map.has(key)) {
              map.set(key, { ...s, batches: Array.isArray(s.batches) ? s.batches.slice() : [] });
            } else {
              const existing = map.get(key);
              const existCodes = new Set((existing.batches || []).map(b => b.code));
              for (const nb of (s.batches || [])) {
                if (!existCodes.has(nb.code)) existing.batches.push(nb);
              }
              map.set(key, existing);
            }
          }
        }
        const combined = Array.from(map.values());
        setStudents(combined);
        return;
      }

      {
        const res = await axios.get(`${API_STUDENTS}/by-course/${cid}`, { headers: authHeader });
        const arr = res.data?.students || res.data || [];
        const normalized = arr.map((s) => ({ ...s, batches: Array.isArray(s.batches) ? s.batches : (s.Batches || []) }));
        setStudents(normalized);
      }
    } catch (err) {
      console.error('loadStudents', err);
      setStudents([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadCourses(); }, []);

  useEffect(() => {
    if (courseId) {
      loadBatchesForCourse(courseId);
      loadStudents(courseId, '');
    } else {
      setStudents([]);
      setBatches([]);
      setBatchNames([]);
      setBatchCodesForName([]);
      setSelectedBatchName('');
      setSelectedBatchCode('');
      setSelectedBatchId('');
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [courseId]);

  useEffect(() => {
    if (!selectedBatchName) {
      setBatchCodesForName([]);
      setSelectedBatchCode('');
      setSelectedBatchId('');
      if (courseId) loadStudents(courseId, '');
      return;
    }
    const codes = batches.filter(b => (b.name || '') === selectedBatchName).map(b => ({ id: b.id, code: b.code }));
    codes.sort((a, b) => (a.code || '').toLowerCase().localeCompare((b.code || '').toLowerCase()));
    setBatchCodesForName(codes);
    setSelectedBatchCode('');
    setSelectedBatchId('');
    if (courseId) loadStudents(courseId, '');
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedBatchName, batches]);

  useEffect(() => {
    if (!selectedBatchName || !selectedBatchCode) {
      setSelectedBatchId('');
      if (courseId) loadStudents(courseId, '');
      return;
    }
    const found = batches.find(b => (b.name || '') === selectedBatchName && (b.code || '') === selectedBatchCode);
    const id = found?.id || '';
    setSelectedBatchId(id);
    if (id) {
      loadStudents(courseId, id);
    } else {
      loadStudents(courseId, '');
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedBatchCode, selectedBatchName, batches]);

  // ---------- toast ----------
  const toast = useToast();

  // ---------- add/edit/upload ----------
  const handleAdd = async () => {
    try {
      const selectedCourse = courses.find(c => String(c.id) === String(courseId));
      if (!selectedCourse) { toast.error('Select a course first'); return; }
      if (!selectedBatchName || !selectedBatchCode) { toast.error('Select batch name and code'); return; }

      const payload = {
        name: addForm.name,
        email: addForm.email,
        phone: addForm.phone,
        course_code: selectedCourse.course_code
      };
      const res = await axios.post(`${API_STUDENTS}/add`, payload, { headers: authHeader });
      const createdId = res.data?.student?.id || res.data?.id || res.data?.insertId || res.data?.createdStudentId || null;

      if (createdId && selectedBatchId) {
        try {
          await axios.post(`${API_STUDENTS}/${createdId}/assign-batch/${selectedBatchId}`, {}, { headers: authHeader });
        } catch (e) { console.warn('assign created student failed', e?.message || e); }
      }
      setOpenAdd(false);
      await loadStudents(courseId, selectedBatchId || '');
      setAddForm({ name: '', email: '', phone: '' });
      toast.success('Student added successfully!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Add student failed');
    }
  };

  const openEditDialog = (student) => {
    setEditForm({ id: student.id, name: student.name || '', email: student.email || '', phone: student.phone || '' });
    setOpenEdit(true);
  };

  const handleUpdateStudent = async () => {
    try {
      if (!editForm.id) return;
      await axios.put(`${API_STUDENTS}/update/${editForm.id}`, {
        name: editForm.name,
        email: editForm.email,
        phone: editForm.phone
      }, { headers: authHeader });
      setOpenEdit(false);
      await loadStudents(courseId, selectedBatchId || '');
      toast.success('Student updated successfully');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Update failed');
    }
  };

  const handleDeleteStudent = async (studentId) => {
    if (!window.confirm('Delete this student permanently?')) return;
    try {
      await axios.delete(`${API_STUDENTS}/remove/${studentId}/${courseId}`, { headers: authHeader });
      await loadStudents(courseId, selectedBatchId || '');
      toast.success('Student deleted successfully');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Delete failed');
    }
  };

  const handleUpload = async () => {
    if (!courseId) { toast.error('Select a course before uploading'); return; }
    if (!selectedBatchName || !selectedBatchCode) { toast.error('Select a batch name and code'); return; }
    if (!uploadFile) { toast.error('Choose a file to upload'); return; }
    try {
      const selectedCourse = courses.find(c => String(c.id) === String(courseId));
      const form = new FormData();
      form.append('file', uploadFile);
      form.append('course_code', selectedCourse?.course_code || '');
      form.append('batch_code', selectedBatchCode || '');
      if (selectedBatchId) form.append('batchId', selectedBatchId);

      const res = await axios.post(`${API_STUDENTS}/upload`, form, {
        headers: { ...authHeader, 'Content-Type': 'multipart/form-data' }
      });

      const { count, assignedExisting, failures } = res.data;
      let msg = `Successfully created ${count} new students.`;
      if (assignedExisting) msg += ` Assigned ${assignedExisting} existing students.`;

      let hasError = false;
      if (failures && failures.length > 0) {
        hasError = true;
        msg += `\n\n${failures.length} rows failed to process:`;
        failures.slice(0, 5).forEach(f => {
          msg += `\n- Row ${f.row?.Name || 'Unknown'}: ${f.error}`;
        });
        if (failures.length > 5) msg += `\n...and ${failures.length - 5} more.`;
      }

      if (hasError) toast.error(msg);
      else toast.success(msg);

      await loadBatchesForCourse(courseId);
      await loadStudents(courseId, selectedBatchId || '');
      setOpenUpload(false);
      setUploadFile(null);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Upload failed');
    }
  };

  const loadStudentTemplateMeta = async () => {
    setTemplateLoading(true);
    try {
      const res = await axios.get(`${API_STUDENTS}/templates/students`, { headers: authHeader });
      setTemplateMeta(res.data?.template || null);
    } catch (err) {
      setTemplateMeta(null);
      toast.error(err.response?.data?.message || 'Failed to load upload template');
    } finally {
      setTemplateLoading(false);
    }
  };

  const handleTemplateUpload = async () => {
    if (!templateFile) {
      toast.error('Choose a template file first');
      return;
    }
    setTemplateUploading(true);
    try {
      const form = new FormData();
      form.append('templateFile', templateFile);
      await axios.post(`${API_STUDENTS}/templates/students`, form, {
        headers: { ...authHeader, 'Content-Type': 'multipart/form-data' }
      });
      setTemplateFile(null);
      await loadStudentTemplateMeta();
      toast.success('Student upload template saved');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Template upload failed');
    } finally {
      setTemplateUploading(false);
    }
  };

  const handleDownloadTemplate = async () => {
    try {
      const response = await axios.get(`${API_STUDENTS}/templates/students/download`, {
        headers: authHeader,
        responseType: 'blob'
      });
      const contentDisposition = response.headers['content-disposition'] || '';
      const fromHeader = /filename="?([^"]+)"?/i.exec(contentDisposition)?.[1];
      const filename = fromHeader || templateMeta?.fileName || 'students_import_template.csv';
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', filename);
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Template download failed');
    }
  };

  // ---------- GLOBAL SEARCH flow ----------
  const openGlobalSearch = async () => {
    setSearchTerm('');
    setSearchResults([]);
    setSelectedSearchStudent(null);
    setSelectedStudentBatches([]);
    setSearchDialogOpen(true);

    if (globalStudentsCache.length > 0) return;
    setSearchLoading(true);
    try {
      const res = await axios.get(`${API_STUDENTS}/get-all-students`, { headers: authHeader });
      const all = res.data?.students || [];
      setGlobalStudentsCache(all);
    } catch (err) {
      setGlobalStudentsCache([]);
    } finally {
      setSearchLoading(false);
    }
  };

  useEffect(() => {
    if (!searchDialogOpen) return;
    const q = (searchTerm || '').trim().toLowerCase();
    if (!q) {
      setSearchResults([]);
      return;
    }
    const results = (globalStudentsCache || []).filter(s =>
      (s.name || '').toLowerCase().includes(q) ||
      (s.email || '').toLowerCase().includes(q) ||
      (s.phone || '').toLowerCase().includes(q)
    );
    setSearchResults(results);
  }, [searchTerm, globalStudentsCache, searchDialogOpen]);

  const fetchStudentBatches = async (student) => {
    if (!student || !student.id) {
      setSelectedStudentBatches([]);
      return;
    }
    setSearchLoading(true);
    try {
      const found = [];
      for (const c of courses) {
        let courseBatches = [];
        try {
          const br = await axios.get(`${API_STUDENTS}/batches/${c.id}`, { headers: authHeader });
          courseBatches = br.data?.batches || [];
        } catch (err) {
          continue;
        }

        for (const b of courseBatches) {
          try {
            const sr = await axios.get(`${API_STUDENTS}/batch/${b.id}`, { headers: authHeader });
            const studentsInBatch = sr.data?.students || [];
            if (studentsInBatch.some(st => String(st.id) === String(student.id))) {
              found.push({ id: b.id, name: b.name, code: b.code, course_id: c.id, course_name: c.name });
            }
          } catch (errInner) {
            continue;
          }
        }
      }
      setSelectedStudentBatches(found);
    } catch (err) {
      setSelectedStudentBatches([]);
    } finally {
      setSearchLoading(false);
    }
  };

  const onSelectSearchStudent = async (s) => {
    setSelectedSearchStudent(s);
    await fetchStudentBatches(s);
  };

  const filteredStudents = (students || []).filter(s => {
    if (!searchQuery || searchQuery.trim() === '') return true;
    const q = searchQuery.trim().toLowerCase();
    return (s.name || '').toLowerCase().includes(q) || (s.email || '').toLowerCase().includes(q) || (s.phone || '').toLowerCase().includes(q);
  });

  const canManage = Boolean(courseId && selectedBatchName && selectedBatchCode);

  // pagination state
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  // Reset page when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [courseId, selectedBatchName, selectedBatchCode, searchQuery]);

  useEffect(() => {
    if (openUpload) {
      loadStudentTemplateMeta();
    } else {
      setTemplateFile(null);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [openUpload]);

  // Derived state for pagination
  const paginatedStudents = useMemo(() => {
    const start = (currentPage - 1) * itemsPerPage;
    return filteredStudents.slice(start, start + itemsPerPage);
  }, [filteredStudents, currentPage, itemsPerPage]);

  return (
    <AdminLayout disableScroll={true}>
      <div className="flex flex-col h-full bg-slate-50">
        {/* Header */}
        <div className="mb-8 bg-white border-b border-slate-200 px-8 py-6 shadow-sm">
          <div className="lms-container flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex items-center gap-4">
              <div className="p-3 rounded-2xl bg-indigo-50 text-indigo-600">
                <Users size={32} />
              </div>
              <div>
                <h1 className="text-2xl font-bold text-slate-900">Student Management</h1>
                <p className="text-slate-500 font-medium">Manage students across courses and batches</p>
              </div>
            </div>

            <div className="flex gap-3">
              <ActionButton
                icon={Globe}
                label="Global Search"
                variant="secondary"
                onClick={openGlobalSearch}
              />
            </div>
          </div>
        </div>

        {/* Filters & Content */}
        <div className="flex-1 overflow-auto px-4 md:px-8 pb-8 custom-scrollbar">
          <div className="lms-container space-y-6">

            {/* Filters Card */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">

                {/* Select Course */}
                <div className="relative">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block">
                    Select Course
                  </label>
                  <div className="relative">
                    <select
                      value={courseId}
                      onChange={(e) => setCourseId(e.target.value)}
                      className="w-full pl-4 pr-10 py-3 appearance-none bg-slate-50 border border-slate-200 rounded-xl font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all"
                    >
                      <option value="">Choose a course...</option>
                      {courses.map(c => (
                        <option key={c.id} value={c.id}>{c.name}</option>
                      ))}
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                  </div>
                </div>

                {/* Batch Name */}
                <div className="relative">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block">
                    Batch Name
                  </label>
                  <div className="relative">
                    <select
                      value={selectedBatchName}
                      onChange={(e) => setSelectedBatchName(e.target.value)}
                      disabled={!courseId}
                      className="w-full pl-4 pr-10 py-3 appearance-none bg-slate-50 border border-slate-200 rounded-xl font-medium text-slate-700 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all"
                    >
                      <option value="">All Batches</option>
                      {batchNames.map(n => <option key={n} value={n}>{n}</option>)}
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                  </div>
                </div>

                {/* Batch Code */}
                <div className="relative">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block">
                    Batch Code
                  </label>
                  <div className="relative">
                    <select
                      value={selectedBatchCode}
                      onChange={(e) => setSelectedBatchCode(e.target.value)}
                      disabled={!selectedBatchName}
                      className="w-full pl-4 pr-10 py-3 appearance-none bg-slate-50 border border-slate-200 rounded-xl font-medium text-slate-700 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all"
                    >
                      <option value="">All Codes</option>
                      {batchCodesForName.map(c => (
                        <option key={c.id} value={c.code}>{c.code}</option>
                      ))}
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                  </div>
                </div>

                {/* Search in List */}
                <div className="relative">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block">
                    Filter List
                  </label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input
                      type="text"
                      placeholder="Search name, email..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all placeholder:text-slate-400"
                    />
                  </div>
                </div>

              </div>
            </div>

            {/* Actions for Selected Batch */}
            {canManage && (
              <div className="flex flex-wrap gap-4 justify-end">
                <ActionButton
                  icon={Upload}
                  label="Bulk Upload"
                  variant="secondary"
                  onClick={() => setOpenUpload(true)}
                />
                <ActionButton
                  icon={UserPlus}
                  label="Add Student"
                  variant="primary"
                  onClick={() => setOpenAdd(true)}
                />
              </div>
            )}

            {/* Students Content Area */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden min-h-[400px] flex flex-col">
              {loading ? (
                <div className="p-6 space-y-4">
                  {[...Array(5)].map((_, i) => (
                    <div key={i} className="flex gap-4">
                      <Skeleton width="40px" height="40px" rounded="rounded-full" />
                      <div className="flex-1 space-y-2">
                        <Skeleton height="20px" width="30%" />
                        <Skeleton height="15px" width="50%" />
                      </div>
                    </div>
                  ))}
                </div>
              ) : !courseId ? (
                <div className="flex flex-col items-center justify-center py-20 text-center flex-1">
                  <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-6">
                    <Users size={40} className="text-slate-400" />
                  </div>
                  <h3 className="text-xl font-bold text-slate-700 mb-2">No Course Selected</h3>
                  <p className="text-slate-500 max-w-sm mx-auto">Please select a course from the filters above to view and manage registered students.</p>
                </div>
              ) : filteredStudents.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-center flex-1">
                  <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-6">
                    <Search size={40} className="text-slate-400" />
                  </div>
                  <h3 className="text-xl font-bold text-slate-700 mb-2">No Students Found</h3>
                  <p className="text-slate-500">Try adjusting your filters or search terms.</p>
                </div>
              ) : (
                <>
                  {/* Desktop Table View */}
                  <div className="hidden md:block overflow-x-auto">
                    <table className="w-full">
                      <thead>
                        <tr className="bg-slate-50 border-b border-slate-200">
                          <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider w-16">#</th>
                          <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Student Name</th>
                          <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Email / Contact</th>
                          <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Batches</th>
                          <th className="px-6 py-4 text-right text-xs font-bold text-slate-500 uppercase tracking-wider">Actions</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                        {paginatedStudents.map((s, i) => (
                          <tr key={s.id || i} className="hover:bg-slate-50/50 transition-colors group">
                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-500">
                              {(currentPage - 1) * itemsPerPage + i + 1}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <div className="text-sm font-bold text-slate-700">{s.name}</div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <div className="flex flex-col gap-1">
                                <div className="flex items-center gap-2 text-sm font-medium text-slate-600">
                                  <Mail size={14} className="text-slate-400" />
                                  {s.email}
                                </div>
                                <div className="flex items-center gap-2 text-xs font-medium text-slate-500">
                                  <Phone size={14} className="text-slate-400" />
                                  {s.phone || 'N/A'}
                                </div>
                              </div>
                            </td>
                            <td className="px-6 py-4">
                              <div className="flex flex-wrap gap-2">
                                {s.batches && s.batches.length > 0 ? (
                                  s.batches.map(b => (
                                    <span key={b.id || `${b.code}-${b.name}`} className="inline-flex items-center px-2.5 py-1 rounded-md bg-indigo-50 text-indigo-700 text-xs font-semibold border border-indigo-100">
                                      {b.code}
                                    </span>
                                  ))
                                ) : (
                                  <span className="text-xs text-slate-400 italic">Unassigned</span>
                                )}
                              </div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-right">
                              <div className="flex items-center justify-end gap-2 opacity-100">
                                <button
                                  onClick={() => openEditDialog(s)}
                                  className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                                  title="Edit Student"
                                >
                                  <Edit size={18} />
                                </button>
                                <button
                                  onClick={() => handleDeleteStudent(s.id)}
                                  className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                  title="Remove Student"
                                >
                                  <Trash2 size={18} />
                                </button>
                              </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>

                  {/* Mobile Card View */}
                  <div className="md:hidden divide-y divide-slate-100">
                    {paginatedStudents.map((s) => (
                      <div key={s.id} className="p-4 space-y-3">
                        <div className="flex justify-between items-start">
                          <div>
                            <h4 className="font-bold text-slate-800">{s.name}</h4>
                            <div className="text-sm text-slate-500 flex items-center gap-2 mt-1">
                              <Mail size={12} /> {s.email}
                            </div>
                          </div>
                          <div className="flex gap-1">
                            <button onClick={() => openEditDialog(s)} className="p-2 text-indigo-600 bg-indigo-50 rounded-lg"><Edit size={16} /></button>
                            <button onClick={() => handleDeleteStudent(s.id)} className="p-2 text-red-600 bg-red-50 rounded-lg"><Trash2 size={16} /></button>
                          </div>
                        </div>

                        <div className="flex flex-wrap gap-2">
                          {s.batches && s.batches.length > 0 ? (
                            s.batches.map(b => (
                              <span key={b.id || `${b.code}-${b.name}`} className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-100 text-slate-700">
                                {b.code}
                              </span>
                            ))
                          ) : (
                            <span className="text-xs text-slate-400 italic">No batches</span>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>

                  {/* Pagination Control */}
                  <Pagination
                    currentPage={currentPage}
                    totalItems={filteredStudents.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                  />
                </>
              )}
            </div>

          </div>
        </div>
      </div>

      {/* --- Dialogs --- */}

      {/* Add Student Modal */}
      <Modal isOpen={openAdd} onClose={() => setOpenAdd(false)} title="Add New Student">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Full Name</label>
            <input
              type="text"
              className="lms-input"
              value={addForm.name}
              onChange={e => setAddForm(prev => ({ ...prev, name: e.target.value }))}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Email Address</label>
            <input
              type="email"
              className="lms-input"
              value={addForm.email}
              onChange={e => setAddForm(prev => ({ ...prev, email: e.target.value }))}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Phone Number (Optional)</label>
            <input
              type="text"
              maxLength={10}
              className={`lms-input ${phoneError.add ? 'border-red-500 ring-red-100 focus:ring-red-100 focus:border-red-500' : ''}`}
              placeholder="10-digit number"
              value={addForm.phone}
              onChange={handleAddPhoneChange}
            />
            {phoneError.add && <p className="text-red-500 text-xs mt-1 font-medium">Must be a valid 10-digit number</p>}
          </div>

          {selectedBatchName && (
            <div className="bg-emerald-50 border border-emerald-100 rounded-xl p-4 flex items-start gap-3">
              <CheckCircle className="text-emerald-600 shrink-0 mt-0.5" size={18} />
              <div>
                <h4 className="text-sm font-bold text-emerald-800">Assigning to Batch</h4>
                <p className="text-sm text-emerald-600">{selectedBatchCode} - {selectedBatchName}</p>
              </div>
            </div>
          )}

          <div className="pt-4 flex justify-end gap-3">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setOpenAdd(false)} />
            <ActionButton
              label="Add Student"
              variant="primary"
              onClick={handleAdd}
              disabled={!addForm.name || !addForm.email || phoneError.add}
            />
          </div>
        </div>
      </Modal>

      {/* Edit Student Modal */}
      <Modal isOpen={openEdit} onClose={() => setOpenEdit(false)} title="Edit Student">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Full Name</label>
            <input
              type="text"
              className="lms-input"
              value={editForm.name}
              onChange={e => setEditForm(prev => ({ ...prev, name: e.target.value }))}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Email Address</label>
            <input
              type="email"
              className="lms-input"
              value={editForm.email}
              onChange={e => setEditForm(prev => ({ ...prev, email: e.target.value }))}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Phone Number</label>
            <input
              type="text"
              maxLength={10}
              className={`lms-input ${phoneError.edit ? 'border-red-500 ring-red-100 focus:ring-red-100 focus:border-red-500' : ''}`}
              placeholder="10-digit number"
              value={editForm.phone}
              onChange={handleEditPhoneChange}
            />
            {phoneError.edit && <p className="text-red-500 text-xs mt-1 font-medium">Must be a valid 10-digit number</p>}
          </div>

          <div className="pt-4 flex justify-end gap-3">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setOpenEdit(false)} />
            <ActionButton
              label="Save Changes"
              variant="primary"
              onClick={handleUpdateStudent}
              disabled={!editForm.name || !editForm.email || phoneError.edit}
            />
          </div>
        </div>
      </Modal>

      {/* Upload Modal */}
      <Modal isOpen={openUpload} onClose={() => setOpenUpload(false)} title="Bulk Upload Students">
        <div className="space-y-6">
          <div className="bg-blue-50 border border-blue-100 rounded-xl p-4">
            <h4 className="flex items-center gap-2 font-bold text-blue-800 mb-2">
              <FileText size={18} />
              Format Requirements
            </h4>
            <p className="text-sm text-blue-700 mb-1">Upload a <strong>CSV</strong> or <strong>Excel</strong> file with columns:</p>
            <ul className="text-sm text-blue-700 list-disc list-inside font-medium pl-2">
              <li>Name</li>
              <li>Email</li>
              <li>Phone (Optional)</li>
            </ul>
            <div className="mt-4 space-y-3">
              <button
                type="button"
                onClick={handleDownloadTemplate}
                className="text-sm font-bold text-blue-600 hover:text-blue-800 hover:underline inline-flex items-center gap-1"
              >
                <Download size={14} /> Download CSV Template
              </button>
              <div className="rounded-lg border border-blue-200 bg-white p-3 space-y-2">
                <p className="text-xs text-slate-600">
                  {templateLoading
                    ? 'Loading template details...'
                    : templateMeta
                      ? `Current template: ${templateMeta.fileName} (${new Date(templateMeta.uploadedAt).toLocaleString()})`
                      : 'Using default built-in template. Upload a custom one below.'}
                </p>
                <div className="flex flex-col md:flex-row gap-2">
                  <input
                    type="file"
                    accept=".csv, .xls, .xlsx"
                    className="lms-input h-10 px-3 py-1.5 text-sm"
                    onChange={(e) => setTemplateFile(e.target.files?.[0] || null)}
                  />
                  <button
                    type="button"
                    onClick={handleTemplateUpload}
                    disabled={!templateFile || templateUploading}
                    className="lms-btn-secondary h-10 px-3 text-sm whitespace-nowrap"
                  >
                    {templateUploading ? 'Saving...' : 'Upload Template'}
                  </button>
                </div>
              </div>
            </div>
          </div>

          <div className={`border-2 border-dashed rounded-2xl p-8 text-center transition-colors ${uploadFile ? 'border-emerald-500 bg-emerald-50/50' : 'border-slate-300 hover:border-indigo-500 hover:bg-slate-50'}`}>
            <Upload className={`mx-auto mb-4 ${uploadFile ? 'text-emerald-500' : 'text-slate-400'}`} size={48} />
            {uploadFile ? (
              <div>
                <p className="text-emerald-700 font-bold text-lg mb-1">File Selected</p>
                <p className="text-slate-600 border border-slate-200 bg-white px-3 py-1 rounded inline-block">{uploadFile.name}</p>
              </div>
            ) : (
              <>
                <p className="text-slate-700 font-bold mb-1">Click to browse</p>
                <p className="text-slate-500 text-sm">Supports .csv, .xls, .xlsx</p>
              </>
            )}
            <input
              type="file"
              accept=".csv, .xls, .xlsx"
              className="hidden"
              id="file-upload"
              onChange={e => setUploadFile(e.target.files?.[0] || null)}
            />
            <label htmlFor="file-upload" className="absolute inset-0 cursor-pointer"></label>
          </div>

          <div className="pt-2 flex justify-end gap-3">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setOpenUpload(false)} />
            <ActionButton
              label="Upload"
              variant="primary"
              onClick={handleUpload}
              disabled={!uploadFile}
            />
          </div>
        </div>
      </Modal>

      {/* Global Search Modal */}
      <Modal isOpen={searchDialogOpen} onClose={() => setSearchDialogOpen(false)} title="Global Student Search" maxWidth="max-w-2xl">
        <div className="space-y-6 min-h-[400px] flex flex-col">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input
              type="text"
              autoFocus
              placeholder="Search all students by name, email, phone..."
              className="lms-input pl-12 pr-4 text-base"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>

          {searchLoading ? (
            <div className="flex-1 flex flex-col items-center justify-center p-8">
              <RefreshCw className="animate-spin text-indigo-500 mb-2" size={32} />
              <p className="text-slate-500">Searching directory...</p>
            </div>
          ) : searchResults.length === 0 ? (
            <div className="flex-1 flex flex-col items-center justify-center p-8 text-center opacity-60">
              <Search size={48} className="text-slate-300 mb-4" />
              <p className="text-slate-500 font-medium">{searchTerm ? 'No matches found' : 'Start typing to search...'}</p>
            </div>
          ) : (
            <div className="flex-1 overflow-y-auto max-h-[400px] space-y-2 pr-1">
              {searchResults.map(s => (
                <div
                  key={s.id}
                  onClick={() => onSelectSearchStudent(s)}
                  className={`p-4 rounded-xl border cursor-pointer transition-all ${selectedSearchStudent?.id === s.id ? 'bg-indigo-50 border-indigo-200 ring-1 ring-indigo-200' : 'bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50'}`}
                >
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-bold text-slate-800">{s.name}</h4>
                      <div className="text-sm text-slate-500 flex items-center gap-2 mt-0.5">
                        <Mail size={12} /> {s.email}
                      </div>
                      <div className="text-sm text-slate-500 flex items-center gap-2 mt-0.5">
                        <Smartphone size={12} /> {s.phone || 'N/A'}
                      </div>
                    </div>
                    {selectedSearchStudent?.id === s.id && <ArrowRight className="text-indigo-500" size={20} />}
                  </div>

                  {/* Expanded Details */}
                  {selectedSearchStudent?.id === s.id && (
                    <div className="mt-4 pt-4 border-t border-indigo-100/50">
                      <h5 className="text-xs font-bold text-indigo-700 uppercase tracking-wide mb-2">Enrollments</h5>
                      {searchLoading ? (
                        <p className="text-xs text-slate-400">Loading batches...</p>
                      ) : selectedStudentBatches.length > 0 ? (
                        <div className="flex flex-wrap gap-2">
                          {selectedStudentBatches.map(b => (
                            <span key={b.id} className="text-xs px-2 py-1 bg-white border border-indigo-100 text-indigo-700 rounded-md font-medium shadow-sm">
                              {b.code} ({b.course_name})
                            </span>
                          ))}
                        </div>
                      ) : (
                        <p className="text-xs text-slate-400 italic">No batch assignments found</p>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </Modal>

    </AdminLayout>
  );
};

export default StudentManagement;

import React, { useEffect, useMemo, useState } from "react";
import {
  Users, BookOpen, Clock, Edit, Lock, Trash2,
  CheckCircle, AlertCircle, PieChart as PieChartIcon,
  Activity, Shield, Medal, Book, Upload, ChevronDown,
  ChevronRight, Calendar, Phone, Mail
} from "lucide-react";
import StudentNavbar from "./StudentNavbar";
import axios from "axios";
import { useNavigate } from 'react-router-dom';
import { clearSession } from '../utils/auth';
import {
  ResponsiveContainer, LineChart, Line, XAxis, YAxis, Tooltip as RechartTooltip, CartesianGrid, PieChart, Pie, Cell
} from "recharts";
import { motion, AnimatePresence } from "framer-motion";

const API_BASE = "http://localhost:3000/api";
const API_ME = `${API_BASE}/students/me`;
const API_COURSES_WITH_EXAMS = `${API_BASE}/students/courses-with-exams`;
const API_SUBMISSIONS_MINE = `${API_BASE}/submissions/mine`;
const API_CHANGE_PASSWORD = `${API_BASE}/students/change-password`;
const API_UPDATE_ME = `${API_BASE}/students/me`;

const STATUS_COLORS = {
  accepted: "#10b981",
  pending: "#f59e0b",
  rejected: "#ef4444"
};

// --- Helper Components ---

const Modal = ({ isOpen, onClose, title, children, maxWidth = 'max-w-md' }) => {
  if (!isOpen) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
        />
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className={`relative w-full ${maxWidth} bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]`}
        >
          <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <h3 className="text-lg font-bold text-slate-800">{title}</h3>
            <button onClick={onClose} className="p-2 -mr-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 transition-colors">
              <span className="sr-only">Close</span>
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div className="p-6 overflow-y-auto">
            {children}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

const ActionButton = ({ onClick, icon: Icon, label, variant = 'primary', disabled = false, size = 'normal', fullWidth = false }) => {
  const baseClass = "flex items-center justify-center gap-2 rounded-xl font-bold transition-all duration-300 transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none";
  const sizeClass = size === 'small' ? 'px-3 py-1.5 text-xs' : 'px-4 py-2 text-sm';
  const widthClass = fullWidth ? 'w-full' : '';
  const variants = {
    primary: "bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-lg shadow-indigo-500/25 hover:shadow-indigo-500/40 hover:-translate-y-0.5",
    secondary: "bg-white text-slate-700 border border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm",
    danger: "bg-red-50 text-red-600 border border-red-100 hover:bg-red-100",
    ghost: "bg-transparent text-slate-500 hover:text-indigo-600 hover:bg-indigo-50"
  };

  return (
    <button onClick={onClick} disabled={disabled} className={`${baseClass} ${sizeClass} ${widthClass} ${variants[variant]}`}>
      {Icon && <Icon size={size === 'small' ? 14 : 18} strokeWidth={2.5} />}
      {label}
    </button>
  );
};

const StatCard = ({ title, value, icon: Icon, color, subtitle }) => {
  const getColors = (c) => {
    switch (c) {
      case 'indigo': return { bg: 'bg-indigo-50', text: 'text-indigo-600', border: 'border-indigo-100', iconBg: 'bg-indigo-100' };
      case 'emerald': return { bg: 'bg-emerald-50', text: 'text-emerald-600', border: 'border-emerald-100', iconBg: 'bg-emerald-100' };
      case 'cyan': return { bg: 'bg-cyan-50', text: 'text-cyan-600', border: 'border-cyan-100', iconBg: 'bg-cyan-100' };
      case 'amber': return { bg: 'bg-amber-50', text: 'text-amber-600', border: 'border-amber-100', iconBg: 'bg-amber-100' };
      default: return { bg: 'bg-slate-50', text: 'text-slate-600', border: 'border-slate-100', iconBg: 'bg-slate-100' };
    }
  };
  const theme = getColors(color);

  return (
    <div className={`p-6 rounded-2xl border ${theme.border} ${theme.bg} flex flex-col justify-between transition-all duration-300 hover:shadow-md hover:-translate-y-1 h-full`}>
      <div className="flex justify-between items-start mb-4">
        <div className={`p-3 rounded-xl ${theme.iconBg} ${theme.text}`}>
          <Icon size={24} />
        </div>
        <span className={`text-xs font-bold px-2 py-1 rounded-full bg-white/60 ${theme.text}`}>
          {subtitle}
        </span>
      </div>
      <div>
        <h4 className="text-slate-500 font-bold text-sm uppercase tracking-wider mb-1">{title}</h4>
        <p className={`text-3xl font-black ${theme.text}`}>{value}</p>
      </div>
    </div>
  );
};

export default function StudentProfile() {
  const navigate = useNavigate();

  // loading & data
  const [loading, setLoading] = useState(true);
  const [profile, setProfile] = useState(null);
  const [courses, setCourses] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [fetchDebug, setFetchDebug] = useState([]);
  const [error, setError] = useState("");

  // UI state
  const [tab, setTab] = useState("overview"); // overview, submissions, settings
  const [coursesOpen, setCoursesOpen] = useState(true);

  // dialogs
  const [editOpen, setEditOpen] = useState(false);
  const [pwdOpen, setPwdOpen] = useState(false);

  // form state
  const [editForm, setEditForm] = useState({ name: "", phone: "" });
  const [pwdForm, setPwdForm] = useState({ oldPassword: "", newPassword: "", confirmPassword: "" });
  const [deletingAccount, setDeletingAccount] = useState(false);

  // debug helper
  const debug = (label, obj) => {
    const entry = { ts: new Date().toISOString(), label, data: obj };
    // console.log("STUDENTPROFILE DEBUG:", label, obj); 
    setFetchDebug(prev => [entry, ...prev].slice(0, 60));
  };

  useEffect(() => {
    let mounted = true;
    async function loadAll() {
      setLoading(true);
      setError("");
      debug("start-fetch", "starting sequential fetches");
      const token = localStorage.getItem("token");
      const headers = token ? { Authorization: `Bearer ${token}` } : {};

      try {
        const r = await axios.get(API_ME, { headers });
        const me = r?.data?.data ?? r?.data ?? null;
        if (mounted) {
          setProfile(me);
          setEditForm({ name: me?.name || "", phone: me?.phone || "" });
        }
      } catch (err) { debug("GET /students/me ERROR", err); }

      try {
        const r = await axios.get(API_COURSES_WITH_EXAMS, { headers });
        const raw = r?.data?.courses ?? r?.data?.data ?? r?.data ?? [];
        if (mounted) setCourses(Array.isArray(raw) ? raw : []);
      } catch (err) { debug("GET /students/courses-with-exams ERROR", err); }

      try {
        const r = await axios.get(API_SUBMISSIONS_MINE, { headers });
        const payload = r?.data ?? {};
        let arr = [];
        if (Array.isArray(payload)) arr = payload;
        else if (Array.isArray(payload.submissions)) arr = payload.submissions;
        else if (Array.isArray(payload.data)) arr = payload.data;
        else if (Array.isArray(payload.items)) arr = payload.items;

        arr = arr.slice().sort((a, b) => new Date(b?.createdAt ?? 0).getTime() - new Date(a?.createdAt ?? 0).getTime());
        if (mounted) setSubmissions(arr);
      } catch (err) {
        debug("GET /submissions/mine ERROR", err);
        if (err?.response?.status !== 404) setError("Failed to fetch submissions");
      }

      if (mounted) setLoading(false);
    }

    loadAll();
    return () => { mounted = false; };
  }, []);

  // derived metrics
  const submissionCount = Array.isArray(submissions) ? submissions.length : 0;
  const acceptedCount = Array.isArray(submissions) ? submissions.filter(s => ((s?.status || "") + "").toLowerCase() === "accepted").length : 0;
  const totalScore = Array.isArray(submissions) ? submissions.reduce((sum, s) => {
    if (((s?.status || "") + "").toLowerCase() === "accepted") {
      const sc = Number(s?.score);
      return sum + (Number.isNaN(sc) ? 0 : sc);
    }
    return sum;
  }, 0) : 0;

  const acceptanceRate = submissionCount > 0 ? Math.round((acceptedCount / submissionCount) * 100) : 0;

  const topCourse = (() => {
    if (courses.length) {
      const c = courses[0];
      return { name: c?.course_name || c?.name || c?.title || "", code: c?.course_code || c?.code || "" };
    }
    return { name: "", code: "" };
  })();

  const batch = (() => {
    if (profile) {
      if (Array.isArray(profile.batches) && profile.batches.length) return profile.batches[0];
      if (profile.batchName) return { name: profile.batchName, code: profile.batch_code || "" };
    }
    return { name: "N/A", code: "" };
  })();

  const activityData = useMemo(() => {
    const days = 30;
    const map = {};
    for (let i = days - 1; i >= 0; i--) {
      const date = new Date();
      date.setHours(0, 0, 0, 0);
      date.setDate(date.getDate() - i);
      map[date.toISOString().slice(0, 10)] = 0;
    }
    (submissions || []).forEach(s => {
      const dt = s?.createdAt ?? s?.created_at ?? s?.created_at_date ?? null;
      if (!dt) return;
      const key = new Date(dt).toISOString().slice(0, 10);
      if (map[key] != null) map[key] += 1;
    });
    return Object.keys(map).map(k => ({ date: k, count: map[k] }));
  }, [submissions]);

  const handleSaveProfile = async () => {
    try {
      const token = localStorage.getItem("token");
      await axios.put(API_UPDATE_ME, { name: editForm.name, phone: editForm.phone }, { headers: { Authorization: `Bearer ${token}` } });
      const r = await axios.get(API_ME, { headers: { Authorization: `Bearer ${token}` } });
      setProfile(r?.data?.data ?? r?.data ?? null);
      setEditOpen(false);
      alert("Profile updated successfully");
    } catch (err) {
      alert("Failed to save profile");
    }
  };

  const handleChangePassword = async () => {
    if (!pwdForm.oldPassword || !pwdForm.newPassword || !pwdForm.confirmPassword) return alert("Fill all fields");
    if (pwdForm.newPassword !== pwdForm.confirmPassword) return alert("Passwords do not match");
    try {
      const token = localStorage.getItem("token");
      await axios.post(
        API_CHANGE_PASSWORD,
        { currentPassword: pwdForm.oldPassword, newPassword: pwdForm.newPassword },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      alert("Password changed successfully");
      setPwdOpen(false);
      setPwdForm({ oldPassword: "", newPassword: "", confirmPassword: "" });
    } catch (err) {
      alert("Failed to change password");
    }
  };

  const handleDeleteAccount = async () => {
    const proceed = window.confirm("Delete your account permanently? This cannot be undone.");
    if (!proceed) return;

    setDeletingAccount(true);
    try {
      const token = localStorage.getItem("token");
      await axios.delete(`${API_BASE}/students/me`, { headers: { Authorization: `Bearer ${token}` } });
      clearSession();
      navigate('/');
    } catch (err) {
      alert("Failed to delete account");
      setDeletingAccount(false);
    }
  };

  const initials = (profile?.name || "S").split(" ").map(x => x?.[0] || "").slice(0, 2).join("").toUpperCase() || "S";

  if (loading) return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <StudentNavbar />
      <div className="flex-1 flex flex-col items-center justify-center gap-4">
        <div className="animate-spin text-indigo-600"><Upload size={40} /></div>
        <p className="text-slate-500 font-medium">Loading profile...</p>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-12">
      <StudentNavbar />

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header Card */}
        <div className="bg-white rounded-3xl shadow-xl overflow-hidden mb-8 border border-white/50 relative">
          <div className="absolute top-0 left-0 right-0 h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>
          <div className="p-8 md:p-10 flex flex-col md:flex-row items-center gap-8 relative z-10">
            {/* Avatar */}
            <div className="relative group">
              <div className="w-32 h-32 rounded-full bg-gradient-to-br from-indigo-600 to-purple-600 p-1 shadow-2xl">
                <div className="w-full h-full rounded-full bg-white flex items-center justify-center text-4xl font-black text-transparent bg-clip-text bg-gradient-to-br from-indigo-600 to-purple-600 uppercase">
                  {initials}
                </div>
              </div>
              <div className="absolute bottom-0 right-0 bg-green-500 w-8 h-8 rounded-full border-4 border-white flex items-center justify-center">
                <CheckCircle size={16} className="text-white fill-green-500" />
              </div>
            </div>

            {/* Info */}
            <div className="flex-1 text-center md:text-left space-y-2">
              <h1 className="text-4xl font-black text-slate-800 tracking-tight">{profile?.name}</h1>
              <div className="flex flex-wrap justify-center md:justify-start gap-4 text-slate-500 font-medium">
                <span className="flex items-center gap-1.5"><Mail size={16} /> {profile?.email}</span>
                <span className="flex items-center gap-1.5"><Phone size={16} /> {profile?.phone || "No phone"}</span>
                <span className="flex items-center gap-1.5"><Shield size={16} /> Student ID: {profile?.id}</span>
              </div>
              <div className="flex flex-wrap justify-center md:justify-start gap-2 mt-4 pt-2">
                <span className="px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full text-sm font-bold border border-indigo-100 shadow-sm flex items-center gap-1">
                  <Users size={14} /> {batch.name || "No Batch"}
                </span>
                {topCourse.name && (
                  <span className="px-3 py-1 bg-purple-50 text-purple-700 rounded-full text-sm font-bold border border-purple-100 shadow-sm flex items-center gap-1">
                    <BookOpen size={14} /> {topCourse.name}
                  </span>
                )}
              </div>
            </div>

            {/* Actions */}
            <div className="flex flex-col gap-3 min-w-[160px]">
              <ActionButton icon={Edit} label="Edit Profile" variant="ghost" onClick={() => { setEditForm({ name: profile?.name || "", phone: profile?.phone || "" }); setEditOpen(true); }} fullWidth />
              <ActionButton icon={Lock} label="Change Password" variant="primary" onClick={() => setPwdOpen(true)} fullWidth />
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex gap-1 mb-8 bg-white p-1 rounded-xl shadow-sm border border-slate-100 w-fit">
          {['overview', 'submissions', 'settings'].map((t) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              className={`px-6 py-2 rounded-lg font-bold text-sm transition-all capitalize ${tab === t ? 'bg-slate-900 text-white shadow-md' : 'text-slate-500 hover:text-slate-900 hover:bg-slate-50'}`}
            >
              {t}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="space-y-6">
          {tab === 'overview' && (
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              <div className="md:col-span-4 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard title="Total Score" value={totalScore} icon={Medal} color="indigo" subtitle={`${acceptedCount} Accepted`} />
                <StatCard title="Submissions" value={submissionCount} icon={Upload} color="emerald" subtitle={`${acceptanceRate}% Success Rate`} />
                <StatCard title="Courses" value={courses.length} icon={Book} color="cyan" subtitle="Active" />
                <StatCard title="Performance" value={`${acceptanceRate}%`} icon={Activity} color="amber" subtitle="Overall" />
              </div>

              <div className="md:col-span-3 space-y-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                  <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2"><Activity size={18} /> Submission Activity</h3>
                  <div className="h-64">
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={activityData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#94a3b8' }} />
                        <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#94a3b8' }} />
                        <RechartTooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }} />
                        <Line type="monotone" dataKey="count" stroke="#6366f1" strokeWidth={3} dot={{ r: 4, fill: '#6366f1', strokeWidth: 2, stroke: '#fff' }} activeDot={{ r: 6 }} />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
                  <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2"><Clock size={18} /> Recent Submissions</h3>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                      <thead className="text-xs text-slate-400 uppercase bg-slate-50/50">
                        <tr>
                          <th className="px-4 py-3 rounded-l-lg">Problem</th>
                          <th className="px-4 py-3">Language</th>
                          <th className="px-4 py-3">Status</th>
                          <th className="px-4 py-3 rounded-r-lg text-right">Date</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50">
                        {submissions.slice(0, 5).map((s, i) => (
                          <tr key={i} className="hover:bg-slate-50">
                            <td className="px-4 py-3 font-medium text-slate-700">{s.Question?.title || s.title || `Problem ${s.question_id}`}</td>
                            <td className="px-4 py-3 text-slate-500">{s.language || "Unknown"}</td>
                            <td className="px-4 py-3">
                              <span className={`px-2 py-1 rounded-full text-xs font-bold ${s.status === 'accepted' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                                {s.status}
                              </span>
                            </td>
                            <td className="px-4 py-3 text-right text-slate-400">{new Date(s.createdAt).toLocaleDateString()}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>

              <div className="md:col-span-1 space-y-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                  <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2"><PieChartIcon size={18} /> Breakdown</h3>
                  <div className="h-48">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={[{ name: 'Accepted', value: acceptedCount }, { name: 'Other', value: submissionCount - acceptedCount }]} dataKey="value" innerRadius={40} outerRadius={70}>
                          <Cell fill={STATUS_COLORS.accepted} />
                          <Cell fill={STATUS_COLORS.pending} />
                        </Pie>
                        <RechartTooltip />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="flex justify-center gap-4 text-xs font-bold text-slate-500">
                    <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-emerald-500"></span> Accepted</span>
                    <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-amber-500"></span> Other</span>
                  </div>
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                  <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2"><BookOpen size={18} /> My Courses</h3>
                  <div className="space-y-2">
                    {courses.map((c, i) => (
                      <div key={i} className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                        <p className="font-bold text-slate-800 text-sm mb-0.5">{c.name || c.course_name}</p>
                        <p className="text-xs text-slate-500">{c.code || c.course_code}</p>
                      </div>
                    ))}
                    {courses.length === 0 && <p className="text-slate-400 text-sm italic text-center py-4">No courses assigned</p>}
                  </div>
                </div>
              </div>
            </div>
          )}

          {tab === 'submissions' && (
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-6 border-b border-slate-100 bg-slate-50/50">
                <h3 className="font-bold text-lg text-slate-800">All Submissions</h3>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                  <thead className="bg-slate-50 text-slate-500 uppercase font-bold text-xs">
                    <tr>
                      <th className="px-6 py-4">Question</th>
                      <th className="px-6 py-4">Language</th>
                      <th className="px-6 py-4">Result</th>
                      <th className="px-6 py-4 text-right">Submitted</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {submissions.map((s, i) => (
                      <tr key={i} className="hover:bg-slate-50">
                        <td className="px-6 py-4 font-bold text-slate-700">{s.Question?.title || s.title || `Question ID: ${s.question_id}`}</td>
                        <td className="px-6 py-4">
                          <span className="px-2 py-1 bg-slate-100 rounded text-xs font-mono text-slate-600">{s.language}</span>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold uppercase ${s.status === 'accepted' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100'}`}>
                            {s.status === 'accepted' ? <CheckCircle size={12} /> : <AlertCircle size={12} />}
                            {s.status || 'Unknown'}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right text-slate-400 font-mono text-xs">
                          {new Date(s.createdAt).toLocaleString()}
                        </td>
                      </tr>
                    ))}
                    {submissions.length === 0 && <tr><td colSpan="4" className="p-8 text-center text-slate-400">No submissions found</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {tab === 'settings' && (
            <div className="max-w-2xl mx-auto space-y-6">
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <h3 className="font-bold text-lg text-slate-800 mb-4">Account Actions</h3>
                <div className="space-y-4">
                  <div className="flex items-center justify-between p-4 bg-slate-50 rounded-xl border border-slate-100">
                    <div>
                      <p className="font-bold text-slate-800">Update Profile</p>
                      <p className="text-sm text-slate-500">Change your name or contact info</p>
                    </div>
                    <ActionButton icon={Edit} label="Edit" size="small" variant="secondary" onClick={() => setEditOpen(true)} />
                  </div>
                  <div className="flex items-center justify-between p-4 bg-slate-50 rounded-xl border border-slate-100">
                    <div>
                      <p className="font-bold text-slate-800">Change Password</p>
                      <p className="text-sm text-slate-500">Update your login credentials</p>
                    </div>
                    <ActionButton icon={Lock} label="Update" size="small" variant="secondary" onClick={() => setPwdOpen(true)} />
                  </div>
                  <div className="flex items-center justify-between p-4 bg-red-50 rounded-xl border border-red-100">
                    <div>
                      <p className="font-bold text-red-700">Delete Account</p>
                      <p className="text-sm text-red-500">Permanently remove your data</p>
                    </div>
                    <ActionButton icon={Trash2} label="Delete" size="small" variant="danger" onClick={handleDeleteAccount} />
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Edit Modal */}
      <Modal isOpen={editOpen} onClose={() => setEditOpen(false)} title="Edit Profile">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Name</label>
            <input className="w-full px-4 py-2 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500" value={editForm.name} onChange={e => setEditForm({ ...editForm, name: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Phone</label>
            <input className="w-full px-4 py-2 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500" value={editForm.phone} onChange={e => setEditForm({ ...editForm, phone: e.target.value })} />
          </div>
          <div className="flex justify-end gap-3 pt-4">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setEditOpen(false)} />
            <ActionButton label="Save Changes" onClick={handleSaveProfile} />
          </div>
        </div>
      </Modal>

      {/* Password Modal */}
      <Modal isOpen={pwdOpen} onClose={() => setPwdOpen(false)} title="Change Password">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Current Password</label>
            <input type="password" className="w-full px-4 py-2 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500" value={pwdForm.oldPassword} onChange={e => setPwdForm({ ...pwdForm, oldPassword: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">New Password</label>
            <input type="password" className="w-full px-4 py-2 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500" value={pwdForm.newPassword} onChange={e => setPwdForm({ ...pwdForm, newPassword: e.target.value })} />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Confirm New Password</label>
            <input type="password" className="w-full px-4 py-2 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500" value={pwdForm.confirmPassword} onChange={e => setPwdForm({ ...pwdForm, confirmPassword: e.target.value })} />
          </div>
          <div className="flex justify-end gap-3 pt-4">
            <ActionButton label="Cancel" variant="secondary" onClick={() => setPwdOpen(false)} />
            <ActionButton label="Change Password" onClick={handleChangePassword} />
          </div>
        </div>
      </Modal>

    </div>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Trophy, TrendingUp, Activity, Code, RotateCw, ArrowRight,
  Target, AlertCircle
} from 'lucide-react';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import StudentNavbar from './StudentNavbar';

const API_COURSES = 'http://localhost:3000/api/students/courses-with-exams';
const API_SUBMISSIONS = 'http://localhost:3000/api/submissions/mine';

// Helper to pick an icon based on course name
function getCourseIcon(name, idx) {
  if (!name) return <Activity size={24} />;
  const n = name.toLowerCase();
  if (n.includes('learn') || n.includes('machine') || n.includes('ml')) return <Activity size={24} />;
  if (n.includes('data') || n.includes('algorithm') || n.includes('dsa')) return <RotateCw size={24} />;
  if (n.includes('web') || n.includes('frontend') || n.includes('react')) return <Code size={24} />;

  const icons = [<Activity size={24} />, <RotateCw size={24} />, <Code size={24} />];
  return icons[idx % icons.length];
}

export default function StudentScore() {
  const [courses, setCourses] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    let mounted = true;
    const token = localStorage.getItem('token');
    const headers = token ? { Authorization: `Bearer ${token}` } : {};

    const fetchAll = async () => {
      setLoading(true);
      setError('');
      try {
        const [coursesRes, subsRes] = await Promise.allSettled([
          axios.get(API_COURSES, { headers }),
          axios.get(API_SUBMISSIONS, { headers }),
        ]);

        // Normalize courses
        let coursesData = [];
        if (coursesRes.status === 'fulfilled') {
          const d = coursesRes.value?.data ?? {};
          const rawCourses = Array.isArray(d) ? d : (d.courses || d.data || []);
          coursesData = rawCourses.map((c, idx) => ({
            id: c.course_id ?? c.id ?? c._id ?? `c-${idx}`,
            name: c.course_name ?? c.name ?? c.title ?? `Course ${idx + 1}`,
            code: c.course_code ?? c.code ?? '',
          }));
        }

        // Normalize submissions
        let subsRaw = [];
        if (subsRes.status === 'fulfilled') {
          const d = subsRes.value?.data ?? {};
          if (Array.isArray(d)) subsRaw = d;
          else if (Array.isArray(d.submissions)) subsRaw = d.submissions;
          else if (Array.isArray(d.data)) subsRaw = d.data;
          else if (Array.isArray(d.items)) subsRaw = d.items;
        }

        const normalizedSubs = subsRaw.map((s, idx) => {
          const courseId = s.course?.id ?? s.course_id ?? s.courseId ?? s.Question?.course_id ?? null;
          const courseName = s.course?.name ?? s.course_name ?? s.courseName ?? s.Question?.Course?.name ?? null;
          const status = (s.status ?? s.state ?? (s.raw && s.raw.status) ?? '').toString();
          const scoreRaw = s.score ?? s.marks ?? s.points ?? null;
          const score = (scoreRaw != null && scoreRaw !== '') ? Number(scoreRaw) : null;
          const createdAt = s.createdAt ?? s.created_at ?? s.created_at_date ?? null;

          return {
            id: s.id ?? s._id ?? `sub-${idx}`,
            courseId,
            courseName,
            status,
            score: Number.isNaN(score) ? null : score,
            createdAt,
            raw: s,
          };
        });

        if (mounted) {
          setCourses(coursesData);
          setSubmissions(normalizedSubs);
        }
      } catch (err) {
        console.error('Fetch error:', err);
        if (mounted) setError(err.response?.data?.message || 'Failed to load data');
      } finally {
        if (mounted) setLoading(false);
      }
    };

    fetchAll();
    return () => { mounted = false; };
  }, []);

  const aggregates = useMemo(() => {
    const map = new Map();
    courses.forEach(c => {
      map.set(c.id, { id: c.id, name: c.name || c.code || c.id, score: 0, accepted: 0, total: 0 });
    });

    submissions.forEach(s => {
      const key = s.courseId ?? s.courseName ?? 'unknown';
      if (!map.has(key)) {
        map.set(key, { id: key, name: s.courseName ?? (typeof key === 'string' ? key : 'Unknown Course'), score: 0, accepted: 0, total: 0 });
      }
      const entry = map.get(key);
      entry.total += 1;
      if (s.status?.toLowerCase() === 'accepted') {
        entry.accepted += 1;
        const sc = Number(s.score);
        if (!isNaN(sc)) entry.score += sc;
      }
    });

    return Array.from(map.values());
  }, [courses, submissions]);

  return (
    <>
      <StudentNavbar />

      <div className="min-h-screen bg-slate-50 pt-20 pb-12 px-4 md:px-8">
        <div className="max-w-7xl mx-auto space-y-8">

          {/* Header Card */}
          <div className="bg-white rounded-3xl p-8 relative overflow-hidden shadow-xl border border-white/50">
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>
            <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
              <div className="flex items-center gap-6">
                <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-indigo-600 to-purple-600 flex items-center justify-center shadow-lg transform rotate-3 hover:rotate-6 transition-transform">
                  <Trophy className="text-white" size={40} />
                </div>
                <div>
                  <h1 className="text-4xl font-black text-slate-800 tracking-tight mb-2">My Performance</h1>
                  <p className="text-slate-500 font-medium text-lg">Track your progress and scores across all courses</p>
                </div>
              </div>

              <div className="flex items-center gap-6 flex-wrap justify-end">
                <div className="flex items-center gap-2 px-4 py-2 bg-emerald-50 text-emerald-700 rounded-xl border border-emerald-100 font-bold shadow-sm">
                  <Target size={20} />
                  <span>{aggregates.reduce((acc, c) => acc + c.accepted, 0)} Accepted</span>
                </div>
                <div className="flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-700 rounded-xl border border-blue-100 font-bold shadow-sm">
                  <Activity size={20} />
                  <span>{submissions.length} Total</span>
                </div>
              </div>
            </div>
          </div>

          {/* Content */}
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20">
              <RotateCw className="animate-spin text-indigo-600 mb-4" size={48} />
              <p className="text-slate-500 font-bold text-lg">Calculating scores...</p>
            </div>
          ) : error ? (
            <div className="bg-rose-50 border border-rose-200 text-rose-700 px-6 py-4 rounded-xl flex items-center gap-3">
              <AlertCircle size={24} />
              <p className="font-medium">{error}</p>
            </div>
          ) : aggregates.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-slate-300">
              <TrendingUp className="text-slate-300 mb-4" size={64} />
              <h3 className="text-xl font-bold text-slate-600">No Activity Yet</h3>
              <p className="text-slate-400">Join a course and start solving problems to see your stats!</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {aggregates.map((course, idx) => {
                const ratio = course.total > 0 ? (course.accepted / course.total) : 0;
                const isPositive = ratio >= 0.5;

                return (
                  <motion.div
                    key={course.id}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: idx * 0.1 }}
                    whileHover={{ y: -5 }}
                    className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 flex flex-col h-full group"
                  >
                    <div className="p-6 flex-1">
                      <div className="flex items-center gap-4 mb-6">
                        <div className="w-14 h-14 rounded-xl bg-gradient-to-br from-slate-100 to-white border border-slate-100 shadow-sm flex items-center justify-center text-indigo-600 group-hover:scale-110 transition-transform duration-300">
                          {getCourseIcon(course.name, idx)}
                        </div>
                        <div>
                          <h3 className="font-bold text-slate-800 text-lg leading-tight line-clamp-2">{course.name}</h3>
                          <p className="text-xs font-mono text-slate-400 mt-1">{course.id}</p>
                        </div>
                      </div>

                      <div className="mb-6">
                        <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Total Score</p>
                        <div className="text-4xl font-black bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600">
                          {course.score}
                        </div>
                      </div>

                      <div className="space-y-2">
                        <div className="flex justify-between text-xs font-bold text-slate-600 mb-1">
                          <span>Progress</span>
                          <span>{Math.round(ratio * 100)}%</span>
                        </div>
                        <div className="h-2.5 w-full bg-slate-100 rounded-full overflow-hidden">
                          <motion.div
                            initial={{ width: 0 }}
                            animate={{ width: `${ratio * 100}%` }}
                            transition={{ duration: 1, ease: 'easeOut' }}
                            className={`h-full rounded-full ${isPositive ? 'bg-gradient-to-r from-emerald-400 to-emerald-600' : 'bg-gradient-to-r from-amber-400 to-amber-600'}`}
                          />
                        </div>
                        <p className={`text-xs font-bold mt-2 ${isPositive ? 'text-emerald-600' : 'text-amber-600'}`}>
                          {course.accepted} / {course.total} Problems Solved
                        </p>
                      </div>
                    </div>

                    <div className="p-4 bg-slate-50 border-t border-slate-100">
                      <button
                        onClick={() => navigate(`/student/submissions?courseId=${encodeURIComponent(course.id)}`)}
                        className="w-full flex items-center justify-center gap-2 py-2.5 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl hover:bg-slate-50 hover:border-slate-300 hover:text-indigo-600 transition-all shadow-sm active:scale-95"
                      >
                        View Details <ArrowRight size={18} />
                      </button>
                    </div>
                  </motion.div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import StudentNavbar from './StudentNavbar';
import { useSearchParams } from 'react-router-dom';
import {
  RefreshCw, BookOpen, Download, AlertCircle, CheckCircle,
  XCircle, Clock, Calendar, Filter, Hash
} from 'lucide-react';
import { AnimatePresence } from 'framer-motion';

const API_SUBMISSIONS = 'http://localhost:3000/api/submissions/mine';
const API_EXPORT_MY = 'http://localhost:3000/api/export/students/me/submissions/export';

const StatusBadge = ({ status }) => {
  const s = (status || '').toLowerCase();

  if (s === 'accepted' || s === 'passed') {
    return (
      <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold bg-emerald-100 text-emerald-700 border border-emerald-200">
        <CheckCircle size={12} /> Accepted
      </span>
    );
  }
  if (s === 'rejected' || s === 'failed') {
    return (
      <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold bg-rose-100 text-rose-700 border border-rose-200">
        <XCircle size={12} /> Failed
      </span>
    );
  }
  if (s === 'pending') {
    return (
      <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold bg-amber-100 text-amber-700 border border-amber-200">
        <Clock size={12} /> Pending
      </span>
    );
  }
  return (
    <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold bg-slate-100 text-slate-700 border border-slate-200">
      {status || 'Unknown'}
    </span>
  );
};

export default function StudentSubmissions() {
  const [searchParams, setSearchParams] = useSearchParams();
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [selectedCourseId, setSelectedCourseId] = useState(searchParams.get('courseId') || '');
  const [exporting, setExporting] = useState(false);

  // ---------------------------------------------------------------------
  // Data fetching
  // ---------------------------------------------------------------------
  useEffect(() => {
    let mounted = true;
    const load = async () => {
      setLoading(true);
      setError('');
      try {
        const token = localStorage.getItem('token');
        const headers = token ? { Authorization: `Bearer ${token}` } : {};
        const res = await axios.get(API_SUBMISSIONS, { headers });
        const payload = res?.data ?? {};
        let arr = [];
        if (Array.isArray(payload)) arr = payload;
        else if (Array.isArray(payload.submissions)) arr = payload.submissions;
        else if (Array.isArray(payload.data)) arr = payload.data;
        else if (Array.isArray(payload.items)) arr = payload.items;

        const normalized = arr.map((s) => ({
          id: s.id ?? s._id ?? s.submission_id ?? null,
          question_title: s.question_title ?? s.question?.title ?? s.Question?.title ?? s.questionTitle ?? '-',
          course: (s.course && {
            id: s.course.id ?? s.course.course_id ?? s.course._id,
            name: s.course.name,
          }) || (s.Question && s.Question.Course && {
            id: s.Question.Course.id ?? s.Question.Course._id ?? s.Question.Course.course_id,
            name: s.Question.Course.name,
          }) || null,
          status: s.status ?? s.state ?? null,
          score: s.score ?? s.marks ?? null,
          createdAt: s.createdAt ?? s.created_at ?? s.created_at_date ?? s.created_on ?? null,
          raw: s,
        }));
        const sorted = normalized.slice().sort((a, b) => {
          const ta = a.createdAt ? new Date(a.createdAt).getTime() : 0;
          const tb = b.createdAt ? new Date(b.createdAt).getTime() : 0;
          return tb - ta;
        });
        if (mounted) setSubmissions(sorted);
      } catch (err) {
        setError('Failed to load submissions');
      } finally {
        if (mounted) setLoading(false);
      }
    };
    load();
    return () => { mounted = false; };
  }, []);

  // ---------------------------------------------------------------------
  // Helper data
  // ---------------------------------------------------------------------
  const courses = useMemo(() => {
    const map = new Map();
    submissions.forEach((s) => {
      const id = s.course?.id ?? s.raw?.Question?.Course?.id ?? s.raw?.course?.id;
      const name = s.course?.name ?? s.raw?.Question?.Course?.name ?? s.raw?.course?.name;
      if (id || name) {
        const key = id ?? name;
        if (!map.has(key)) map.set(key, { id: id ?? name, name: name ?? String(id) });
      }
    });
    return Array.from(map.values()).sort((a, b) => String(a.name).localeCompare(String(b.name)));
  }, [submissions]);

  const filtered = useMemo(() => {
    if (!selectedCourseId) return [];
    return submissions.filter((s) => {
      const id = s.course?.id ?? s.raw?.Question?.Course?.id ?? s.raw?.course?.id ?? s.course?.name ?? '';
      return String(id) === String(selectedCourseId);
    });
  }, [submissions, selectedCourseId]);

  const groupedFiltered = useMemo(() => {
    const acc = {};
    filtered.forEach((item) => {
      const d = item.createdAt ? new Date(item.createdAt) : new Date();
      if (isNaN(d.getTime())) return;
      const iso = d.toISOString().slice(0, 10);
      const display = d.toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' });
      if (!acc[iso]) acc[iso] = { display, items: [] };
      acc[iso].items.push(item);
    });
    return acc;
  }, [filtered]);

  const dateKeys = useMemo(() => Object.keys(groupedFiltered).sort((a, b) => new Date(b) - new Date(a)), [groupedFiltered]);
  const selectedCourse = useMemo(() => courses.find((c) => String(c.id) === String(selectedCourseId)), [courses, selectedCourseId]);

  useEffect(() => {
    if (!courses.length) return;
    if (!selectedCourseId) return;
    const hasSelected = courses.some((c) => String(c.id) === String(selectedCourseId));
    if (!hasSelected) setSelectedCourseId('');
  }, [courses, selectedCourseId]);

  // ---------------------------------------------------------------------
  // Export handling
  // ---------------------------------------------------------------------
  const handleExport = async () => {
    try {
      setExporting(true);
      const token = localStorage.getItem('token');
      const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
      const params = {};
      if (selectedCourseId) params.courseId = selectedCourseId;

      const resp = await axios.get(API_EXPORT_MY, { headers, params, responseType: 'blob', timeout: 30000 });
      let filename = 'my_submissions.xlsx';

      const blob = new Blob([resp.data], { type: resp.headers['content-type'] });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (err) {
      alert('Export failed. Please try again.');
    } finally {
      setExporting(false);
    }
  };

  if (loading) return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <StudentNavbar />
      <div className="flex-1 flex flex-col items-center justify-center gap-4">
        <RefreshCw className="animate-spin text-indigo-600" size={40} />
        <p className="text-slate-500 font-medium">Loading submissions...</p>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-12">
      <StudentNavbar />

      <div className="max-w-7xl mx-auto px-4 md:px-8 pt-8">
        {error && (
          <div className="mb-6 rounded-xl border border-rose-200 bg-rose-50 text-rose-700 px-4 py-3 text-sm font-medium">
            {error}
          </div>
        )}

        {/* Header Card */}
        <div className="bg-white rounded-3xl p-8 shadow-xl border border-white/50 relative overflow-hidden mb-8">
          <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>
          <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
            <div className="flex items-center gap-6">
              <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-indigo-600 to-purple-600 flex items-center justify-center shadow-lg transform rotate-3 hover:rotate-6 transition-transform">
                <Hash className="text-white" size={40} />
              </div>
              <div>
                <h1 className="text-3xl md:text-4xl font-black text-slate-800 tracking-tight mb-2">My Submissions</h1>
                <p className="text-slate-500 font-medium text-lg">Track your coding journey and review past solutions</p>
              </div>
            </div>

            <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
              <div className="relative w-full sm:w-64">
                <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <select
                  value={selectedCourseId}
                  onChange={(e) => {
                    const nextCourseId = e.target.value;
                    setSelectedCourseId(nextCourseId);
                    if (nextCourseId) {
                      setSearchParams({ courseId: nextCourseId });
                    } else {
                      setSearchParams({});
                    }
                  }}
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer hover:bg-slate-100 transition-colors"
                >
                  <option value="">-- Select Course to View --</option>
                  {courses.map((c) => (
                    <option key={c.id} value={c.id}>{c.name}</option>
                  ))}
                </select>
              </div>

              <button
                onClick={handleExport}
                disabled={exporting || !selectedCourseId}
                className="flex items-center justify-center gap-2 px-6 py-3 bg-white text-slate-700 border border-slate-200 rounded-xl font-bold hover:bg-slate-50 transition-colors w-full sm:w-auto shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {exporting ? <RefreshCw className="animate-spin" size={20} /> : <Download size={20} />}
                {exporting ? 'Exporting...' : 'Export Excel'}
              </button>
            </div>
          </div>
        </div>

        {/* Course Stats / Selected Info */}
        <AnimatePresence mode="wait">
          {selectedCourse && (
            <div className="bg-indigo-600 rounded-2xl p-6 shadow-lg mb-8 text-white flex items-center gap-6">
              <div className="p-3 bg-white/20 rounded-xl backdrop-blur-sm">
                <BookOpen size={32} />
              </div>
              <div>
                <h3 className="text-xl font-bold">{selectedCourse.name}</h3>
                <p className="opacity-90 font-medium">{filtered.length} total submissions in this course</p>
              </div>
            </div>
          )}
        </AnimatePresence>

        {/* Content */}
        {!selectedCourseId ? (
          <div className="flex flex-col items-center justify-center h-64 bg-white rounded-3xl border border-dashed border-slate-300 text-slate-400">
            <BookOpen size={64} className="mb-4 opacity-50" />
            <h3 className="text-xl font-bold text-slate-500">No Course Selected</h3>
            <p>Please select a course from the dropdown to view submissions.</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 bg-white rounded-3xl border border-dashed border-slate-300 text-slate-400">
            <AlertCircle size={64} className="mb-4 opacity-50" />
            <h3 className="text-xl font-bold text-slate-500">No Submissions Yet</h3>
            <p>Start solving problems to see your history here!</p>
          </div>
        ) : (
          <div className="space-y-8">
            {dateKeys.map((dateKey) => (
              <div key={dateKey} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="px-6 py-4 bg-slate-50 border-b border-slate-100 flex items-center gap-2">
                  <Calendar size={18} className="text-indigo-600" />
                  <h3 className="font-bold text-slate-700">{groupedFiltered[dateKey].display}</h3>
                  <span className="ml-auto text-xs font-bold px-2 py-1 bg-white rounded-md border border-slate-200 text-slate-500">
                    {groupedFiltered[dateKey].items.length} Submissions
                  </span>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="border-b border-slate-100 text-xs uppercase font-bold text-slate-400 bg-white">
                        <th className="px-6 py-3 w-16 text-center">#</th>
                        <th className="px-6 py-3">Problem Title</th>
                        <th className="px-6 py-3">Status</th>
                        <th className="px-6 py-3 text-center">Score</th>
                        <th className="px-6 py-3 text-right">Time</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {groupedFiltered[dateKey].items.map((item, idx) => (
                        <tr key={item.id} className="hover:bg-indigo-50/30 transition-colors group cursor-default">
                          <td className="px-6 py-4 text-center text-sm text-slate-400 font-mono">
                            {(idx + 1).toString().padStart(2, '0')}
                          </td>
                          <td className="px-6 py-4">
                            <p className="font-bold text-slate-700">{item.question_title}</p>
                            <p className="text-xs text-slate-400 group-hover:text-indigo-500 transition-colors">{item.course?.name}</p>
                          </td>
                          <td className="px-6 py-4">
                            <StatusBadge status={item.status} />
                          </td>
                          <td className="px-6 py-4 text-center">
                            <span className={`font-mono font-bold ${item.score === 100 ? 'text-emerald-600' : 'text-slate-600'}`}>
                              {item.score ?? '-'}
                            </span>
                          </td>
                          <td className="px-6 py-4 text-right text-sm text-slate-400 font-mono">
                            {item.createdAt ? new Date(item.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '-'}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
